-- Poems batch 414
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-522','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','江城春霁雪初融。',57,'宋词/ci.song.7000.json','["江城春霁雪初融。", "楼观瑞烟中。", "向晚金莲无数，一时开遍东风。", "多情太守，行携红袖，坐引金锺。", "时出阳春绝唱，才名不减诗翁。"]'),
('song-ci-523','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','从来寒食半阴晴。',57,'宋词/ci.song.7000.json','["从来寒食半阴晴。", "花底听歌声。", "昨夜满城风雨，惜花还系心情。", "海棠枝上，朱唇翠袖，欲斗轻盈。", "须藉嫣然一笑，醉吟同过清明。"]'),
('song-ci-524','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','朝阳淡淡宿云轻。',57,'宋词/ci.song.7000.json','["朝阳淡淡宿云轻。", "风入管弦声。", "十里碧芜幽步，一枝丹杏柔情。", "佳人何处，酒红沁眼，秋水盈盈。", "诗曲羡君三绝，湖山增我双明。"]'),
('song-ci-525','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','老穷无赖事成丛。',57,'宋词/ci.song.7000.json','["老穷无赖事成丛。", "短发自髼松。", "坐想帝城当日，万花绣出天宫。", "几时临赋，深浮绿蚁，缓唱黄锺。", "莫获追陪胜赏，虚烦恼乱衰翁。"]'),
('song-ci-526','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','暖风迟日透香肌。',57,'宋词/ci.song.7000.json','["暖风迟日透香肌。", "春到柳边枝。", "曾见酒红潮颊，玉人初出罗帏。", "东坡何处，朱唇翠袖，空想芳姿。", "争似濡须太守，看花仍赋佳词。"]'),
('song-ci-527','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','天庭丹熟在何时。',57,'宋词/ci.song.7000.json','["天庭丹熟在何时。", "铅汞适投机。", "四海方思霖雨，未容驾鹤先飞。", "当年今日，谪仙初降，庭露馡馡。", "愿对良辰好景，称觞为醉芳菲。"]'),
('song-ci-528','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','州闾庠序少追随。',57,'宋词/ci.song.7000.json','["州闾庠序少追随。", "俯仰鬓成丝。", "仕宦孰逾君达，恩施遍及庭芝。", "溪头春日，欢声和气，如见生时。", "好对高堂寿母，献酬同醉金卮。"]'),
('song-ci-529','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','满庭岩桂蔼香风。',57,'宋词/ci.song.7000.json','["满庭岩桂蔼香风。", "人在画堂中。", "欲验鲁侯难老，欢声千里攸同。", "台分金石，源锺淮水，流庆无穷。", "好继汉朝循吏，从兹入拜三公。"]'),
('song-ci-530','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','君心节直更心虚。',57,'宋词/ci.song.7000.json','["君心节直更心虚。", "移植并庭除。", "好在红蕖相映，卷帘如见吴姝。", "清风明月，君无我弃，我不君疏。", "况有骚人墨客，时来同醉兵厨。"]'),
('song-ci-531','朝中措','王之道','宋','宋词','song-ci','朝中措','[]','晴烟漠漠日晖晖。',57,'宋词/ci.song.7000.json','["晴烟漠漠日晖晖。", "天际远山低。", "槛外碧芜千里，坐来目送鸥飞。", "诗笺谈麈，珠盘落落，玉屑霏霏。", "更把登临馀兴，翻成白雪歌词。"]'),
('song-ci-532','玉楼春','王之道','宋','宋词','song-ci','玉楼春','[]','年来六十增三岁。',64,'宋词/ci.song.7000.json','["年来六十增三岁。", "却忆去年趋盛会。", "风流人物胜斜川，灼灼有同前日事。", "不知弦管催新水。", "但见飘飘萦舞袂。", "主人情厚酒行频，酩酊莫辞今夕醉。"]'),
('song-ci-533','玉楼春','王之道','宋','宋词','song-ci','玉楼春','[]','少年心性消磨尽。',64,'宋词/ci.song.7000.json','["少年心性消磨尽。", "三斗烂肠浑是闷。", "看书聊复强寻行，属句不妨闲趁韵。", "此生自断天休问。", "富贵时来还有分。", "一卮芳酒送清歌，楼下玉人相去近。"]'),
('song-ci-534','石州慢','王之道','宋','宋词','song-ci','石州慢','[]','磔攘送寒，燔烈兴岁，又颁尧历。',122,'宋词/ci.song.7000.json','["磔攘送寒，燔烈兴岁，又颁尧历。", "青霭烧痕，绿浮风皱，暖回春色。", "地天交泰，时当倾否，五鬼休相厄。", "何妨笑倚东风，一饮杯三百。", "长忆。", "苻坚入寇，功高晋室，无如安石。", "义概雄心，辄莫等闲抛掷。", "盖壤声名，鼎彝勋业。", "朋溪虽好，未放终闲逸。", "喈喈黄鸟，更看壶中春日。"]'),
('song-ci-535','鹊桥仙','王之道','宋','宋词','song-ci','鹊桥仙','[]','霜风擢霁，云涛涨晚，更觉我心弥壮。',68,'宋词/ci.song.7000.json','["霜风擢霁，云涛涨晚，更觉我心弥壮。", "一尊谁与醉西风，辄莫负、高吟胜赏。", "致君才术，康时事业，到底不容闲放。", "十年湖海哄樵歌，何幸出、阳春绝唱。"]'),
('song-ci-536','鹊桥仙','王之道','宋','宋词','song-ci','鹊桥仙','["\u957f\u6c5f"]','断虹霁雨，馀霞送日，帘卷西楼月上。',68,'宋词/ci.song.7000.json','["断虹霁雨，馀霞送日，帘卷西楼月上。", "银河风静夜无波，天亦为、云軿相访。", "蛛丝有恨，鹊桥何处，回首又成惆怅。", "长江滚滚向东流，写不尽、别离情状。"]'),
('song-ci-537','菩萨蛮','王之道','宋','宋词','song-ci','菩萨蛮','[]','香鬟倭堕兰膏腻。',52,'宋词/ci.song.7000.json','["香鬟倭堕兰膏腻。", "睡起搔头红玉坠。", "秋水不胜情。", "盈盈横沁人。", "朱阑频徙倚。", "笑与花争媚。", "眉黛索重添。", "春酲意未忺。"]'),
('song-ci-538','菩萨蛮','王之道','宋','宋词','song-ci','菩萨蛮','[]','绿杨低映深深院。',52,'宋词/ci.song.7000.json','["绿杨低映深深院。", "春风不动珠帘卷。", "乳燕引雏飞。", "流苏尽日垂。", "绮窗开小宴。", "娅姹莺声啭。", "一饷不闻声。", "罗衣香汗轻。"]'),
('song-ci-539','菩萨蛮','王之道','宋','宋词','song-ci','菩萨蛮','[]','小庭过雨莓苔滑。',52,'宋词/ci.song.7000.json','["小庭过雨莓苔滑。", "碧波滟滟池也阔。", "睡起□雕阑。", "不言神思闲。", "晚来调瑟罢。", "笑语秋千下。", "高枕绿杨风。", "隔帘花映红。"]'),
('song-ci-540','菩萨蛮','王之道','宋','宋词','song-ci','菩萨蛮','[]','晴窗睡起炉烟直。',52,'宋词/ci.song.7000.json','["晴窗睡起炉烟直。", "香云堕髻娇无力。", "溪水碧涵空。", "拒霜深浅红。", "坠鞭还驻马。", "缥缈珠帘下。", "自是意中人。", "临风休障尘。"]'),
('song-ci-541','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','薰风散雾。',87,'宋词/ci.song.7000.json','["薰风散雾。", "帘幕清无暑。", "萱草径，荷花坞。", "幽香浮几席，秀色侵庭庑。", "微雨过，绿杨枝上珠成缕。", "双燕飞还语。", "似庆良辰遇。", "酾美酒，烹肥羜。", "何妨饮且醉，共作斑衣舞。", "人竟报，蟠桃已实君知否。"]'),
('song-ci-542','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','斜风横雨。',87,'宋词/ci.song.7000.json','["斜风横雨。", "咫尺高城路。", "红蓼岸，苍葭浦。", "滞留春色晚，栖泊邮亭暮。", "信杳杳，鹊声近有无凭据。", "肠断家何处。", "又见重阳度。", "多少恨，从谁诉。", "黄鸡斟白酒，自促供搜句。", "归去好，人生莫被浮名误。"]'),
('song-ci-543','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','金风玉宇。',87,'宋词/ci.song.7000.json','["金风玉宇。", "庭院新经雨。", "香有露，清无暑。", "溪光摇几席，岚翠横尊俎。", "烘笑语，佳时聊复乡人聚。", "门外荷花浦。", "秋到化无数。", "红脍鲤。", "青浮醑。", "何妨文字饮，更得江山助。", "从此去。", "蒲轮入佐中兴主。"]'),
('song-ci-544','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','山前湖外。',87,'宋词/ci.song.7000.json','["山前湖外。", "初日浮云退。", "荷气馥，槐阴碎。", "葵花红障锦，萱草青垂带。", "谁得似，黄鹂求友新成对。", "忆昔东门会。", "千古同侵盖。", "人已远，歌如在。", "银钩虽可漫，琬琰终难改。", "愁浩荡，临风令我思淮海。"]'),
('song-ci-545','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','晓霜初肃。',87,'宋词/ci.song.7000.json','["晓霜初肃。", "秋色团芳菊。", "榴转紫，柑犹绿。", "昨朝吹帽会，未快登临目。", "须信道，兵厨准拟三千斛。", "采采香云掬。", "泛泛纷浮玉。", "红袖捧，清歌逐。", "何妨倾坐客，共献长生祝。", "归去好，北门夜饮金莲烛。"]'),
('song-ci-546','千秋岁','王之道','宋','宋词','song-ci','千秋岁','[]','熙熙台上。',87,'宋词/ci.song.7000.json','["熙熙台上。", "秋色增清壮。", "和气溢，祥烟扬。", "淮山供杂俎，湖水浮新酿。", "人共仰，貔貅坐拥诗书将。", "箫鼓声嘹亮。", "珠翠环相向。", "回妙舞，迟妍唱。", "竟斟长命斝，同试沧溟量。", "锋车往，东归遂继华原相。"]'),
('song-ci-547','胜胜慢・声声慢','王之道','宋','宋词','song-ci','胜胜慢・声声慢','[]','鲁云书瑞，周日迎长，晓占缇室飞灰。',122,'宋词/ci.song.7000.json','["鲁云书瑞，周日迎长，晓占缇室飞灰。", "玉勒朝天，千门禁钥齐开。", "帘卷扇分雉尾，香风远、人到蓬莱。", "霞觞满，□万年献祝，宫殿昭回。", "况有金瓯名姓，一任名园萧散，元自徘徊。", "门外锋车，又连凤沼相催。", "酒到莫辞频举，听清歌、一阕倾杯。", "功成日，渺五湖烟月，堪赋归来。"]'),
('song-ci-548','胜胜慢・声声慢','王之道','宋','宋词','song-ci','胜胜慢・声声慢','[]','凌云气节，贯日精忠，艰难未许心灰。',122,'宋词/ci.song.7000.json','["凌云气节，贯日精忠，艰难未许心灰。", "芳酒一尊，对君聊为君开。", "要识治安非晚，乐得贤、新赋台莱。", "愁似雪，喜青天万里，晓霁春回。", "须信赤绳系足，朱衣点额终在，休叹淹徊。", "梅实槐花，看看便是相催。", "座上觥筹交错，玉山峙、莫遣停杯。", "濡须好，傥他时富贵，犹冀重来。"]'),
('song-ci-549','胜胜慢・声声慢','王之道','宋','宋词','song-ci','胜胜慢・声声慢','[]','菊团封绿，莲萼凋红，萧然独见芳姿。',118,'宋词/ci.song.7000.json','["菊团封绿，莲萼凋红，萧然独见芳姿。", "短墙高榭，疏筠怪石偏宜。", "香遍秋风到处，微雨过、清露零时。", "花阴下，称笺毫唱和，杖履追随。", "曷似江头竹外，凌霜犯雪，岁晚争奇。", "夕赏朝吟，劝秋莫放离披。", "细看石楠玉茗，叶纵似、风韵输伊。", "最好处，拥新妆、临鉴碧溪。"]'),
('song-ci-550','宴桃源・如梦令','王之道','宋','宋词','song-ci','宴桃源・如梦令','[]','飞雪舞稀还骤。',40,'宋词/ci.song.7000.json','["飞雪舞稀还骤。", "高阁下临群岫。", "独立遂移时，归去黄昏前后。", "知否。", "知否。", "落笔骚人赋就。"]'),
('song-ci-551','宴桃源・如梦令','王之道','宋','宋词','song-ci','宴桃源・如梦令','[]','风急柳花飞骤。',40,'宋词/ci.song.7000.json','["风急柳花飞骤。", "白尽千林万岫。", "樵担晚来归，正在栖鸦啼后。", "知否。", "知否。", "语到谢娘诗就。"]'),
('song-ci-552','宴桃源・如梦令','王之道','宋','宋词','song-ci','宴桃源・如梦令','[]','黄叶声迟风歇。',40,'宋词/ci.song.7000.json','["黄叶声迟风歇。", "龛火夜寒明灭。", "残月却多情，来照先生归辙。", "清绝。", "清绝。", "透隙飞霜似雪。"]'),
('song-ci-553','宴桃源・如梦令','王之道','宋','宋词','song-ci','宴桃源・如梦令','[]','遥指汤泉西路。',40,'宋词/ci.song.7000.json','["遥指汤泉西路。", "隐约碧云天暮。", "宿鸟择深枝，两两相呼如语。", "凝伫。", "凝伫。", "今夜梦魂何处。"]'),
('song-ci-554','宴桃源・如梦令','王之道','宋','宋词','song-ci','宴桃源・如梦令','[]','水外漫山桃李。',40,'宋词/ci.song.7000.json','["水外漫山桃李。", "那得个中风味。", "一种最怜渠，酒著佳人半醉。", "还似。", "还似。", "惊起午窗春睡。"]'),
('song-ci-555','折丹桂','王之道','宋','宋词','song-ci','折丹桂','["\u897f\u6e56"]','照人何处双瞳碧。',60,'宋词/ci.song.7000.json','["照人何处双瞳碧。", "欲去江城北。", "过江风顺莫迟留，快雁序、飞联翼。", "西湖花柳传消息。", "知是东君客。", "家书须办写泥金，报科名、题淡墨。"]'),
('song-ci-556','折丹桂','王之道','宋','宋词','song-ci','折丹桂','[]','风漪欲皱春江碧。',60,'宋词/ci.song.7000.json','["风漪欲皱春江碧。", "予寄江城北。", "子今东去赴春官，挽不住、抟风翼。", "修程应过天池息。", "何处堪留客。", "预知仙籍桂香浮，语祝史、休占墨。"]'),
('song-ci-557','折丹桂','王之道','宋','宋词','song-ci','折丹桂','[]','雪晴山色分遥碧。',61,'宋词/ci.song.7000.json','["雪晴山色分遥碧。", "辉映江南北。", "子今东去步蟾宫，看少展、垂天翼。", "晚来江上西风息。", "算不是新丰客。", "明年三月见君时，庆章绶、纡铜墨。"]'),
('song-ci-558','八声甘州','王之道','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','叹关河在眼、孰雌雄，兴废古犹今。',118,'宋词/ci.song.7000.json','["叹关河在眼、孰雌雄，兴废古犹今。", "问中原何处，黄尘千里，远水平林。", "闻说讴谣思汉，人有望霓心。", "想垂髫戴白，泣涕盈襟。", "流水高山还会，意不烦挥按，如见虞琴。", "□逶迟周道，四牡骤骎骎。", "尽诹谋询度归来，聊缓辔、岁晚雪霜深。", "西湖好，光风迟日，同快吴吟。"]'),
('song-ci-559','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','风揭珠帘寒乍透。',72,'宋词/ci.song.7000.json','["风揭珠帘寒乍透。", "青娥不住添香兽。", "火暖画檐鸣线溜。", "人醉后。", "锦堂丝竹烘残昼。", "势合湖山增地厚。", "孤高但觉修篁瘦。", "回策如萦今在手。", "骄马骤。", "吾家金埒新编就。"]'),
('song-ci-560','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','岩电晶荧君未老。',72,'宋词/ci.song.7000.json','["岩电晶荧君未老。", "看看门外锋车到。", "一点眉间黄色好。", "人尽道。", "从今次第登三少。", "左右青娥来巧笑。", "注唇涂额新妆了。", "斜插梅花仍斗妙。", "歌窈窕。", "醉来容我相嘲傲。"]'),
('song-ci-561','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','岁月漂流人易老。',72,'宋词/ci.song.7000.json','["岁月漂流人易老。", "东郊又报春来到。", "梅靥柳眉还斗好。", "君信道。", "衰颜得酒重年少。", "对酒邀宾同燕笑。", "莫教虚过芳菲了。", "咳唾珠玑夸笔妙。", "人窈窕。", "新声倾坐渔家傲。"]'),
('song-ci-562','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','灯火熙熙来稚老。',72,'宋词/ci.song.7000.json','["灯火熙熙来稚老。", "喜逢灯夕都齐到。", "花市绮楼随处好。", "人竟道。", "今年天气常年少。", "五马行游还坐笑。", "公堂帘卷东风了。", "箫鼓喧阗歌舞妙。", "人窈窕。", "也应引动南窗傲。"]'),
('song-ci-563','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','系国安危还故老。',72,'宋词/ci.song.7000.json','["系国安危还故老。", "鹤书赴陇行当到。", "多谢不遗敦雅好。", "应信道。", "年高德劭如公少。", "尊酒论文聊一笑。", "肯将苦语夸危了。", "落笔君房天下妙。", "环窈窕。", "清歌一曲渔家傲。"]'),
('song-ci-564','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','海岱惟青遗一老。',72,'宋词/ci.song.7000.json','["海岱惟青遗一老。", "禁垣清切亲曾到。", "独直固劳非所好。", "谁信道。", "才如权相从来少。", "把酒自歌还自笑。", "醉中万事都齐了。", "绝唱清歌仍敏妙。", "声窈窕。", "行云初遏渔家傲。"]'),
('song-ci-565','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','爵齿俱尊惟此老。',72,'宋词/ci.song.7000.json','["爵齿俱尊惟此老。", "诗词笔力谁能到。", "奇字古文仍笃好。", "须信道。", "如公宁复忧才少。", "剩费黄金应买笑。", "穷通得丧都忘了。", "坐对瑶觞看舞妙。", "携窈窕。", "南窗聊得渊明傲。"]'),
('song-ci-566','渔家傲','王之道','宋','宋词','song-ci','渔家傲','[]','老老恩波今及老。',72,'宋词/ci.song.7000.json','["老老恩波今及老。", "诏书前日新颁到。", "视膳慈宁先嗜好。", "隆孝道。", "慕逾五十前王少。", "想见天颜温色笑。", "东朝上寿称觞了。", "易俗功深神且妙。", "来窈窕。", "德齐任姒消骄傲。"]'),
('song-ci-567','浪淘沙','王之道','宋','宋词','song-ci','浪淘沙','[]','高髻堕香鬟。',64,'宋词/ci.song.7000.json','["高髻堕香鬟。", "遗恨眉山。", "老年花似梦中看。", "厌浥一枝漙晓露，珠泪阑干。", "卮酒发酡颜。", "休更留残。", "满城风雨麦秋寒。", "馀馥尚能消酒恶，谁敢包弹。"]'),
('song-ci-568','忆东坡','王之道','宋','宋词','song-ci','忆东坡','[]','雪霁柳舒容，日薄梅摇影。',116,'宋词/ci.song.7000.json','["雪霁柳舒容，日薄梅摇影。", "新岁换符来，天上初见颁桃梗。", "试问我酬君唱，何如博塞欢娱，百万呼卢胜。", "投珠报玉，须放骚人遣春兴。", "诗成谈笑，写出无穷景。", "不妨时作颠草，驰骋张芝圣。", "谁念杜陵野老，心同流水必东，与物初无竞。", "公侯应有种哉，倾否由天命。"]'),
('song-ci-569','忆东坡','王之道','宋','宋词','song-ci','忆东坡','[]','虚堂响应声，皎月形和影。',116,'宋词/ci.song.7000.json','["虚堂响应声，皎月形和影。", "春到也须还，长红多紫啼条梗。", "况有光风丽日，能消积雪繁霜，青女休言胜。", "扶摇借便，请看天池发鹏兴。", "人言强汉，治道夸文景。", "谁能尧舜其君，远继阿衡圣。", "富贵吾所自有，宰相时来则为，自不烦趋竞。", "欲寻文会诗盟，得酒且相命。"]'),
('song-ci-570','六州歌头','王之道','宋','宋词','song-ci','六州歌头','[]','燧瑊勋业，何敢望西平。',182,'宋词/ci.song.7000.json','["燧瑊勋业，何敢望西平。", "观当日，清大憝，震天声。", "绩其凝。", "追配汾阳郭，临淮李，扫妖孽，植颠仆，复疆宇，洗膻腥。", "堪叹中原久矣，长淮隔、胡骑纵横。", "问何时，风驱电扫，重见文明。", "宾雁宵鸣。", "梦初惊。", "念吾君复古，修攘两尽，早晚功成。", "岁云暮，冰腹壮，雪华零。", "怅神京。", "谁信汉家陵阙，呵护有神兵。", "罄寰海，重回首，镇关情。", "想见皇华咨度，望淮北、心曲摇旌。", "愿变夷用夏，荆狄是惩膺。", "补弊支倾。"]'),
('song-ci-571','好事近','王之道','宋','宋词','song-ci','好事近','[]','春色到梅梢，人在东风清嚏。',53,'宋词/ci.song.7000.json','["春色到梅梢，人在东风清嚏。", "曾见少微初降，蔼龙泉佳气。", "功名富贵属多才，如子已无几。", "造物恰同予意，放骅骝千里。"]'),
('song-ci-572','好事近','王之道','宋','宋词','song-ci','好事近','[]','霞影入瑶觞，酒与馀霞同色。',53,'宋词/ci.song.7000.json','["霞影入瑶觞，酒与馀霞同色。", "人共昌朝方永，过觥筹三百。", "一枝红皱石榴裙，帘卷篆烟碧。", "约我他年湖上，看九华终日。"]'),
('song-ci-573','好事近','王之道','宋','宋词','song-ci','好事近','[]','秋色到东篱，金散菊团香馥。',53,'宋词/ci.song.7000.json','["秋色到东篱，金散菊团香馥。", "预借浮觞高会，为作长年祝。", "蟹螯如臂酒如渑，橙橘半黄绿。", "唱我新词一釂，听尊前丝竹。"]'),
('song-ci-574','好事近','王之道','宋','宋词','song-ci','好事近','[]','花影到酴醿，风过玉卮摇碧。',53,'宋词/ci.song.7000.json','["花影到酴醿，风过玉卮摇碧。", "坐上酒豪诗敌，尽骑鲸仙客。", "主人名姓在金瓯，归去定前席。", "要见碧桃千岁，看壶中春日。"]'),
('song-ci-575','好事近','王之道','宋','宋词','song-ci','好事近','[]','春色到酴醿，人在酴醿花底。',53,'宋词/ci.song.7000.json','["春色到酴醿，人在酴醿花底。", "花扑尊罍香透，远胜烧沈水。", "一杯聊复对东风，为祝千千岁。", "作楫和羹事了，归去骑箕尾。"]'),
('song-ci-576','木兰花慢','王之道','宋','宋词','song-ci','木兰花慢','[]','对春光淡沲，烟冉冉、日迟迟。',125,'宋词/ci.song.7000.json','["对春光淡沲，烟冉冉、日迟迟。", "渐红入桃溪，青回柳陌，莺刷金衣。", "差池。", "竞求友去，恼佳人、幽恨上蛾眉。", "应念年时追逐，妆馀为带交枝。", "芳菲。", "谁共赏游嬉。", "何处马如飞。", "□不道新来，牵肠惹肚，暗减腰肢。", "须知。", "乍寒乍暖，褪朱唇、又过海棠时。", "已约姚黄魏紫，留花等待伊归。"]'),
('song-ci-577','感皇恩','王之道','宋','宋词','song-ci','感皇恩','[]','宿雾霁晨霜，江山明秀。',81,'宋词/ci.song.7000.json','["宿雾霁晨霜，江山明秀。", "照眼黄花乱晴昼。", "当年今日，正是悬弧时候。", "一杯聊献祝，同亲旧。", "莫问穷通，休论贫富。", "且趁良辰醉醇酎。", "扬珠捣玉，况值西成多收。", "饱餐歌至治，天垂祐。"]'),
('song-ci-578','石州慢','王之道','宋','宋词','song-ci','石州慢','[]','天迥楼高，日长院静，琴声幽咽。',123,'宋词/ci.song.7000.json','["天迥楼高，日长院静，琴声幽咽。", "昵昵恩情，切切言语，似伤离别。", "子期何处，漫高山流水，又逐新声彻。", "仿佛江上移舟，听琵琶凄切。", "休说。", "春寒料峭，夜来花柳，弄风摇雪。", "大错因谁，算不翅六州铁。", "波下双鱼，云中乘雁，嗣音无计，空叹初谋拙。", "但愿相逢，同心再绾重结。"]'),
('song-ci-579','一翦梅','王之道','宋','宋词','song-ci','一翦梅','[]','风揭珠帘夜气清。',72,'宋词/ci.song.7000.json','["风揭珠帘夜气清。", "香扑尊罍，初见云英。", "蓝桥何处旧知名。", "今夕相逢，此恨消停。", "劝酒嫣然一笑倾。", "细意端相，无限娉婷。", "曲终犹带绕梁声。", "莫辞沈醉，为覆金觥。"]'),
('song-ci-580','汉宫春','王之道','宋','宋词','song-ci','汉宫春','[]','欢动江城，快风声震地，云势颓山。',118,'宋词/ci.song.7000.json','["欢动江城，快风声震地，云势颓山。", "半年不雨，玉霙来溉冬乾。", "飘飘弱絮，杂檐花、飞上宾筵。", "疏林表，数行征雁，翱翔欲下清湾。", "何处梅梢点白，弄横斜疏影，竹外溪边。", "天寒日暮，含香脉脉无言。", "朱唇玉颊，映碧梧、峙鹄停鸾。", "最好是，携壶挈榼，相期同醉霜天。"]'),
('song-ci-581','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','一撮檀心，春来还对东君吐。',50,'宋词/ci.song.7000.json','["一撮檀心，春来还对东君吐。", "莫随春去。", "我欲花间住。", "燕子衔泥，似向吾人诉。", "烦相语。", "九龄风度。", "流落今何处。"]'),
('song-ci-582','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','珠幰霜蕤，晚来芬馥清香吐。',50,'宋词/ci.song.7000.json','["珠幰霜蕤，晚来芬馥清香吐。", "流莺飞去。", "应上花梢住。", "一曲阳春，聊对东风诉。", "无多语。", "韶光暗度。", "恨到分携处。"]'),
('song-ci-583','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','宿雨朝寒，芳时又过酴醿了。',50,'宋词/ci.song.7000.json','["宿雨朝寒，芳时又过酴醿了。", "舞环歌绕。", "应恨金杯小。", "零乱霜蕤，点缀青青草。", "花间道。", "曾遭花恼。", "把酒呼晴昊。"]'),
('song-ci-584','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','短棹西来，追随不及桃花宴。',50,'宋词/ci.song.7000.json','["短棹西来，追随不及桃花宴。", "薰风庭院。", "明月裁纨扇。", "睡起娇慵，想见云鬟乱。", "双鱼远。", "欲凭春唤。", "一觇韦娘面。"]'),
('song-ci-585','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','透幕穿帘，回风舞态能轻妙。',50,'宋词/ci.song.7000.json','["透幕穿帘，回风舞态能轻妙。", "不须相恼。", "江上春来了。", "一阕清歌，唱彻琼楼晓。", "春工巧。", "柳颦梅笑。", "点缀芳菲早。"]'),
('song-ci-586','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','竹外梅花，檀心玉颊春初透。',50,'宋词/ci.song.7000.json','["竹外梅花，檀心玉颊春初透。", "一池风皱。", "妙语天生就。", "有个人人，袅娜灵和柳。", "君知否。", "目成心授。", "何日同携手。"]'),
('song-ci-587','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','春意催花，片云又作朝来雨。',50,'宋词/ci.song.7000.json','["春意催花，片云又作朝来雨。", "淡匀深注。", "红紫纷无数。", "社日人家，准拟行春去。", "痴儿女。", "倚门凝伫。", "借问东郊路。"]'),
('song-ci-588','点绛唇','王之道','宋','宋词','song-ci','点绛唇','[]','古屋衰杨，淡烟疏雨江南岸。',50,'宋词/ci.song.7000.json','["古屋衰杨，淡烟疏雨江南岸。", "几家村疃。", "酒旆还相唤。", "短棹扁舟，风横河频转。", "柔肠断。", "寒鸦噪晚。", "天共蒹葭远。"]'),
('song-ci-589','虞美人','王之道','宋','宋词','song-ci','虞美人','[]','酪浆冷浸金盘粉。',66,'宋词/ci.song.7000.json','["酪浆冷浸金盘粉。", "玉友浮新酝。", "如君真是酒中仙。", "一斗百篇、吟到小池莲。", "清风拂拂来纨素。", "独擅江南步。", "红裙无用妒芳姿。", "且把绿罗、争学画长眉。"]'),
('song-ci-590','虞美人','王之道','宋','宋词','song-ci','虞美人','[]','郑侯美政推仁厚。',66,'宋词/ci.song.7000.json','["郑侯美政推仁厚。", "何独高淮右。", "分携令我预颦眉。", "只恐桐庐民望、怪来迟。", "一尊聊罄金蕉叶。", "更语半时霎。", "青娥罗列竞消凝。", "阁定眼边珠泪、做红冰。"]'),
('song-ci-591','小重山','王之道','宋','宋词','song-ci','小重山','[]','要识长生辈赤松。',70,'宋词/ci.song.7000.json','["要识长生辈赤松。", "朱颜和绿发，正丰茸。", "当年今日堕仙宫。", "佳气郁，香霭菊花风。", "一醉拚千锺。", "小槽新酿美，玉泉浓。", "酒酣诗思浩无穷。", "云烟烂，题破锦笺红。"]'),
('song-ci-592','小重山','王之道','宋','宋词','song-ci','小重山','[]','花艳嫣然照坐红。',70,'宋词/ci.song.7000.json','["花艳嫣然照坐红。", "池光高下见，木芙蓉。", "相从款款莫匆匆。", "新酿熟，浮瓮碧香浓。", "倚槛送飞鸿。", "登高时节近，菊披风。", "笑谈今喜一杯同。", "揉金蕊，和露入杯中。"]'),
('song-ci-593','秦楼月・忆秦娥','王之道','宋','宋词','song-ci','秦楼月・忆秦娥','[]','云不卷。',56,'宋词/ci.song.7000.json','["云不卷。", "浇愁莫放金杯浅。", "金杯浅。", "新词丽句，要人裁翦。", "酒酣思致天同远。", "临风捉笔纶巾岸。", "纶巾岸。", "诗成归去，寒光照晚。"]'),
('song-ci-594','满江红','王之道','宋','宋词','song-ci','满江红','[]','竹马来迎，留不住、寸心如结。',112,'宋词/ci.song.7000.json','["竹马来迎，留不住、寸心如结。", "□历湖、须坞相望，近同吴越。", "阙里风流今未减，此行报政看期月。", "已验康沂富国，千古曾无别。", "多谢润沾枯辙。", "令我神思清发。", "□新命欢浃，两邦情惬。", "明日西风帆卷席。", "高樯到处旌麾列。", "忽相思，吾当往，谁谓三墩隔。"]'),
('song-ci-595','望海潮','王之道','宋','宋词','song-ci','望海潮','[]','宝山烟霁，金湖波渺，珠帘高卷清霜。',129,'宋词/ci.song.7000.json','["宝山烟霁，金湖波渺，珠帘高卷清霜。", "枫叶露痕，荻花风色，人言今日重阳。", "芳菊袅秋香。", "更榴房斗紫，柑实传黄。", "观阁凌空，杯盘照坐独醒狂。", "良辰乐事难忘。", "正少年游冶，人在任庄。", "铜钵探题，金钗当酒，一时绿鬓红妆。", "故国黯凄凉。", "漫情随水远，兴与云长。", "要是致君尧舜，千古继垂裳。"]'),
('song-ci-596','如梦令','王之道','宋','宋词','song-ci','如梦令','[]','绰约一枝红怨。',40,'宋词/ci.song.7000.json','["绰约一枝红怨。", "疏雨淡烟池馆。", "梅子欲黄时，日倚朱阑几遍。", "争看。", "争看。", "人在沈香亭畔。"]'),
('song-ci-597','如梦令','王之道','宋','宋词','song-ci','如梦令','[]','叶底芳蕤如缀。',40,'宋词/ci.song.7000.json','["叶底芳蕤如缀。", "坐对广庭忘味。", "娇呆最怜伊，乱糁舞馀风袂。", "贪喜。", "贪喜。", "不觉宝钗斜坠。"]'),
('song-ci-598','如梦令','王之道','宋','宋词','song-ci','如梦令','[]','一饷凝情无语。',40,'宋词/ci.song.7000.json','["一饷凝情无语。", "手拈梅花何处。", "倚竹不胜愁，暗想江头归路。", "东去。", "东去。", "短艇淡烟疏雨。"]'),
('song-ci-599','临江仙','王之道','宋','宋词','song-ci','临江仙','[]','红楼缥缈光风里，熙熙和气欢声。',70,'宋词/ci.song.7000.json','["红楼缥缈光风里，熙熙和气欢声。", "遏云馀韵最关情。", "春山闲淡淡，秋水醉盈盈。", "老去自怜心尚在，相逢殊慰劳生。", "纹楸聊复戏同枰。", "试烦歌一曲，须借酒三行。"]'),
('song-ci-600','临江仙','王之道','宋','宋词','song-ci','临江仙','[]','鼓棹正逢江雪霁，是行应快吴吟。',70,'宋词/ci.song.7000.json','["鼓棹正逢江雪霁，是行应快吴吟。", "透云寒日半晴阴。", "烟岚凝翠重，霜树溅红深。", "案上文书闲展读，圣贤踪迹重寻。", "不堪华发故骎骎。", "三旌还有分，万事付无心。"]'),
('song-ci-601','临江仙','王之道','宋','宋词','song-ci','临江仙','[]','怪得举头闻鹊喜，果然都骑相过。',70,'宋词/ci.song.7000.json','["怪得举头闻鹊喜，果然都骑相过。", "柳阴乘月倒金荷。", "疏星明耿耿，银汉静无波。", "总角追随今老矣，相逢无惜婆娑。", "夜阑馀兴到狂歌。", "长鲸方正渴，应不厌倾河。"]'),
('song-ci-602','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','朱实盈盈露，黄花细细风。',62,'宋词/ci.song.7000.json','["朱实盈盈露，黄花细细风。", "龙山胜集古今同。", "断送一年秋色、酒杯中。", "鸭脚供柔白，鸡头荐嫩红。", "量吞云梦正能容。", "试问具区何处、浙江东。"]'),
('song-ci-603','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','老懒诗才退，春融醉眼昏。',62,'宋词/ci.song.7000.json','["老懒诗才退，春融醉眼昏。", "青山终日对柴门。", "柳外断桥流水、几家村。", "桃李添新意，池塘失旧痕。", "一尊聊复为君温。", "倾倒年来酬唱、细论文。"]'),
('song-ci-604','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','扇里薰风细，壶中化日长。',62,'宋词/ci.song.7000.json','["扇里薰风细，壶中化日长。", "榴花高下照红妆。", "花外云飞馥郁、水沈香。", "新竹轻储粉，流莺巧弄簧。", "不知何处是华阳。", "应有千年白李、荐霞觞。"]'),
('song-ci-605','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','玉露澄天宇，金风净月华。',62,'宋词/ci.song.7000.json','["玉露澄天宇，金风净月华。", "满庭秋色木犀花。", "记得谪仙初下、五云车。", "才业追前辈，人门属当家。", "寿觞无惜醉流霞。", "闻说姓名潜护、有笼纱。"]'),
('song-ci-606','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','角簟横龟枕，兰房挂艾人。',62,'宋词/ci.song.7000.json','["角簟横龟枕，兰房挂艾人。", "一尊菖歜泛清醇。", "好在佳人如玉、映长春。", "冰彻杯盘莹，香和笑语薰。", "莲花衫子入时新。", "挂起南窗一榻、晚风清。"]'),
('song-ci-607','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','玉斝浮菖虎，金盘馈鰁鱼。',62,'宋词/ci.song.7000.json','["玉斝浮菖虎，金盘馈鰁鱼。", "研丹聊作厌兵符。", "何必城头一女、当千夫。", "雨过山如洗，风来草似梳。", "佳人不惯手谈输。", "却道如今重赌、选官图。"]'),
('song-ci-608','南歌子','王之道','宋','宋词','song-ci','南歌子','[]','露竹舒新绿，风荷递暗香。',62,'宋词/ci.song.7000.json','["露竹舒新绿，风荷递暗香。", "谁家池馆睡鸳鸯。", "还有玉人相对、坐传觞。", "角簟清冰滑，纱厨薄雾凉。", "晚来行雨过巫阳。", "强整罗衣临镜、学宫妆。"]'),
('song-ci-609','念奴娇','王之道','宋','宋词','song-ci','念奴娇','[]','碧天无际，乍雨清烟霭，风开云月。',121,'宋词/ci.song.7000.json','["碧天无际，乍雨清烟霭，风开云月。", "人在南楼，剧谈胜咏，拥碧油旌节。", "银阙腾辉，冰轮驾彩，颢气资高洁。", "大星不见，更容萤火明灭。", "须烦翠杓琼杯，华笺象管，与我酬清绝。", "谁使琵琶声到耳，轻赋荻花枫叶。", "露脚斜飞，河阴低转，香篆环三杰。", "莫辞终日，舞腰重看回雪。"]'),
('song-ci-610','念奴娇','王之道','宋','宋词','song-ci','念奴娇','[]','黄花照眼，对西风庭槛，为渠凝伫。',120,'宋词/ci.song.7000.json','["黄花照眼，对西风庭槛，为渠凝伫。", "准拟登高酬一醉，底事晚来微雨。", "蟋蟀声中，芭蕉叶上，怎得争如许。", "龙山何处，无言暗想烟树。", "须知天意随人，重阳晴未晚，不须频诉。", "幸有兵厨三万斛，足助赏心欢趣。", "千里江山，两行珠翠，端为骚人付。", "层楼飞观，应容老子追步。"]'),
('song-ci-611','贺新郎','王之道','宋','宋词','song-ci','贺新郎','[]','又是春残去，倚东风、寒云淡日，堕红飘絮。',142,'宋词/ci.song.7000.json','["又是春残去，倚东风、寒云淡日，堕红飘絮。", "燕社鸿秋人不问，尽管吴声越鼓。", "但短发、星星无数。", "万事惟消彭泽醉，也何妨、袖卷长沙舞。", "身与世，只如许。", "阑干拍手闲情绪。", "便明朝、苍烟白鹭，北山南浦。", "笑指午桥桥畔路，帘幕深深院宇。", "尚趁得、柳烟花雾。", "我亦故山猿鹤怨，问何时、归棹双溪渚。", "歌一曲，恨千缕。"]'),
('song-ci-612','菩萨蛮','王之道','宋','宋词','song-ci','菩萨蛮','[]','藕丝衫剪轻红窄。',52,'宋词/ci.song.7000.json','["藕丝衫剪轻红窄。", "衫轻不碍琼肤白。", "缦鬓小横波。", "花楼东是家。", "上湖闲荡桨。", "粉艳芙蓉榜。", "湖水亦多情。", "照妆天底清。"]'),
('song-ci-613','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','怒潮卷雪，魏岫布云，越襟吴带如斯。',156,'宋词/ci.song.7000.json','["怒潮卷雪，魏岫布云，越襟吴带如斯。", "有客经游，月伴风随。", "值盛世。", "观此江山美。", "合放怀、何事却兴悲。", "不为回头，旧谷天涯。", "为想前君事。", "越王嫁祸献西施。", "吴即中深机。", "阖庐死。", "有遗誓。", "句践必诛夷。", "吴未干戈出境，仓卒越兵，投怒夫差。", "鼎沸鲸鲵。", "越遭劲敌，可怜无计脱重围。", "归路茫然，城郭丘墟，飘泊稽山里。", "旅魂暗逐战尘飞。", "天日惨无辉。"]'),
('song-ci-614','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','自笑平生，英气凌云，凛然万里宣威。',151,'宋词/ci.song.7000.json','["自笑平生，英气凌云，凛然万里宣威。", "那知此际。", "熊虎涂穷，来伴麋鹿卑栖。", "既甘臣妾，犹不许，何为计。", "争若都燔宝器。", "尽诛吾妻子。", "径将死战决雄雌。", "天意恐怜之。", "偶闻太宰，正擅权，贪赂市恩私。", "因将宝玩献诚，虽脱霜戈，石室囚系。", "忧嗟又经时。", "恨不如巢燕自由归。", "残月朦胧，寒雨萧萧，有血都成泪。", "备尝险厄返邦畿。", "冤愤刻肝脾。"]'),
('song-ci-615','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','种陈谋，谓吴兵正炽。',138,'宋词/ci.song.7000.json','["种陈谋，谓吴兵正炽。", "越勇难施。", "破吴策，唯妖姬。", "有倾城妙丽。", "名称西子。", "岁方笄。", "算夫差惑此。", "须致颠危。", "范蠡微行，珠贝为香饵。", "苎萝不钓钓深闺。", "吞饵果殊姿。", "素肌纤弱，不胜罗绮。", "鸾镜畔、粉面淡匀，梨花一朵琼壶里。", "嫣然意态娇春，寸眸剪水。", "斜鬟松翠。", "人无双、宜名动君王，绣履容易。", "来登玉阶。"]'),
('song-ci-616','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','窣湘裙，摇汉佩。',119,'宋词/ci.song.7000.json','["窣湘裙，摇汉佩。", "步步香风起。", "敛双蛾，论时事。", "兰心巧会君意。", "殊珍异宝，犹自朝臣未与。", "妾何人，被此隆恩，虽令效死。", "奉严旨。", "隐约龙姿忻悦。", "重把甘言说。", "辞俊雅，质娉婷，天教汝、众美兼备。", "闻吴重色，凭汝和亲，应为靖边陲。", "将别金门，俄挥粉泪。", "靓妆洗。"]'),
('song-ci-617','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','飞云驶。',106,'宋词/ci.song.7000.json','["飞云驶。", "香车故国难回睇。", "芳心渐摇，迤逦吴都繁丽。", "忠臣子胥，预知道为邦崇。", "谏言先启。", "愿勿容其至。", "周亡褒姒。", "商倾妲己。", "吴王却嫌胥逆耳。", "才经眼、便深恩爱。", "东风暗绽娇蕊。", "彩鸾翻妒伊。", "得取次、于飞共戏。", "金屋看承，他宫尽废。"]'),
('song-ci-618','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','华宴夕，灯摇醉。',121,'宋词/ci.song.7000.json','["华宴夕，灯摇醉。", "粉菡萏，笼蟾桂。", "扬翠袖，含风舞，轻妙处，惊鸿态。", "分明是。", "瑶台琼榭，阆苑蓬壶，景尽移此地。", "花绕仙步，莺随管吹。", "宝帐暖留春，百和馥郁融鸳被。", "银漏永，楚云浓，三竿日、犹褪霞衣。", "宿酲轻腕，嗅宫花，双带系。", "合同心时。", "波下比目，深怜到底。"]'),
('song-ci-619','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','耳盈丝竹，眼摇珠翠。',109,'宋词/ci.song.7000.json','["耳盈丝竹，眼摇珠翠。", "迷乐事。", "宫闱门。", "争知。", "渐国势凌夷。", "奸臣献佞，转恣奢淫，天谴岁屡饥。", "从此万姓离心解体。", "越遣使。", "阴窥虚实，蚤夜营边备。", "兵未动，子胥存，虽堪伐、尚畏忠义。", "斯人既戮，又且严兵卷土，赴黄池观衅，种蠡方云可矣。"]'),
('song-ci-620','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','机有神，征鼙一鼓，万马襟喉地。',119,'宋词/ci.song.7000.json','["机有神，征鼙一鼓，万马襟喉地。", "庭喋血，诛留守，怜屈服，敛兵还，危如此。", "当除祸本，重结人心，争奈竟荒迷。", "战骨方埋，灵旗又指。", "势连败。", "柔荑携泣。", "不忍相抛弃。", "身在兮，心先死。", "宵奔兮，兵已前围。", "谋穷计尽，泪鹤啼猿，闻处分外悲。", "丹穴纵近，谁容再归。"]'),
('song-ci-621','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','哀诚屡吐，甬东分赐。',111,'宋词/ci.song.7000.json','["哀诚屡吐，甬东分赐。", "垂暮日，置荒隅，心知愧。", "宝锷红委。", "鸾存凤去，辜负恩怜，情不似虞姬。", "尚望论功，荣还故里。", "降令曰，吴亡赦汝，越与吴何异。", "吴正怨，越方疑。", "从公论、合去妖类。", "蛾眉宛转，竟殒鲛绡，香骨委尘泥。", "渺渺姑苏，荒芜鹿戏。"]'),
('song-ci-622','薄媚','董颖','宋','宋词','song-ci','薄媚','[]','王公子。',101,'宋词/ci.song.7000.json','["王公子。", "青春更才美。", "风流慕连理。", "耶溪一日，悠悠回首凝思。", "云鬟烟鬓，玉佩霞裾，依约露妍姿。", "送目惊喜。", "俄迂玉趾。", "同仙骑。", "洞府归去，帘栊窈窕戏鱼水。", "正一点犀通，遽别恨何已。", "媚魄千载，教人属意。", "况当时。", "金殿里。"]'),
('song-ci-623','卜算子','董颖','宋','宋词','song-ci','卜算子','[]','春浅借和风，吹绿庭皋树。',52,'宋词/ci.song.7000.json','["春浅借和风，吹绿庭皋树。", "依约屏间出紫云，入阁风流处。", "便做铁心肠，也为梅花语。", "欲去东君更挽留，巧栈烟霞路。"]'),
('song-ci-624','满庭芳','董颖','宋','宋词','song-ci','满庭芳','[]','红斗风桃，绿肥烟草，杨柳春暗重门。',117,'宋词/ci.song.7000.json','["红斗风桃，绿肥烟草，杨柳春暗重门。", "五陵佳兴，酿酝付芳尊。", "窈窕笙箫丛里，金猊篆、雾绕云纷。", "勾情也，歌眉低翠，依约鹧鸪村。", "人生须快意，十分春事，才破三分。", "况点检年时，胜客都存。", "更把馀欢卜夜，纵彻晓、蜡泪流痕。", "花阴昼，朱帘未卷，犹自醉昏昏。"]'),
('song-ci-625','满庭芳','潘良贵','宋','宋词','song-ci','满庭芳','[]','夹水松篁，一天风露，觉来身在扁舟。',118,'宋词/ci.song.7000.json','["夹水松篁，一天风露，觉来身在扁舟。", "桂花当午，云卷素光流。", "起傍篷窗危坐，飘然竟、欲到瀛洲。", "人世乐，那知此夜，空际列琼楼。", "休休。", "闲最好，十年归梦，两眼乡愁。", "谩赢得、萧萧华发盈头。", "往事不须追谏，从今去、拂袖何求。", "一尊酒，持杯顾影，起舞自相酬。"]'),
('song-ci-626','柳梢青','董德元','宋','宋词','song-ci','柳梢青','[]','满腹文章，满头霜雪，满面埃尘。',61,'宋词/ci.song.7000.json','["满腹文章，满头霜雪，满面埃尘。", "直至如今，别无收拾，只有清贫。", "功名已是因循。", "最懊恨、张巡李巡。", "几个明年，几番好运，只是瞒人。"]'),
('song-ci-627','青玉案','冯时行','宋','宋词','song-ci','青玉案','[]','年时江上垂杨路。',80,'宋词/ci.song.7000.json','["年时江上垂杨路。", "信柱杖、穿云去。", "碧涧步虚声里度。", "疏林小寺，远山孤渚，独倚阑干处。", "别来无几春还暮。", "空记当时锦囊句。", "南北东西知几许。", "相思难寄，野航蓑笠，独钓巴江雨。"]'),
('song-ci-628','虞美人','冯时行','宋','宋词','song-ci','虞美人','[]','东君已了韶华媚。',66,'宋词/ci.song.7000.json','["东君已了韶华媚。", "未快芳菲意。", "临居倾倒向荼䕷。", "十万宝珠璎珞、带风垂。", "合欢翠玉新呈瑞。", "十日傍边醉。", "今年花好为谁开。", "欲寄一枝无处、觅阳台。"]'),
('song-ci-629','虞美人','冯时行','宋','宋词','song-ci','虞美人','[]','芳菲不是浑无据。',66,'宋词/ci.song.7000.json','["芳菲不是浑无据。", "只是春收取。", "都将酝造晚风光。", "百尺瑶台、吹下半天香。", "多愁多病疏慵意。", "也被香扶起。", "微吟小酌送花飞。", "更拚小屏幽梦、到开时。"]'),
('song-ci-630','虞美人','冯时行','宋','宋词','song-ci','虞美人','[]','去年同醉黄花下。',66,'宋词/ci.song.7000.json','["去年同醉黄花下。", "采采香盈把。", "今年仍复对黄花。", "醉里不羞斑鬓、落乌纱。", "劝君莫似阳关柳。", "飞伴离亭酒。", "愿君只似月常圆。", "还使人人一月、一回看。"]'),
('song-ci-631','渔家傲','冯时行','宋','宋词','song-ci','渔家傲','[]','云复衡茅霜雪后。',72,'宋词/ci.song.7000.json','["云复衡茅霜雪后。", "风吹江面青罗皱。", "镜里功名愁里瘦。", "闲袖手。", "去年长至今年又。", "梅逼玉肌春欲透。", "小槽新压冰澌溜。", "好把升沈分付酒。", "光阴骤。", "须臾又绿章台柳。"]'),
('song-ci-632','天仙子','冯时行','宋','宋词','song-ci','天仙子','[]','风幸多情开得好。',80,'宋词/ci.song.7000.json','["风幸多情开得好。", "忍却吹教零落了。", "弄花衣上有馀香，春已老。", "枝头少。", "况又酒醒鶗鴂晓。", "一片初飞情已悄。", "可更如今纷不扫。", "年随流水去无踪，恨不了。", "愁不了。", "楼外远山眉样小。"]'),
('song-ci-633','点绛唇','冯时行','宋','宋词','song-ci','点绛唇','[]','十日春风，吹开一岁闲桃李。',50,'宋词/ci.song.7000.json','["十日春风，吹开一岁闲桃李。", "南柯惊起。", "归踏春风尾。", "世事无凭，偶耳成忧喜。", "歌声里。", "落花流水。", "明日人千里。"]'),
('song-ci-634','玉楼春','冯时行','宋','宋词','song-ci','玉楼春','[]','杏花微露春犹浅。',64,'宋词/ci.song.7000.json','["杏花微露春犹浅。", "春浅愁浓愁送远。", "山拖馀翠断行踪，细雨疏烟迷望眼。", "暮云浓处轻吹散。", "往事时时心上见。", "不禁慵瘦倚东风，燕子双双花片片。"]'),
('song-ci-635','点绛唇','冯时行','宋','宋词','song-ci','点绛唇','[]','江上新晴，闲撑小艇寻梅去。',50,'宋词/ci.song.7000.json','["江上新晴，闲撑小艇寻梅去。", "自知梅处。", "香满鱼家路。", "路尽疏篱，一树开如许。", "留人住。", "留人不住。", "黯淡黄昏雨。"]'),
('song-ci-636','点绛唇','冯时行','宋','宋词','song-ci','点绛唇','[]','眉黛低颦，一声春满留苏帐。',50,'宋词/ci.song.7000.json','["眉黛低颦，一声春满留苏帐。", "却从檀响。", "渐到梅花上。", "归卧孤舟，梅影舟前扬。", "劳心想。", "岸横千嶂。", "霜月铺寒浪。"]'),
('song-ci-637','梦兰堂','冯时行','宋','宋词','song-ci','梦兰堂','[]','小雨清尘淡烟晚。',63,'宋词/ci.song.7000.json','["小雨清尘淡烟晚。", "官柳殢花待暖。", "君愁入伤阙眼。", "芳草绿、断云归雁。", "酒重斟，须再劝。", "今夕近、明朝乍远。", "到时暗花飞乱。", "千里断肠春不管。"]'),
('song-ci-638','蓦山溪','冯时行','宋','宋词','song-ci','蓦山溪','[]','艰难时世。',102,'宋词/ci.song.7000.json','["艰难时世。", "万事休夸会。", "官宦误人多，道是也、终须不是。", "功名事业，已是负初心，人老也，发白也，随分谋生计。", "如今晓得，更莫争闲气。", "高下与人和，且觅个、置锥之地。", "江村僻处，作个老渔樵，一壶酒，一声歌，一觉醺醺睡。"]'),
('song-ci-639','醉落魄・一斛珠','冯时行','宋','宋词','song-ci','醉落魄・一斛珠','[]','点酥点蜡。',67,'宋词/ci.song.7000.json','["点酥点蜡。", "凭君尽做风流骨。", "汉家旧样宫妆额。", "流落人间，真个没人识。", "佳人误拨龙香觅。", "一枝初向烟林得。", "被花惹起愁难说。", "恰恨西窗，酒醒乌啼月。"]'),
('song-ci-640','蝶恋花','朱松','宋','宋词','song-ci','蝶恋花','[]','清晓方塘开一镜。',70,'宋词/ci.song.7000.json','["清晓方塘开一镜。", "落絮飞花，肯向春风定。", "点破翠奁人未醒。", "馀寒犹倚芭蕉劲。", "拟托行云医酒病。", "帘卷闲愁，空占红香迳。", "青鸟呼君君莫听。", "日边幽梦从来正。"]'),
('song-ci-641','点绛唇','朱翌','宋','宋词','song-ci','点绛唇','[]','流水泠泠，断桥横路梅枝亚。',50,'宋词/ci.song.7000.json','["流水泠泠，断桥横路梅枝亚。", "雪花飞下。", "浑似江南画。", "白璧青钱，欲买春无价。", "归来也。", "西风平野。", "一点香随马。"]'),
('song-ci-642','朝中措','朱翌','宋','宋词','song-ci','朝中措','[]','玉台金盏对炎光。',57,'宋词/ci.song.7000.json','["玉台金盏对炎光。", "全似去年香。", "有意庄严端午，不应忘却重阳。", "菖蒲九叶，金英满把，同泛瑶觞。", "旧日东篱陶令，北窗正卧义皇。"]'),
('song-ci-643','生查子','朱翌','宋','宋词','song-ci','生查子','[]','宫纱蜂趁梅，宝扇鸾开翅。',48,'宋词/ci.song.7000.json','["宫纱蜂趁梅，宝扇鸾开翅。", "数折聚清风，一捻生秋意。", "摇摇云母轻，袅袅琼枝细。", "莫解玉连环，怕作飞花坠。"]'),
('song-ci-644','阮郎归','陈康伯','宋','宋词','song-ci','阮郎归','[]','闲来溪上有云飞。',56,'宋词/ci.song.7000.json','["闲来溪上有云飞。", "溪光接翠微。", "江南三月落花时。", "春波去棹迟。", "寻竹路，破林扉。", "苍台旧钓矶。", "欲归回首未成归。", "黄尘满素衣。"]'),
('song-ci-645','浪淘沙','陈康伯','宋','宋词','song-ci','浪淘沙','[]','台上凭阑干。',64,'宋词/ci.song.7000.json','["台上凭阑干。", "犹怯春寒。", "被谁偷了最高山。", "将谓六丁移取去，不在人间。", "却是晓寒闲。", "特地遮栏。", "与天一样自漫漫。", "喜得东风收卷尽，依就追还。"]'),
('song-ci-646','踏莎行','欧阳澈','宋','宋词','song-ci','踏莎行','[]','雁字书空，橘星垂槛。',68,'宋词/ci.song.7000.json','["雁字书空，橘星垂槛。", "江天水墨秋光晚。", "香丝袅袅祝尧年，公庭锡宴挥金碗。", "醉索蛮笺，狂吟象管。", "珠玑灿灿惊人眼。", "遏云更倩雪儿歌，从教拍碎红牙板。"]'),
('song-ci-647','蝶恋花','欧阳澈','宋','宋词','song-ci','蝶恋花','[]','红叶飘风秋欲暮。',70,'宋词/ci.song.7000.json','["红叶飘风秋欲暮。", "送目层楼，帘卷西山雨。", "解榻聚宾挥玉尘。", "风流只欠王夷甫。", "质剑为公沽绿醑。", "涤濯吟魂，拟摘黄花句。", "醉眼瞢腾携手处。", "谢池风月谁分付。"]'),
('song-ci-648','玉楼春','欧阳澈','宋','宋词','song-ci','玉楼春','[]','个人风韵天然俏。',64,'宋词/ci.song.7000.json','["个人风韵天然俏。", "入鬓秋波常似笑。", "一弯月样黛眉低，四寸鞋儿莲步小。", "绝缨尝宴琼楼杪。", "软语清歌无限妙。", "归时桂影射帘旌，沈水烟消深院悄。"]'),
('song-ci-649','玉楼春','欧阳澈','宋','宋词','song-ci','玉楼春','[]','年时醉倚温温玉。',64,'宋词/ci.song.7000.json','["年时醉倚温温玉。", "妒月精神疑可掬。", "香丝篆袅一帘秋，潋滟十分浮蚁绿。", "兴来笑把朱弦促。", "切切含情声断续。", "曲中依约断人肠，除却梨园无此曲。"]'),
('song-ci-650','踏莎行','欧阳澈','宋','宋词','song-ci','踏莎行','[]','罗幕风轻，水沈烟细。',68,'宋词/ci.song.7000.json','["罗幕风轻，水沈烟细。", "杯行笑拥东山妓。", "酬歌何惜锦缠头，清音暗绕粱尘起。", "银甲弹筝，碧桃荐味。", "举觞飞白拚沈醉。", "花窗弄月晚归来，门迎蜡炬笙箫沸。"]'),
('song-ci-651','小重山','欧阳澈','宋','宋词','song-ci','小重山','[]','红叶伤心月午楼。',70,'宋词/ci.song.7000.json','["红叶伤心月午楼。", "袭人风细细，远烟浮。", "瞢腾醉眼不禁秋。", "追旧事，拍塞一怀秋。", "心绪两悠悠。", "东阳消瘦损，甚风流。", "拟凭仙枕梦中游。", "无眠久，通夕数更筹。"]'),
('song-ci-652','虞美人','欧阳澈','宋','宋词','song-ci','虞美人','[]','玉楼缥缈孤烟际。',66,'宋词/ci.song.7000.json','["玉楼缥缈孤烟际。", "徙倚愁如醉。", "雁来人远暗消魂。", "帘卷一钩新月、怯黄昏。", "那人音信全无个。", "幽恨谁凭破。", "扑花蝴蝶若知人。", "为我一场清梦、去相亲。"]'),
('song-ci-653','朝中措','曾','宋','宋词','song-ci','朝中措','[]','幽芳独秀在山林。',57,'宋词/ci.song.7000.json','["幽芳独秀在山林。", "不怕晓寒侵。", "应笑钱塘苏小，语娇终带吴音。", "乘槎归去，云涛万顷，谁是知心。", "写向生绡屏上，萧然伴我寒衾。"]'),
('song-ci-654','朝中措','曾','宋','宋词','song-ci','朝中措','[]','绿华居处渺云深。',57,'宋词/ci.song.7000.json','["绿华居处渺云深。", "不受一尘侵。", "细看宜州新句，平生才是知音。", "凌波一去，平山梦断，谁是关心。", "惟有青天碧海，知渠夜夜孤衾。"]'),
('song-ci-655','念奴娇','曾','宋','宋词','song-ci','念奴娇','[]','绣衣直指，问凌风一笑，翩然何许。',120,'宋词/ci.song.7000.json','["绣衣直指，问凌风一笑，翩然何许。", "诏出层霄持汉节，千里秋风淮浦。", "鉴远江山，竹西歌吹，曾被腥膻污。", "须君椽笔，为渠一洗尘土。", "休厌共倒金荷，翠眉重为唱，渭城朝雨。", "看即扬鞭归骑稳，还指郁葱深处。", "宝带兼金，华鞯新绣，直上云霄去。", "回头莫忘，玉霄今夜风露。"]'),
('song-ci-656','诉衷情','曾惇','宋','宋词','song-ci','诉衷情','[]','鄞江云气近蓬莱。',54,'宋词/ci.song.7000.json','["鄞江云气近蓬莱。", "花柳满城隈。", "风流谢守相遇，应覆故人杯。", "烟浪暖，锦帆回。", "莫徘徊。", "玉霄亭下，芍药荼䕷，都望归来。"]'),
('song-ci-657','浣溪沙','曾','宋','宋词','song-ci','浣溪沙','[]','无数春山展画屏。',48,'宋词/ci.song.7000.json','["无数春山展画屏。", "无穷烟柳照溪明。", "花枝缺处小舟横。", "紫禁正须红药句，清江莫与白鸥盟。", "主人元自是仙卿。"]'),
('song-ci-658','点绛唇','曾','宋','宋词','song-ci','点绛唇','[]','九月传杯，要携佳客栖霞去。',50,'宋词/ci.song.7000.json','["九月传杯，要携佳客栖霞去。", "满城风雨。", "记得潘郎句。", "紫菊红萸，何意留侬住。", "愁如许。", "暮烟一缕。", "正在归时路。"]'),
('song-ci-659','菩萨蛮','张表臣','宋','宋词','song-ci','菩萨蛮','[]','垂虹亭下扁舟住。',52,'宋词/ci.song.7000.json','["垂虹亭下扁舟住。", "松江烟雨长桥暮。", "白纻听吴歌。", "佳人泪脸波。", "劝倾金凿落。", "莫作思家恶。", "绿鸭与鲈鱼。", "如何可寄书。"]'),
('song-ci-660','蓦山溪','张表臣','宋','宋词','song-ci','蓦山溪','[]','楼横北固，尽日厌厌雨。',102,'宋词/ci.song.7000.json','["楼横北固，尽日厌厌雨。", "欸乃数声歌，但渺漠、江山烟树。", "寂寥风物，三五过元宵，寻柳眼，觅花英，春色知何处。", "落梅呜咽，吹彻江城暮。", "脉脉数飞鸿，杳归期、东风凝伫。", "长安不见，烽起夕阳间，魂欲断、酒初醒，独下危梯去。"]'),
('song-ci-661','南乡子','吴亿','宋','宋词','song-ci','南乡子','[]','江上雪初消。',66,'宋词/ci.song.7000.json','["江上雪初消。", "暖日晴烟弄柳条。", "认得裙腰芳草路，魂消。", "曾折梅花过断桥。", "潘鬓为谁凋。", "长恨金闺闭阿娇。", "遥想晚妆呵手罢，夭饶。", "更傍珠唇暖玉箫。"]'),
('song-ci-662','烛影摇红','吴亿','宋','宋词','song-ci','烛影摇红','[]','楼雪初消，丽谯吹罢单于晚。',116,'宋词/ci.song.7000.json','["楼雪初消，丽谯吹罢单于晚。", "使君千炬起班春，歌吹香风暖。", "十里珠帘尽卷。", "正人在、蓬壶阆苑。", "卖薪买酒，立马传觞，升平重见。", "谁识鳌头，去年曾侍传柑宴。", "至今衣袖带天香，行处氤氲满。", "已是春宵苦短。", "且莫遣、欢游意懒。", "细听归路，璧月光中，玉箫声远。"]'),
('song-ci-663','临江仙','刘袤','宋','宋词','song-ci','临江仙','[]','樱桃结子春归尽，蝶翻金粉双飞。',68,'宋词/ci.song.7000.json','["樱桃结子春归尽，蝶翻金粉双飞。", "子规啼月小楼西。", "玉钩罗幕，惆怅卷金泥。", "门巷寂寥人去后，望残烟草低迷。", "何时重听玉骢嘶。", "扑帘飞絮，依约梦回时。"]'),
('song-ci-664','清平乐','李鼐','宋','宋词','song-ci','清平乐','[]','乱云将雨。',54,'宋词/ci.song.7000.json','["乱云将雨。", "飞过鸳鸯浦。", "人在小楼空翠处。", "分得一襟离绪。", "片帆隐隐归舟。", "天边雪卷云浮。", "今夜梦魂何处，青山不隔人愁。"]'),
('song-ci-665','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','[]','当年谁种官梅，自开自落清无比。',126,'宋词/ci.song.7000.json','["当年谁种官梅，自开自落清无比。", "一朝惊见，危亭岑立，繁华丛里。", "知是贤侯，有难兄弟，素书时寄。", "纵舞携如意，吟搔短发，无从诉、心中喜。", "却对斜枝冷蕊。", "似於人、不胜风味。", "冰姿斜映，朱唇浅破，欣然会意。", "青子垂垂，翠阴密密，尤堪频憩。", "待促归禁近，邦人指点，作甘棠比。"]'),
('song-ci-666','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','[]','晓来雨歇风生，素商乍入鸳鸯浦。',126,'宋词/ci.song.7000.json','["晓来雨歇风生，素商乍入鸳鸯浦。", "红蕖翠盖，不知西帝，神游何处。", "罗绮丛中，是谁相慕，凭肩私语。", "似汉皋佩解，桃源人去，成思忆、空凝伫。", "肯为风流令尹，把芳心、双双分付。", "碧纱对引，朱衣前导，应须此去。", "好揖清香，盛邀嘉客，杯行无数。", "唤瑶姬并立，如花并蒂，唱黄金缕。"]'),
('song-ci-667','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','西湖天下应如是。',127,'宋词/ci.song.7000.json','["西湖天下应如是。", "谁唤作、真西子。", "云凝山秀，日增波媚，宜晴宜雨。", "况是深秋，更当遥夜，月华如水。", "记词人解道，丹青妙手，应难写、真奇语。", "往事输他范蠡。", "泛扁舟、仍携佳丽。", "毫端幻出，淡妆浓抹，可人风味。", "和靖幽居，老坡遗迹，也应堪记。", "更凭君画我，追随二老，游千家寺。"]'),
('song-ci-668','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','[]','小轩潇洒清宵午，风正紧、门深闭。',127,'宋词/ci.song.7000.json','["小轩潇洒清宵午，风正紧、门深闭。", "藜床危坐，竹窗频听，春虫扑纸。", "灯烬垂红，篆烟消碧，衣轻如水。", "料飞花未止，堆檐已满，时催折、琅玕尾。", "骨冷魂清无寐。", "这身在、广寒宫里。", "暗怀千古，浑疑一夜，冰生肠胃。", "岁事峥嵘，故园睽阻，归期犹未。", "向寒乡、不念丰年，只忆青天万里。"]'),
('song-ci-669','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','[]','夜来六出飞花，又催寂寞袁门闭。',125,'宋词/ci.song.7000.json','["夜来六出飞花，又催寂寞袁门闭。", "幽斋无寐，寒欺衾布，明吞窗纸。", "起步闲庭，月华交映，长空如水。", "便乘风欲去，凌云直上，青冥际、骑箕尾。", "谁信团成和气。", "在贤侯、笑谈声里。", "咸惊句琢琼瑰，端是锦缠肠胃。", "宿麦连云，遗蝗入地，田家知未。", "更明年看取，东阡北陌，黄云万里。"]'),
('song-ci-670','水龙吟','杨无咎','宋','宋词','song-ci','水龙吟','["\u94b1\u5858\u6c5f"]','智琼娇额涂黄，为谁种作秋风蕊。',125,'宋词/ci.song.7000.json','["智琼娇额涂黄，为谁种作秋风蕊。", "寒香半露，绿帏深护，犹闻十里。", "山麝生脐，水沈削蜡，一时羞避。", "向钱塘江上，中秋月下，有人暗寻遗子。", "不奈书生习气。", "对群花、领略风味。", "骚人已去，欲纫幽佩，重为湘酹。", "天赋风流，友梅兄蕙，舆桃奴李。", "向明窗棐几，纤枝未老，眼明如水。"]'),
('song-ci-671','念奴娇','杨无咎','宋','宋词','song-ci','念奴娇','[]','单于吹罢，望西山乞得，斜阳收脚。',122,'宋词/ci.song.7000.json','["单于吹罢，望西山乞得，斜阳收脚。", "素魄旋升，听桂子、风里时时飘落。", "莹彻杯盘，冷侵毛发，浑不胜衣著。", "天公有意，为人掀尽云幕。", "童稚犹也多情，广庭扫净草，不容纤恶。", "步绕周遭，疑便是、踏雪当年东郭。", "慢引歌声，响穿云际，直使姮娥觉。", "一尊重酹，为言千载同约。"]'),
('song-ci-672','扫花游・扫地游','杨无咎','宋','宋词','song-ci','扫花游・扫地游','[]','乳莺啭午。',117,'宋词/ci.song.7000.json','["乳莺啭午。", "□好梦初醒，小轩清楚。", "水沈细缕。", "趁游丝落絮，缓随风舞。", "罥起春心，又是愁云怨雨。", "玉人去。", "遍徙倚旧时，曾并肩处。", "相望知几许。", "纵远隔云山，不遮愁路。", "捧杯荐俎。", "记低歌丽曲，共论心素。", "薄恨斜阳，不道离情最苦。", "正凝伫。", "向谯门、又催笳鼓。"]'),
('song-ci-673','隔浦莲・隔浦莲近拍','杨无咎','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','墙头低荫翠幄。',88,'宋词/ci.song.7000.json','["墙头低荫翠幄。", "格磔鸣乌鹊。", "好梦惊回处，馀酲推枕犹觉。", "新晴人意乐。", "云容薄。", "丽日明池阁。", "卷帘幕。", "披衣散策，闲庭吟绕红药。", "残英几许，尚可一供春酌。", "天气今宵怕又恶。", "凭托。", "东风且慢吹落。"]'),
('song-ci-674','品令','杨无咎','宋','宋词','song-ci','品令','[]','水寒江静。',67,'宋词/ci.song.7000.json','["水寒江静。", "浸一抹、青山影。", "楼外指点渔村近。", "笛声谁喷。", "惊起宾鸿阵。", "往事总归眉际恨。", "这相思、□□谁问。", "泪痕空把罗襟印。", "泪应尽。", "争奈情无尽。"]'),
('song-ci-675','阳春','杨无咎','宋','宋词','song-ci','阳春','[]','蕙风轻，莺语巧，应喜乍离幽谷。',128,'宋词/ci.song.7000.json','["蕙风轻，莺语巧，应喜乍离幽谷。", "飞过北窗前，递晴晓，丽日明透翠帏縠。", "篆台芬馥。", "初睡起、横斜簪玉。", "因甚自觉腰肢瘦，新来又宽裙幅。", "对清镜、无心忺梳裹，谁问著、馀酲带宿。", "寻思前欢往事，似惊回、好梦难续。", "花亭遍倚槛曲。", "厌满眼、争春凡木。", "尽憔悴、过了清明候，愁红惨绿。"]'),
('song-ci-676','白雪','杨无咎','宋','宋词','song-ci','白雪','[]','檐收雨脚，云乍敛、依然又满长空。',117,'宋词/ci.song.7000.json','["檐收雨脚，云乍敛、依然又满长空。", "纹蜡焰低，熏炉烬冷，寒衾拥尽重重。", "隔帘栊。", "听撩乱、扑漉春虫。", "晓来见、玉楼珠殿，恍若在蟾宫。", "长爱越水泛舟，蓝关立马，画图中。", "怅望几多诗□，无句可形容。", "谁与问、已经三白，忒是报年丰。", "未应真个，情多老却天公。"]'),
('song-ci-677','垂丝钓','杨无咎','宋','宋词','song-ci','垂丝钓','[]','燕将旧侣。',81,'宋词/ci.song.7000.json','["燕将旧侣。", "呢喃终日相语。", "似惜别离情，知几许。", "谁与度。", "为向人代诉。", "空朝暮。", "谩千言百句。", "怎生会得，争如作个青羽。", "又闻院宇。", "不在当时住。", "飞去无寻处。", "肠万缕。", "寄暴风横雨。"]'),
('song-ci-678','垂丝钓','杨无咎','宋','宋词','song-ci','垂丝钓','[]','玉纤半露。',81,'宋词/ci.song.7000.json','["玉纤半露。", "香檀低应鼍鼓。", "逸调响穿空，云不度。", "情几许。", "看两眉碧聚。", "为谁诉。", "听敲冰戛玉。", "恨云怨雨。", "声声总在愁处。", "放杯未举。", "倾坐惊相顾。", "应也肠千缕。", "人欲去。", "更画檐细雨。"]'),
('song-ci-679','解蹀躞','杨无咎','宋','宋词','song-ci','解蹀躞','[]','金谷楼中人在，两点眉颦绿。',91,'宋词/ci.song.7000.json','["金谷楼中人在，两点眉颦绿。", "叫云穿月，横吹楚山竹。", "怨断忧忆因谁，坐中有客，犹记住、平阳宿。", "泪盈目。", "百转千声相续。", "停杯听难足。", "谩夸天海风涛旧时曲。", "夜深烟惨云愁，倩君沈醉，明日看、梅梢玉。"]'),
('song-ci-680','醉落魄・一斛珠','杨无咎','宋','宋词','song-ci','醉落魄・一斛珠','[]','双心小萼。',68,'宋词/ci.song.7000.json','["双心小萼。", "瑞炉慢炷轻烟初著。", "清香已透红绡幄。", "底事多情，玉笋更轻掠。", "鬓云侧畔□眉角。", "妆成曾印铅华薄。", "几回殢酒襟怀恶。", "莺舌偷传，低语教人嚼。"]'),
('song-ci-681','青玉案','杨无咎','宋','宋词','song-ci','青玉案','[]','芝兰桃李环围著。',80,'宋词/ci.song.7000.json','["芝兰桃李环围著。", "拥和气、浮帘幕。", "寿斝交飞争满酌。", "一声珠丳，数敲牙板，应有梁尘落。", "腰金虽重何曾觉。", "更看悬鱼上麟阁。", "不用祖洲寻灵药。", "平时阴德，几人今日，额手称安乐。"]'),
('song-ci-682','青玉案','杨无咎','宋','宋词','song-ci','青玉案','[]','南州独数多名士。',80,'宋词/ci.song.7000.json','["南州独数多名士。", "谁富贵、归桑梓。", "昼锦如公难比似。", "傍湖开径，雨帘云栋，平地居仙子。", "行须勋业超青史。", "再侍宸帏任非次。", "醉袖尽教春酒渍。", "明年此会，寿觞欲举，百拜君王赐。"]'),
('song-ci-683','青玉案','杨无咎','宋','宋词','song-ci','青玉案','[]','奇葩珍树丛丛绕。',80,'宋词/ci.song.7000.json','["奇葩珍树丛丛绕。", "望仙隐、蓬莱小。", "前枕湖光秋色晓。", "荷花今岁，也如人意，不逐西风老。", "霞觞献寿频频倒。", "瑞蔼浮空凝不扫。", "定自日边飞诏早。", "芝庭呈秀，桂宫得意，更看明年好。"]'),
('song-ci-684','青玉案','杨无咎','宋','宋词','song-ci','青玉案','[]','五云楼阁蓬瀛路。',80,'宋词/ci.song.7000.json','["五云楼阁蓬瀛路。", "空相望、无由去。", "弱水渺茫谁可渡。", "君家徐福，荡舟寻访，却是曾知处。", "群仙应问来何暮。", "说与荣归锦封句。", "句里丁宁天已许。", "要教强健，召还廊庙，永作商岩雨。"]'),
('song-ci-685','望江南・忆江南','杨无咎','宋','宋词','song-ci','望江南・忆江南','[]','锺陵好，佳节庆元正。',64,'宋词/ci.song.7000.json','["锺陵好，佳节庆元正。", "瑞色潜将春共到，台星遥映月初升。", "贤帅为时生。", "人意乐，天宇亦清明。", "淡薄眉腮娇倚暖，依微柳眼喜窥晴。", "和气满江城。"]'),
('song-ci-686','望江南・忆江南','杨无咎','宋','宋词','song-ci','望江南・忆江南','[]','锺陵好，和气满江城。',64,'宋词/ci.song.7000.json','["锺陵好，和气满江城。", "忆昨旌麾初至止，到今政令只宽平。", "仍岁兆丰登。", "称庆旦，遐迩一般情。", "共信我公跻寿考，从来阴德被生灵。", "襦裤听欢声。"]'),
('song-ci-687','望江南・忆江南','杨无咎','宋','宋词','song-ci','望江南・忆江南','[]','锺陵好，襦裤听欢声。',64,'宋词/ci.song.7000.json','["锺陵好，襦裤听欢声。", "薰入管弦增亮响，唤教罗绮亦光荣。", "引满劝金觥。", "谁信是，元自悟长生。", "铃阁才投公事笔，云章惟读道家经。", "家世仰仙卿。"]'),
('song-ci-688','望江南・忆江南','杨无咎','宋','宋词','song-ci','望江南・忆江南','[]','锺陵好，家世仰仙卿。',64,'宋词/ci.song.7000.json','["锺陵好，家世仰仙卿。", "衣带不须藏贝叶，集贤何用化金瓶。", "且欲佐中兴。", "期早晚，丹诏天下庭。", "不许南州犹弭节，促归东府共和羹。", "膏泽遍寰瀛。"]'),
('song-ci-689','选冠子','杨无咎','宋','宋词','song-ci','选冠子','[]','海上楼台，壶中日月，乍觉挈来平地。',138,'宋词/ci.song.7000.json','["海上楼台，壶中日月，乍觉挈来平地。", "熙熙鸡犬，簇簇僮奴，亦自有登天志。", "知是仙宫，出应亨期，因识前修风味。", "看纵横才美，雍容谈笑，一团和气。", "锺秀处、雪洁霜□，梅清竹瘦，占尽小春佳致。", "笙歌韵溢，锦绣香浓，饮少未妨欢醉。", "好在双椿，伫看丹桂分折，芝庭兰砌。", "向游惟功行，和羹勋业，共传家世。"]'),
('song-ci-690','满庭芳','杨无咎','宋','宋词','song-ci','满庭芳','[]','节物争妍，江山改观，已闻春到萧滩。',117,'宋词/ci.song.7000.json','["节物争妍，江山改观，已闻春到萧滩。", "瑞烟和气，葱茜接螺川。", "元是使君诞日，半千运、来踵三贤。", "争相竞，谁知胜地，拜相有前山。", "芳筵。", "开富寿，罗绮间，簪组骈阗。", "正雪梅迎腊，霜月将圆。", "看取霜髯秀颊，人人道、平世神仙。", "调元手，阴功在继，八百定长年。"]'),
('song-ci-691','二郎神','杨无咎','宋','宋词','song-ci','二郎神','[]','炎光欲谢，更几日、薰风吹雨。',129,'宋词/ci.song.7000.json','["炎光欲谢，更几日、薰风吹雨。", "共说是天公，亦嘉神贶，特作澄清海宇。", "灌口擒龙，离堆平水，休问功超前古。", "当中兴、护我边陲，重使四方安堵。", "新府。", "祠庭占得，山川佳处。", "看晓汲双泉，晚除百病，奔走千门万户。", "岁岁生朝，勤勤称颂，可但民无灾苦。", "□愿得、地久天长，佐绍兴□□□。"]'),
('song-ci-692','水调歌头','杨无咎','宋','宋词','song-ci','水调歌头','[]','闰馀有何好，一岁两中秋。',114,'宋词/ci.song.7000.json','["闰馀有何好，一岁两中秋。", "霁云卷尽，依旧银汉截天流。", "长记芗林堂上，静对小山丛桂，尊俎许从游。", "遥想此时兴，不减上南楼。", "引玉觞，看金饼，水云头。", "醉听哦响，宁羡王粲赋荆州。", "此夕翻成愁绝，未斫广寒丹桂，犹衣敝貂裘。", "万事付谈笑，斗酒且宽忧。"]'),
('song-ci-693','水调歌头','杨无咎','宋','宋词','song-ci','水调歌头','[]','芗林有何好，花蕊不惊秋。',114,'宋词/ci.song.7000.json','["芗林有何好，花蕊不惊秋。", "千章云木，长见密叶翠光流。", "中有三朝勋旧，早岁辞荣轩冕，归伴赤松游。", "不羡鸳鸯侣，锺听景阳楼。", "问向来。", "麟阁上，凤池头。", "有谁能继，向来解印似苏州。", "自是英姿绝俗，非我与时违异，何用衣羊裘。", "况得长生趣，千岁有怀忧。"]'),
('song-ci-694','水调歌头','杨无咎','宋','宋词','song-ci','水调歌头','[]','寥亮度弦管，笑语集簪缨。',114,'宋词/ci.song.7000.json','["寥亮度弦管，笑语集簪缨。", "又逢华旦争庆，豪杰为时生。", "犹对中秋月影，渐放重阳菊蕊，万宝正西成。", "爽气知多少，天赋满襟灵。", "擅词华，追鲍谢，踵斯冰。", "入趋禁近，出镇藩辅早辞荣。", "休恋平湖佳致，好为苍生重起，归去侍宸庭。", "一德及元□，千载致升平。"]'),
('song-ci-695','水调歌头','杨无咎','宋','宋词','song-ci','水调歌头','[]','帝里记当日，赐第富相联。',114,'宋词/ci.song.7000.json','["帝里记当日，赐第富相联。", "惟君家最称著，桐木老参天。", "三相勋庸才业，一代风流人物，继世赖君贤。", "自合跻清要，小屈佐平川。", "下车初，逢庆旦，听欢传。", "冰清玉润，仁爱终始被江堧。", "满泛黄花称寿，细看红萸枝健，和气霭芳筵。", "隔日醉重九，千岁似今年。"]'),
('song-ci-696','传言玉女','杨无咎','宋','宋词','song-ci','传言玉女','[]','小院春长，整整绣帘低轴。',91,'宋词/ci.song.7000.json','["小院春长，整整绣帘低轴。", "异葩幽艳，满千瓶百斛。", "珠钿翠佩，尘袜锦笼环簇。", "日烘风和，奈何芬馥。", "凤髓龙津，觉从前、气味俗。", "夜阑人醉，引春葱兢□。", "只愁飞去，暗与行云相逐。", "月娥好在，为歌新曲。"]'),
('song-ci-697','传言玉女','杨无咎','宋','宋词','song-ci','传言玉女','[]','料峭寒生，知是那番花信。',93,'宋词/ci.song.7000.json','["料峭寒生，知是那番花信。", "算来都为，惜花人做恨。", "看犹未足，早觉枝头吹尽。", "曲栏幽榭，乱红成阵。", "酾酒花前，试停杯、与细问。", "褪香销粉，问东君怎忍。", "韶华过半，谩赢得、几场春困。", "厌厌空自，为花愁损。"]'),
('song-ci-698','於中好','杨无咎','宋','宋词','song-ci','於中好','[]','墙头艳杏花初试。',66,'宋词/ci.song.7000.json','["墙头艳杏花初试。", "绕珍丛、细挼红蕊。", "欲知占尽春明媚。", "诮无意、看桃李。", "持杯准拟花前醉。", "早一叶、两叶飞坠。", "晚来旋旋深无地。", "更听得、东风起。"]'),
('song-ci-699','於中好','杨无咎','宋','宋词','song-ci','於中好','[]','溅溅不住溪流素。',66,'宋词/ci.song.7000.json','["溅溅不住溪流素。", "忆曾记、碧桃红露。", "别来寂寞朝朝暮。", "恨遮乱、当时路。", "仙家岂解空相误。", "嗟尘世、自难知处。", "而今重与春为主。", "尽浪蕊、浮花妒。"]'),
('song-ci-700','於中好','杨无咎','宋','宋词','song-ci','於中好','[]','梅花摘索穿疏竹。',66,'宋词/ci.song.7000.json','["梅花摘索穿疏竹。", "荫纹禽、喜欢相逐。", "坐中已自清堪掬。", "更潇洒、人如玉。", "新声爱度周郎曲。", "捧霞杯、再三相嘱。", "无情有恨重分北。", "也撩得、双眉蹙。"]'),
('song-ci-701','瑞云浓','杨无咎','宋','宋词','song-ci','瑞云浓','[]','睽离谩久，年华谁信曾换。',92,'宋词/ci.song.7000.json','["睽离谩久，年华谁信曾换。", "依旧当时似花面。", "幽欢小会，记永夜、杯行无算。", "醉里屡忘归，任虚檐月转。", "能变新声，随语意、悲欢感怨。", "可更馀音寄羌管。", "倦游江浙，问似伊、阿谁会见。", "度已无肠，为伊可断。"]'),
('song-ci-702','一丛花','杨无咎','宋','宋词','song-ci','一丛花','[]','娟娟□月可庭方。',95,'宋词/ci.song.7000.json','["娟娟□月可庭方。", "窗户进新凉。", "美人为我歌新曲，翻身调、韵超出宫商。", "犀箸细敲，花瓷清响，馀韵绕红梁。", "风流难似我清狂。", "随处占烟光。", "怜君语带京华样，纵娇软、不似吴邦。", "拚了醉眠，不须重唱，真个已无肠。"]'),
('song-ci-703','好事近','杨无咎','宋','宋词','song-ci','好事近','[]','花里爱姚黄，琼苑旧曾相识。',53,'宋词/ci.song.7000.json','["花里爱姚黄，琼苑旧曾相识。", "不道风流种在，又一枝倾国。", "拟图遮断倚阑人，休教妄攀摘。", "其奈老来情减，负十分春色。"]'),
('song-ci-704','人娇','杨无咎','宋','宋词','song-ci','人娇','[]','恼乱东君，满目千花百卉。',84,'宋词/ci.song.7000.json','["恼乱东君，满目千花百卉。", "偏怜处、爱他秾李。", "莹然风骨，占十分春意。", "休漫说、唐昌观中玉蕊。", "妒雪凝霜，凌红掩翠。", "看不足、可人情味。", "会须移种，向曲栏幽砌。", "愁绿叶成阴，道傍人指。"]'),
('song-ci-705','人娇','杨无咎','宋','宋词','song-ci','人娇','[]','露下天高，最是中秋景胜。',84,'宋词/ci.song.7000.json','["露下天高，最是中秋景胜。", "喜银蟾、十分增晕。", "嫦娥飞下，见雾鬟风鬓。", "念八景园中，画谁能尽。", "慢奏云韶，美斟仙酝。", "清不寐、桂香成阵。", "只愁来夕，又阴晴无准。", "却待约重圆，后期难问。"]'),
('song-ci-706','蝶恋花','杨无咎','宋','宋词','song-ci','蝶恋花','[]','端正纤柔如玉削。',70,'宋词/ci.song.7000.json','["端正纤柔如玉削。", "窄袜宫鞋，暖衬吴绫薄。", "掌上细看才半搦。", "巧偷强夺尝春酌。", "稳称身材轻绰约。", "微步盈盈，未怕香尘觉。", "试问更谁如样脚。", "除非借与嫦娥著。"]'),
('song-ci-707','蝶恋花','杨无咎','宋','宋词','song-ci','蝶恋花','[]','春睡腾腾长过午。',70,'宋词/ci.song.7000.json','["春睡腾腾长过午。", "楚梦云收，雨歇香风度。", "起傍妆台低笑语。", "画檐双鹊尤偷顾。", "笑指遥山微敛处。", "问我清癯，莫是因诗苦。", "不道别来愁几许。", "相逢更忍从头诉。"]'),
('song-ci-708','蝶恋花','杨无咎','宋','宋词','song-ci','蝶恋花','[]','昔在仁皇当极治。',70,'宋词/ci.song.7000.json','["昔在仁皇当极治。", "南极星宫，曾降为嘉瑞。", "犹有画图传好事。", "身材只恐君今是。", "对酒不妨同看戏。", "他日功名，晏子堪为比。", "更愿远孙逢九世。", "安排君在鸡窠里。"]'),
('song-ci-709','蝶恋花','杨无咎','宋','宋词','song-ci','蝶恋花','[]','万里无云秋色静。',70,'宋词/ci.song.7000.json','["万里无云秋色静。", "上下天光，共水交辉映。", "坐对冰轮心目莹。", "此身不在尘寰境。", "扑漉文禽飞不定。", "勾引离人，分外添归兴。", "来往悠悠重记省。", "夜阑人散花移影。"]'),
('song-ci-710','锯解令','杨无咎','宋','宋词','song-ci','锯解令','[]','送人归后酒醒时，睡不稳、衾翻翠缕。',63,'宋词/ci.song.7000.json','["送人归后酒醒时，睡不稳、衾翻翠缕。", "应将别泪洒西风，尽化作、断肠夜雨。", "卸帆浦溆。", "一种恓惶两处。", "寻思却是我无情，便不解、寄将梦去。"]'),
('song-ci-711','忆秦娥','杨无咎','宋','宋词','song-ci','忆秦娥','[]','情难足。',56,'宋词/ci.song.7000.json','["情难足。", "不堪黄帽催行速。", "催行速。", "扁舟一叶，别愁千斛。", "津亭送客惊相嘱。", "举杯欲唱眉先蹙。", "眉先蹙。", "背人掩面，不能终曲。"]'),
('song-ci-712','倾杯・倾杯乐','杨无咎','宋','宋词','song-ci','倾杯・倾杯乐','[]','瑞日凝晖，东风解冻，峭寒犹浅。',130,'宋词/ci.song.7000.json','["瑞日凝晖，东风解冻，峭寒犹浅。", "正池馆、梅英粉淡，柳梢金软，兰芽香暖。", "滕城谁种芙蕖满。", "浸银蟾影，一夜万花开遍。", "翠楼朱户，是处重帘竞卷。", "罗绮簇、欢声一片。", "看五马行春旌旆远。", "拥襦裤、千里歌谣，都入太平弦管。", "且莫厌、瑶觞屡劝。", "闻凤诏、催归非晚。", "愿岁岁今夜里，端门侍宴。"]'),
('song-ci-713','望海潮','杨无咎','宋','宋词','song-ci','望海潮','[]','菊暗荷枯，橙黄桔绿，嘉时记得今朝。',129,'宋词/ci.song.7000.json','["菊暗荷枯，橙黄桔绿，嘉时记得今朝。", "欢蔼十州，香飘万井，春容小试梅梢。", "星昂耀层霄。", "庆诞生元德，出佐明朝。", "雅奏声中，彩旗光里仰英标。", "遐年已卜民谣。", "最招徕瘵俗，洗尽奸骄。", "东府政声，北门治绩，流芳况自迢遥。", "莫惜拚今宵。", "听缓敲牙板，引满金蕉。", "看即泥封峻召，无计驻华镳。"]'),
('song-ci-714','齐天乐','杨无咎','宋','宋词','song-ci','齐天乐','[]','后堂芳树阴阴见。',123,'宋词/ci.song.7000.json','["后堂芳树阴阴见。", "疏蝉又还催晚。", "燕守朱门，萤粘翠幕，纹蜡啼红慵剪。", "纱帏半卷。", "记云亸瑶山，粉融珍簟。", "睡起援毫，戏题新句谩盈卷。", "睽离鳞雁顿阻，似闻频念我，愁绪无限。", "瑞鸭香销，铜壶漏永，谁惜无眠展转。", "蓬山恨远。", "想月好风清，酒登琴荐。", "一曲高歌，为谁眉黛敛。"]'),
('song-ci-715','齐天乐','杨无咎','宋','宋词','song-ci','齐天乐','[]','疏疏数点黄梅雨。',123,'宋词/ci.song.7000.json','["疏疏数点黄梅雨。", "殊方又逢重五。", "角黍包金，草蒲泛玉，风物依然荆楚。", "衫裁艾虎。", "更钗凫朱符，臂缠红缕。", "扑粉香绵，唤风绫扇小窗午。", "沈湘人去已远，劝君休对酒，感时怀古。", "慢啭莺喉，轻敲象板，胜读离骚章句。", "荷香暗度。", "渐引入陶陶，醉乡深处。", "卧听江头，画船喧叠鼓。"]'),
('song-ci-716','蓦山溪','杨无咎','宋','宋词','song-ci','蓦山溪','[]','去年今日，踪迹留金水。',102,'宋词/ci.song.7000.json','["去年今日，踪迹留金水。", "乘兴挈朋侪，游赏遍、南峰佳致。", "崇仙岸左，争看竞龙舟，人汹汹，鼓冬冬，不觉金鸟坠。", "而今寂寞，独处山林里。", "欲去恨无因，奈阻隔、川途百里。", "香蒲角黍，对暑悄无言，梅雨细，麦风轻，怅望宽垂泪。"]'),
('song-ci-717','蓦山溪','杨无咎','宋','宋词','song-ci','蓦山溪','[]','天姿雅素，不管群芳妒。',102,'宋词/ci.song.7000.json','["天姿雅素，不管群芳妒。", "微笑倚春风，似窥宋、墙头凝伫。", "一春花草，陡觉更无香，悬绣帐，结罗巾，谁更熏沈炷。", "可堪开晚，未放韶光去。", "生怕糁庭阶，直不忍、苍苔散步。", "会须开宴，满摘蘸瑶觞，何况有，绮窗人，娇鬓相宜处。"]'),
('song-ci-718','蓦山溪','杨无咎','宋','宋词','song-ci','蓦山溪','[]','玉英檀蕊，细意凭君看。',102,'宋词/ci.song.7000.json','["玉英檀蕊，细意凭君看。", "青帝忒多情，费几许、春风暗剪。", "晓来敧枕，不觉嫩香飘，披宿雾，启幽窗，不道开初遍。", "无穷风味，乍可蜂莺占。", "莫遣俗人知，怕毒眼、急须遮断。", "倚墙压架，娇困卧枝头，心绪里，阿谁知，似个人撩乱。"]'),
('song-ci-719','蓦山溪','杨无咎','宋','宋词','song-ci','蓦山溪','[]','蟾宫仙种，几日飘鸳甃。',102,'宋词/ci.song.7000.json','["蟾宫仙种，几日飘鸳甃。", "密叶绣围栾，似翦出、佳人翠袖。", "叶间金粟，蔌蔌糁枝头，黄菊嫩，碧莲披，独对秋容瘦。", "浓香馥郁，庭户宜熏透。", "十里远随风，又何必、凭阑细嗅。", "明犀一点，暗里为谁通，秋夜永，月华寒，无寐听残漏。"]'),
('song-ci-720','醉蓬莱','杨无咎','宋','宋词','song-ci','醉蓬莱','[]','见恩荣故里。',120,'宋词/ci.song.7000.json','["见恩荣故里。", "□著贤关，特然超诣。", "满腹诗书，洗膏粱馀味。", "羞挽乌号，换将蓝绶，向广庭亲试。", "磊落胸襟，雍容人物，于今谁比。", "争许才猷，合跻严禁，行看横飞，少将清议。", "喜对生朝，且陶陶欢醉。", "太华莲开，海山桃熟，况是当佳致。", "满引瑶觞，相期眉寿，君家重耳。"]'),
('song-ci-721','醉蓬莱','杨无咎','宋','宋词','song-ci','醉蓬莱','[]','正才过七夕，又近中元，素秋时候。',120,'宋词/ci.song.7000.json','["正才过七夕，又近中元，素秋时候。", "月皎风高，渐凉生襟袖。", "灏气澄凝，是谁清白，应此□□秀。", "味洗膏粱，才侔沈谢，三朝勋旧。", "好是新来，日临连帅，化格黔黎，政归仁厚。", "早祷群祠，有雨随车骤。", "愿与寰区，共资膏泽，岁岁称眉寿。", "孝感灵泉，涓涓不绝，斟为醇酎。"]'),
('song-ci-722','醉蓬莱','杨无咎','宋','宋词','song-ci','醉蓬莱','[]','见禾山凝秀，禾水澄清，地灵境胜。',120,'宋词/ci.song.7000.json','["见禾山凝秀，禾水澄清，地灵境胜。", "天与珍奇，产凌霄峰顶。", "嫩叶森枪，轻尘飞雪，冠中州双井。", "绝品家藏，武陵有客，清奇相称。", "坐列群贤，手呈三味，云逐瓯圆，乳随汤迸。", "珍重殷勤，念文园多病。", "毛孔生香，舌根回味，助苦吟幽兴。", "两腋风生，从教飞到，蓬莱仙境。"]'),
('song-ci-723','朝中措','杨无咎','宋','宋词','song-ci','朝中措','[]','杯盘狼藉烛参差。',57,'宋词/ci.song.7000.json','["杯盘狼藉烛参差。", "欲去未容辞。", "春雪看飞金碾，香云旋涌花瓷。", "雍容四座，矜夸一品，重听新词。", "归路清风生腋，不妨轻拈吟髭。"]'),
('song-ci-724','朝中措','杨无咎','宋','宋词','song-ci','朝中措','[]','打窗急听□然汤。',57,'宋词/ci.song.7000.json','["打窗急听□然汤。", "沈水剩熏香。", "冷暖旋投冰碗，荤膻一洗诗肠。", "酒醒酥魂，茶添胜致，齿颊生凉。", "莫道淡交如此，於中有味尤长。"]'),
('song-ci-725','点绛唇','杨无咎','宋','宋词','song-ci','点绛唇','[]','宝勒嘶归，未教佳客轻辞去。',50,'宋词/ci.song.7000.json','["宝勒嘶归，未教佳客轻辞去。", "姊夫屡鼠。", "笑听殊方语。", "清入回肠，端助诗情苦。", "春风路。", "梦寻何处。", "门掩桃花雨。"]'),
('song-ci-726','点绛唇','杨无咎','宋','宋词','song-ci','点绛唇','[]','瓦枕藤床，道人劝饮鸡苏水。',50,'宋词/ci.song.7000.json','["瓦枕藤床，道人劝饮鸡苏水。", "清虽无比。", "何似今宵意。", "红袖传持，别是般情味。", "歌筵起。", "绛纱影里。", "应有吟鞭坠。"]'),
('song-ci-727','点绛唇','杨无咎','宋','宋词','song-ci','点绛唇','[]','借问嫦娥，当初谁种婆娑树。',50,'宋词/ci.song.7000.json','["借问嫦娥，当初谁种婆娑树。", "空中呈露。", "不坠凡花数。", "却爱芗林，便似蟾宫住。", "清如许。", "醉看歌舞。", "同在高寒处。"]'),
('song-ci-728','点绛唇','杨无咎','宋','宋词','song-ci','点绛唇','[]','散策芗林，几回来绕团团树。',50,'宋词/ci.song.7000.json','["散策芗林，几回来绕团团树。", "月明风露。", "平地神仙数。", "准拟归来，移近东家住。", "应相许。", "为君起舞。", "直到高寒处。"]'),
('song-ci-729','卜算子','杨无咎','宋','宋词','song-ci','卜算子','[]','婆娑月里枝，隐约空中露。',52,'宋词/ci.song.7000.json','["婆娑月里枝，隐约空中露。", "拟访嫦娥高处看，一夜心生羽。", "仙种落人间，群艳难俦侣。", "恼乱骚人有底香，欲赋无奇语。"]'),
('song-ci-730','卜算子','杨无咎','宋','宋词','song-ci','卜算子','[]','平分月殿香，碎点金盘露。',52,'宋词/ci.song.7000.json','["平分月殿香，碎点金盘露。", "占断秋光独自芳，端称觞飞羽。", "谢了却重开，若个花同侣。", "谁识灵心一点通，手拈空无语。"]'),
('song-ci-731','卜算子','杨无咎','宋','宋词','song-ci','卜算子','[]','昨夜月初圆，今日春才半。',52,'宋词/ci.song.7000.json','["昨夜月初圆，今日春才半。", "自是元君并旦生，岂在称遐算。", "花诰看加封，玉斝休辞满。", "绮席来年谁与同，笑揖麻姑伴。"]'),
('song-ci-732','滴滴金','杨无咎','宋','宋词','song-ci','滴滴金','[]','当初本合蟾宫里。',60,'宋词/ci.song.7000.json','["当初本合蟾宫里。", "谩容易、到尘世。", "表里冰清谁与比。", "占无双两地。", "诜诜已是多孙子。", "看将来、总荣贵。", "岁岁今朝捧瑶觞，劝南园桃李。"]'),
('song-ci-733','滴滴金','杨无咎','宋','宋词','song-ci','滴滴金','[]','相逢未尽论心素。',60,'宋词/ci.song.7000.json','["相逢未尽论心素。", "早容易、背人去。", "忆得歌翻断肠句。", "更惺惺言语。", "萋萋芳草迷南浦。", "正风吹、打船雨。", "静听愁声夜无眠，到水村何处。"]'),
('song-ci-734','上林春令・一落索','杨无咎','宋','宋词','song-ci','上林春令・一落索','[]','秾李夭桃堆绣。',65,'宋词/ci.song.7000.json','["秾李夭桃堆绣。", "正暖日、如熏芳袖。", "流莺恰恰娇啼。", "似为劝、百觞进酒。", "少年未用称遐寿。", "愿来岁、如今时侯。", "相将得意皇都，同携手、上林春昼。"]'),
('song-ci-735','瑞鹤仙','杨无咎','宋','宋词','song-ci','瑞鹤仙','[]','看灯花尽落。',127,'宋词/ci.song.7000.json','["看灯花尽落。", "更欲换，门外初听剥啄。", "一尊赴谁约。", "甚不知早暮，忒贪欢乐。", "嗔人调谑。", "饮芳容、索强倒恶。", "渐娇慵不语，迷奚带笑，柳柔花弱。", "难藐。", "扶归鸳帐，不褪罗裳，要人求托。", "偷偷弄搦。", "红玉软，暖香薄。", "待酒醒枕臂，同歌新唱，怕晓愁闻画角。", "问昨宵、可㬠归迟，更休道著。"]'),
('song-ci-736','瑞鹤仙','杨无咎','宋','宋词','song-ci','瑞鹤仙','["\u897f\u6e56"]','听梅花再弄。',126,'宋词/ci.song.7000.json','["听梅花再弄。", "残酒醒，无寐寒衾愁拥。", "凄凉谁与共。", "谩赢得，别恨离怀千种。", "拂墙树动。", "更晓来、云阴雨重。", "对伤心好景，回首旧游，恍然如梦。", "欢纵。", "西湖曾是，画舫争驰，绣鞍双控。", "归来夜中。", "要银烛，卸金凤。", "到而今，谁拈花枝同载，谁酌酒杯笑捧。", "但逢花对酒，空祗自歌自送。"]'),
('song-ci-737','瑞鹤仙','杨无咎','宋','宋词','song-ci','瑞鹤仙','["\u897f\u6e56"]','见兰枯菊悴。',126,'宋词/ci.song.7000.json','["见兰枯菊悴。", "□寂寞，天与春风来至。", "梅梢弄晴蕊。", "似於人，装点十分和气。", "吴头楚尾。", "听民谣、欢声鼎沸。", "总扶携□手，嬉游鼓腹，顿忘愁悴。", "谁比。", "承流宣化，问俗观风，一时双美。", "笙歌宴启。", "交酬献，尽沈醉。", "□□□，行看宸庭同拜，归向天街并辔。", "对西湖把酒，应须共谈旧治。"]'),
('song-ci-738','瑞鹤仙','杨无咎','宋','宋词','song-ci','瑞鹤仙','[]','数文章翰墨。',126,'宋词/ci.song.7000.json','["数文章翰墨。", "前辈远，稍□风流岑寂。", "公才万夫敌。", "嗣家声，不坠江西人物。", "凝脂点漆。", "向鸳行、神峰秀出。", "况襟怀倜傥，词华洒落，未容俦匹。", "均逸。", "妙龄识退，故国怀归，问安亲戚。", "屏风坐隔。", "看除召，在晨夕。", "对生朝，且趁清明时节，痛饮无妨堕帻。", "著莱衣戏舞，千春永如是日。"]'),
('song-ci-739','雨中花・夜行船','杨无咎','宋','宋词','song-ci','雨中花・夜行船','[]','海宇澄明，天气宴温，人情物态昭苏。',118,'宋词/ci.song.7000.json','["海宇澄明，天气宴温，人情物态昭苏。", "喜分付揽辔，来与春俱。", "潇洒兰亭醉墨，丁宁黄石传书。", "到如今几载，不坠风流，世有名儒。", "山川瑞色，樵牧欢声，尽随弦管虚徐。", "判醉笑、频挥玉麈，共□金壶。", "湔祓聊勤大手，谋谟宜佐皇图。", "定知朝暮，未容温席，已促锋车。"]'),
('song-ci-740','雨中花・夜行船','杨无咎','宋','宋词','song-ci','雨中花・夜行船','[]','漠漠云轻，涓涓露重，西风特地飕飕。',119,'宋词/ci.song.7000.json','["漠漠云轻，涓涓露重，西风特地飕飕。", "觉良宵初永，袢暑微收。", "乘鹤缑山，浮槎银汉，尚想风流。", "笑人间儿戏，瓜果堆盘，缯彩为楼。", "广庭净扫，露坐披衣，细看新月如钩。", "谁道是、嫦娥不嫁，独守清秋。", "雅有骚人伴侣，长交清影夷犹。", "举杯相属，却应羞杀，呆女痴牛。"]'),
('song-ci-741','雨中花・夜行船','杨无咎','宋','宋词','song-ci','雨中花・夜行船','[]','雨霁云收，风高露冷，银河万里波澄。',119,'宋词/ci.song.7000.json','["雨霁云收，风高露冷，银河万里波澄。", "正冰轮初见，玉斧修成。", "还是一年，凭栏望处，对景愁生。", "想姮娥应念，待久西厢，为可中庭。", "翻思皓彩，未如微暗，向人多少深情。", "长记得、墙阴密语，花底潜行。", "饮散频羞烛影，梦馀常怯窗明。", "此时此意，有谁曾问，月白风清。"]'),
('song-ci-742','鹊桥仙','杨无咎','宋','宋词','song-ci','鹊桥仙','[]','云容掩帐，星辉排烛，待得鹊成桥后。',68,'宋词/ci.song.7000.json','["云容掩帐，星辉排烛，待得鹊成桥后。", "匆匆相见夜将阑，更应副、家家乞巧。", "经年怨别，霎时欢会，心事如何可了。", "朝朝暮暮是佳期，乍可在、人间先老。"]'),
('song-ci-743','洞仙歌','杨无咎','宋','宋词','song-ci','洞仙歌','[]','痴牛呆女，谩恩深情远。',101,'宋词/ci.song.7000.json','["痴牛呆女，谩恩深情远。", "一岁惟能一相见。", "纵金风玉露，胜却人间，争奈向、雪月花时阻间。", "幽欢犹未足，催度桥归，乌鹊无端便惊散。", "别后欲重来，杳杳银河，空怅望、不胜凄断。", "最可惜、当初泛槎人，甚不问、天边这些磨难。"]'),
('song-ci-744','多丽','杨无咎','宋','宋词','song-ci','多丽','[]','晚风清，淡云卷尽轻罗。',173,'宋词/ci.song.7000.json','["晚风清，淡云卷尽轻罗。", "看银蟾、初离海上，万里碧汉澄波。", "碾云衢、玉轮缓驾，照山影、宝镜新磨。", "光彻庭除，寒生绮席，无聊清兴助吟哦。", "共宴赏、明宵天气，晴晦又知他。", "无眠处，衣濡湛露，目断明河。", "念年来、青云失志，举头羞见嫦娥。", "且高歌、细敲檀板，拚痛饮、频倒金荷。", "断约他年，重挥大手，桂枝须斫最高柯。", "恁时节、清光比似，今夕更应多。", "功名事，到头须在，休用忙呵。"]'),
('song-ci-745','卓牌子慢・卓牌子','杨无咎','宋','宋词','song-ci','卓牌子慢・卓牌子','[]','西楼天将晚。',68,'宋词/ci.song.7000.json','["西楼天将晚。", "流素月、寒光正满。", "楼上笑揖姮娥，似看罗袜尘生，鬓云风乱。", "珠帘终夕卷。", "判不寐、阑干凭暖。", "好在影落清尊，冷侵香幄，欢馀未教人散。"]'),
('song-ci-746','倒垂柳','杨无咎','宋','宋词','song-ci','倒垂柳','[]','晓来烟露重，为重阳、增胜致。',98,'宋词/ci.song.7000.json','["晓来烟露重，为重阳、增胜致。", "记一年好处，无似此天气。", "东篱白衣至，南陌芳筵启。", "风流曾未远，登临都在眼底。", "人生如寄。", "谩把茱萸看子细。", "击节听高歌，痛饮莫辞醉。", "乌帽任教，颠倒风里坠。", "黄花明日，纵好无情味。"]'),
('song-ci-747','惜黄花慢','杨无咎','宋','宋词','song-ci','惜黄花慢','[]','霁空如水。',130,'宋词/ci.song.7000.json','["霁空如水。", "衬落木坠红，遥山堆翠。", "独立闲阶，数声□度风前，几点雁横云际。", "已凉天气未寒时，问好处、一年谁记。", "笑声里。", "摘得半钗，金蕊来至。", "横斜为插乌纱，更碎揉、泛入金尊琼蚁。", "满酌霞觞，愿人寿百千，可奈此时情味。", "牛山何必独沾衣，对佳节、惟应欢醉。", "看睡起。", "晓蝶也愁花悴。"]'),
('song-ci-748','醉花阴','杨无咎','宋','宋词','song-ci','醉花阴','[]','满城风雨无端恶。',62,'宋词/ci.song.7000.json','["满城风雨无端恶。", "孤负登高约。", "佳节若为酬，盛与歌呼，胜却秋萧索。", "菊花旋摘揉青萼。", "满满浮杯杓。", "老鬓未侵霜，醉里乌纱，不怕风吹落。"]'),
('song-ci-749','醉花阴','杨无咎','宋','宋词','song-ci','醉花阴','[]','捧杯不管馀酲恶。',62,'宋词/ci.song.7000.json','["捧杯不管馀酲恶。", "玉腕宽金约。", "宛转一声清，戛玉敲冰，浑胜鸣弦索。", "朱唇浅破桃花萼。", "重注鸬鹚杓。", "夜永醉归来，细想罗襟，犹有梁尘落。"]'),
('song-ci-750','醉花阴','杨无咎','宋','宋词','song-ci','醉花阴','[]','楚乡易得天时恶。',62,'宋词/ci.song.7000.json','["楚乡易得天时恶。", "风雨长如约。", "不道有幽人，衣带秋深，犹自悬鹑索。", "招呼朋侣如花萼。", "有酒须同酌。", "世态任凋疏，却爱黄花，不似群花落。"]'),
('song-ci-751','醉花阴','杨无咎','宋','宋词','song-ci','醉花阴','[]','金铃玉屑嫌非巧。',62,'宋词/ci.song.7000.json','["金铃玉屑嫌非巧。", "生作文鸳小。", "西帝也多情，偷取佳名，分付闲花草。", "渊明手把谁携酒。", "羞把簪乌帽。", "寄与绮窗人，百种妖娆，不似酴醿好。"]'),
('song-ci-752','醉花阴','杨无咎','宋','宋词','song-ci','醉花阴','[]','淋漓尽日黄梅雨。',62,'宋词/ci.song.7000.json','["淋漓尽日黄梅雨。", "断送春光暮。", "目断向高楼，持酒停歌，无计留春住。", "扑人飞絮浑无数。", "总是添愁绪。", "回首问春风，争得春愁，也解随春去。"]'),
('song-ci-753','解蹀躞','杨无咎','宋','宋词','song-ci','解蹀躞','[]','迤逦韶华将半。',90,'宋词/ci.song.7000.json','["迤逦韶华将半。", "桃杏匀於染。", "又还撩拨、春心倍凄黯。", "准拟□□狂吟，可怜无复当年，酒肠文瞻。", "倦游览。", "憔悴羞窥鸾鉴。", "眉端为谁敛。", "可堪风雨、无情暗亭槛。", "触目千点飞红，问春争得春愁，也随春减。"]'),
('song-ci-754','琐窗寒','杨无咎','宋','宋词','song-ci','琐窗寒','[]','柳暗藏鸦，花深见蝶，物华如绣。',123,'宋词/ci.song.7000.json','["柳暗藏鸦，花深见蝶，物华如绣。", "情多思远，又是一番清瘦。", "忆前回、庭榭来春，个人预约同携手。", "恨迟留，载酒期程，孤负踏青时候。", "搔首。", "双眉暗斗。", "况无似今年，一春晴昼。", "风﹀雨︽。", "直得□时迤逗。", "想闲窗、针线倦拈，寂寞细拈酴醿嗅。", "待还家、定自冤人，泪粉盈襟袖。"]'),
('song-ci-755','玉楼春','杨无咎','宋','宋词','song-ci','玉楼春','[]','朱帘碧瓦干云际。',64,'宋词/ci.song.7000.json','["朱帘碧瓦干云际。", "占尽潇滩形势地。", "傍墙人唤状元家，想见华堂融瑞气。", "寿杯莫惜团栾醉。", "跳虎转龟寻旧喜。", "小邦只恐久难留，异日君王重赐第。"]'),
('song-ci-756','玉楼春','杨无咎','宋','宋词','song-ci','玉楼春','[]','娉婷标格神仙样。',64,'宋词/ci.song.7000.json','["娉婷标格神仙样。", "几日佩环离海上。", "小春只隔一旬期，菊蕊包香犹未放。", "霞觞满酌摇红浪。", "慢引新声云际响。", "玉颜长与姓相宜，寿数三回排第行。"]'),
('song-ci-757','玉楼春','杨无咎','宋','宋词','song-ci','玉楼春','[]','酒阑未放宾朋散。',64,'宋词/ci.song.7000.json','["酒阑未放宾朋散。", "自拈冰芽教旋碾。", "调膏初喜玉成泥，溅沫共惊银作线。", "已知於我情非浅。", "不必宁宁书碗面。", "满尝乞得夜无眠，要听枕边言语软。"]'),
('song-ci-758','清平乐','杨无咎','宋','宋词','song-ci','清平乐','[]','开心暖胃。',54,'宋词/ci.song.7000.json','["开心暖胃。", "最爱门冬水。", "欲识味中犹有味。", "记取东坡诗意。", "笑看玉笋双传。", "还思此老亲煎。", "归去北窗高卧，清风不用论钱。"]'),
('song-ci-759','清平乐','杨无咎','宋','宋词','song-ci','清平乐','[]','花阴转午。',54,'宋词/ci.song.7000.json','["花阴转午。", "小院清无暑。", "雪碗冰瓯凝灏露。", "自涤紫毫鸡距。", "麝煤落纸生春。", "只应李卫夫人。", "我亦前身逸少，莫嗔太逼君真。"]'),
('song-ci-760','渔家傲','杨无咎','宋','宋词','song-ci','渔家傲','[]','昨日小春才得信。',72,'宋词/ci.song.7000.json','["昨日小春才得信。", "明宵新月初生晕。", "又对寿觞斟九酝。", "香成阵。", "欢声点破梅梢粉。", "琪树长青资玉润。", "鸳鸯不老眠沙稳。", "此去期程知远近。", "君休问。", "山河有尽情无尽。"]'),
('song-ci-761','渔家傲','杨无咎','宋','宋词','song-ci','渔家傲','[]','菊暗枯秋已满。',71,'宋词/ci.song.7000.json','["菊暗枯秋已满。", "枨黄橘绿冬初暖。", "草草杯盘成小宴。", "殷勤劝。", "尊前莫遣霞觞浅。", "两鬓从教霜点半。", "人生最要长为伴。", "举洒岂徒称寿算。", "深深愿。", "来年更看门风换。"]'),
('song-ci-762','渔家傲','杨无咎','宋','宋词','song-ci','渔家傲','[]','梅晕渐开红蜡垒。',72,'宋词/ci.song.7000.json','["梅晕渐开红蜡垒。", "菊篱尚耀黄金蕊。", "正是小春风物美。", "宜家喜。", "生朝颜巷犹和气。", "古鼎氤氲云缕细。", "霞觞潋滟红鳞起。", "听取殷勤歌里意。", "千秋气。", "北堂同我供甘旨。"]'),
('song-ci-763','渔家傲','杨无咎','宋','宋词','song-ci','渔家傲','[]','事事无心闲散惯。',72,'宋词/ci.song.7000.json','["事事无心闲散惯。", "有时独坐溪桥畔。", "雨密波平鱼曼衍。", "鱼曼衍。", "轮轻钓细随风卷。", "忆昔故人为侣伴。", "而今怎奈成疏间。", "水远山长无计见。", "无计见。", "投竿顿觉肠千断。"]'),
('song-ci-764','双雁儿','杨无咎','宋','宋词','song-ci','双雁儿','[]','穷阴急景暗推迁。',64,'宋词/ci.song.7000.json','["穷阴急景暗推迁。", "减绿鬓，捐朱颜。", "利名牵役几时闲。", "又还惊，一岁圆。", "劝君今夕不须眠。", "且满满，泛觥船。", "大家沈醉对芳筵。", "愿新年，胜旧年。"]'),
('song-ci-765','双雁儿','杨无咎','宋','宋词','song-ci','双雁儿','[]','休惊明日岁华新。',64,'宋词/ci.song.7000.json','["休惊明日岁华新。", "且喜得，又逢春。", "北堂歌舞奉慈亲。", "愿遐龄，等大椿。", "□□□□□□□。", "□□□，□□□。", "□□□□□□□。", "□□□，□□□。"]'),
('song-ci-766','迎春乐','杨无咎','宋','宋词','song-ci','迎春乐','[]','新来特特更门地。',65,'宋词/ci.song.7000.json','["新来特特更门地。", "都收拾、山和水。", "看明年、事事都如意。", "迎福禄、俱来至。", "莫管明朝添一岁。", "尽同向、尊前沈醉。", "且唱迎春乐，祝慈母、千秋岁。"]'),
('song-ci-767','永遇乐','杨无咎','宋','宋词','song-ci','永遇乐','[]','鸳瓦霜明，绣帘烟暖，和气容与。',127,'宋词/ci.song.7000.json','["鸳瓦霜明，绣帘烟暖，和气容与。", "云想衣裳，风清环佩，拥翠娥扶步。", "蓬山远别，仙班知是，有客旧同俦侣。", "朅来到、人间又也，爱他相门荣遇。", "清秋菊在，小春梅绽，正是年华好处。", "酒满瑶觞，歌翻金缕，莫放行云去。", "已随夫贵，仍因儿显，两国看齐楚。", "此时对、生朝听我，却称寿语。"]'),
('song-ci-768','永遇乐','杨无咎','宋','宋词','song-ci','永遇乐','[]','黄叶缤纷，碧江清浅，锦水秋暮。',128,'宋词/ci.song.7000.json','["黄叶缤纷，碧江清浅，锦水秋暮。", "画鼓冬冬，高牙飐飐，离棹无由驻。", "波声笳韵，芦花蓼穗，翻作别离情绪。", "须知道、风流太守，未尝恝情来去。", "那堪对此，来时单骑，去也文鸳得侣。", "绣被熏香，蓬窗听雨，还解知人否。", "一川风月，满堤杨柳，今夜酒醒何处。", "调疏呵，双栖正稳，慢摇去橹。"]'),
('song-ci-769','永遇乐','杨无咎','宋','宋词','song-ci','永遇乐','[]','风褪柔英，雨肥繁实，又还如豆。',128,'宋词/ci.song.7000.json','["风褪柔英，雨肥繁实，又还如豆。", "玉核初成，红腮尚浅，齿软酸微透。", "粉墙低亚，佳人惊见，不管露沾襟袖。", "折一枝、钗头未插，应把手捘频嗅。", "相如病酒，只因思此，免使文君眉皱。", "入鼎调羹，攀林止渴，功业还依旧。", "看看飞燕，衔将春去，又是欲黄时候。", "争如向、金盘满捧，共君对酒。"]'),
('song-ci-770','玉烛新','杨无咎','宋','宋词','song-ci','玉烛新','[]','荒山藏古寺。',125,'宋词/ci.song.7000.json','["荒山藏古寺。", "见傍水梅开，一枝三四。", "兰枯蕙死。", "登临处、慰我魂消惟此。", "可堪红紫。", "曾不解、和羹结子。", "高压尽、百卉千葩，因君合修花史。", "韶华且莫吹残，待浅搵松煤，写教形似。", "此时胸次。", "凝冰雪、洗尽从前尘滓。", "吟安个字。", "判不寐、勾牵幽思。", "谁伴我、香宿蜂媒，光浮月姊。"]'),
('song-ci-771','御街行','杨无咎','宋','宋词','song-ci','御街行','[]','平生厌见花时节。',94,'宋词/ci.song.7000.json','["平生厌见花时节。", "惟只爱、梅花发。", "破寒迎腊吐幽姿，占断一番清绝。", "照溪印月，带烟和雨，傍竹仍藏雪。", "松煤淡出宜孤洁。", "最嫌把、铅华说。", "暗香销尽欲飘零，须得笛声呜咽。", "这些风味，自家领略，莫与傍人说。"]'),
('song-ci-772','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','["\u897f\u6e56"]','傲雪凌霜。',61,'宋词/ci.song.7000.json','["傲雪凌霜。", "平欺寒力，搀借春光。", "步绕西湖，兴馀东阁，可奈诗肠。", "娟娟月转回廊。", "悄无处、安排暗香。", "一夜相思，几枝疏影，落在寒窗。"]'),
('song-ci-773','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','雪艳烟痕。',60,'宋词/ci.song.7000.json','["雪艳烟痕。", "又要春色来到芳尊。", "却忆年时，月移清影，人立黄昏。", "一番幽思谁论。", "但永夜、空迷梦魂。", "绕遍江南，缭墙深苑，水郭山村。"]'),
('song-ci-774','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','茅舍疏篱。',61,'宋词/ci.song.7000.json','["茅舍疏篱。", "半飘残雪，斜卧低枝。", "可更相宜，烟笼修竹，月在寒溪。", "亭亭伫立移时。", "判瘦损、无妨为伊。", "谁赋才情，画成幽思，写入新诗。"]'),
('song-ci-775','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','月堕霜飞。',61,'宋词/ci.song.7000.json','["月堕霜飞。", "隔窗疏瘦，微见横枝。", "不道寒香，解随羌管，吹到屏帷。", "个中风味谁知。", "睡乍起、乌云任敧。", "嚼蕊挼英，浅颦轻笑，酒半醒时。"]'),
('song-ci-776','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','日转墙东。',61,'宋词/ci.song.7000.json','["日转墙东。", "几枝寒影，一点香风。", "清不成眠，醉凭诗兴，起绕珍丛。", "平生只个情锺。", "渐老矣、无愁可供。", "最是难忘，倚楼人在，横笛声中。"]'),
('song-ci-777','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','玉骨冰肌。',61,'宋词/ci.song.7000.json','["玉骨冰肌。", "为谁偏好，特地相宜。", "一段风流，广平休赋，和靖无诗。", "绮窗睡起春迟。", "困无力、菱花笑窥。", "嚼蕊吹香，眉心贴处，鬓畔簪时。"]'),
('song-ci-778','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','为爱冰姿，画看不足，吟看不足。',61,'宋词/ci.song.7000.json','["为爱冰姿，画看不足，吟看不足。", "已恨春催，可堪风里，飞英相逐。", "只应自惜高标，似羞伴、妖红媚绿。", "藏白收香，放他桃李，漫山粗俗。"]'),
('song-ci-779','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','水曲山傍。',61,'宋词/ci.song.7000.json','["水曲山傍。", "寒梢冷蕊，隐映修篁。", "细细吹香，疏疏沈影，恼断回肠。", "为伊驻马横塘。", "漫立尽、烟村夕阳。", "空袅吟鞭，几多诗句，不入思量。"]'),
('song-ci-780','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','天付风流。',61,'宋词/ci.song.7000.json','["天付风流。", "相时宜称，著处清幽。", "雪月光中，烟溪影里，松竹梢头。", "却憎吹笛高楼。", "一夜里、教人鬓秋。", "不道明朝，半随风远，半逐波浮。"]'),
('song-ci-781','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','屋角墙隅。',61,'宋词/ci.song.7000.json','["屋角墙隅。", "占宽闲处，种两三株。", "月夕烟朝，影侵窗牖，香彻肌肤。", "群芳欲比何如。", "癯儒岂、膏梁共途。", "因事顺心，为花修史，从记中书。"]'),
('song-ci-782','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','瑞鸭烟浓。',61,'宋词/ci.song.7000.json','["瑞鸭烟浓。", "晓来弦管，声在霜空。", "却退寒威，借回春色，满苑香风。", "几时人下瑶宫。", "记千载、今朝庆逢。", "满捧瑶觞，芝兰丛里，锦绣光中。"]'),
('song-ci-783','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','江月轩中。',61,'宋词/ci.song.7000.json','["江月轩中。", "拍堤新涨，绕院熏风。", "深注瑶觞，低歌金缕，声在晴空。", "新词尽索无穷。", "断酩酊、衰颜为红。", "愿得年年，繁枝子满，绿叶阴浓。"]'),
('song-ci-784','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','槐夏风清。',61,'宋词/ci.song.7000.json','["槐夏风清。", "霁天欲晓，武曲增明。", "元是今朝，曾生名将，力佐中兴。", "朝家息马休兵。", "享逸乐、嬉游太平。", "忧国胸襟，平戎材略，分付瑶觥。"]'),
('song-ci-785','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','灼灼红榴，垂垂绿柳，庭户清和。',61,'宋词/ci.song.7000.json','["灼灼红榴，垂垂绿柳，庭户清和。", "罗绮香中，十分春酒，几叠高歌。", "遐龄欲问如何。", "记平日、阴功数多。", "千载今朝，笑看池面，龟戏青荷。"]'),
('song-ci-786','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','小阁深沈，酒醺香暖，容易眠熟。',61,'宋词/ci.song.7000.json','["小阁深沈，酒醺香暖，容易眠熟。", "梦入仙源，桃红似火，李莹如玉。", "觉来几许悲凉，记永夜、传杯换烛。", "绣被熏香，宝钗落枕，同论心曲。"]'),
('song-ci-787','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','送雁迎鸿，未寒时节，已凉天气。',61,'宋词/ci.song.7000.json','["送雁迎鸿，未寒时节，已凉天气。", "针线倦拈，帘帏低卷，别般风味。", "敧眠梦到山中，共老幼、扶携笑喜。", "桑柘影深，鸡豚香美，家家人醉。"]'),
('song-ci-788','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','暴雨生凉。',61,'宋词/ci.song.7000.json','["暴雨生凉。", "做成好梦，飞到伊行。", "几叶芭蕉，数竿修竹，人在南窗。", "傍人笑我恓惶。", "算除是、铁心石肠。", "一自别来，百般宜处，都入思量。"]'),
('song-ci-789','解连环','杨无咎','宋','宋词','song-ci','解连环','[]','素书谁托。',132,'宋词/ci.song.7000.json','["素书谁托。", "嗟鳞沈雁断，水遥山邈。", "问别来、几许离愁，但只觉衣宽，不禁消薄。", "岁岁年年，又岂是、春光萧索。", "自无心、强陪醉笑，负他满庭花药。", "援琴试弹贺若。", "尽清于别鹤，悲甚霜角。", "怎似得、斜拥檀槽，看小品吟商，玉纤推却。", "旋暖熏炉，更自炷、龙津双萼。", "正怀思、又还夜永，烛花自落。"]'),
('song-ci-790','踏莎行','杨无咎','宋','宋词','song-ci','踏莎行','[]','灯月交光，笙簧递响。',68,'宋词/ci.song.7000.json','["灯月交光，笙簧递响。", "繁华依旧升平样。", "心期休卜紫姑神，文章曾照青藜杖。", "歌落梁尘，酒摇鳞浪。", "暂还南国同邀赏。", "明年侍辇向端门，却瞻日表青霄上。"]'),
('song-ci-791','探春令','杨无咎','宋','宋词','song-ci','探春令','[]','梅英粉淡，柳梢金软，兰芽依旧。',65,'宋词/ci.song.7000.json','["梅英粉淡，柳梢金软，兰芽依旧。", "见万家、灯火明如昼。", "正人月、圆时候。", "挨香傍玉偷携手。", "尽轻衫寒透。", "听一声、画角催残漏。", "惜归去、频回首。"]'),
('song-ci-792','探春令','杨无咎','宋','宋词','song-ci','探春令','[]','雪梅风柳，弄金匀粉，峭寒犹浅。',64,'宋词/ci.song.7000.json','["雪梅风柳，弄金匀粉，峭寒犹浅。", "又还近、三五银蟾满。", "渐玉漏、声初短。", "尊前重约年时伴。", "拈灯词先按。", "便直饶、心似蛾儿撩乱。", "也有春风管。"]'),
('song-ci-793','探春令','杨无咎','宋','宋词','song-ci','探春令','[]','搦儿身分，测儿鞋子、捻儿年纪。',65,'宋词/ci.song.7000.json','["搦儿身分，测儿鞋子、捻儿年纪。", "著一套、时样不肯红，甚打扮、诸馀济。", "回头一笑千娇媚。", "知几多深意。", "奈月华、灯影交相照，诮没个、商量地。"]'),
('song-ci-794','探春令','杨无咎','宋','宋词','song-ci','探春令','[]','东风初到，小梅枝上，又惊春近。',63,'宋词/ci.song.7000.json','["东风初到，小梅枝上，又惊春近。", "料天台不比，人间日月，桃萼红英晕。", "刘郎浪迹凭谁问。", "莫因诗瘦损。", "怕桑田变海，仙源重返，老大无人认。"]'),
('song-ci-795','人月圆','杨无咎','宋','宋词','song-ci','人月圆','[]','风和日薄馀烟嫩，测测透鲛绡。',58,'宋词/ci.song.7000.json','["风和日薄馀烟嫩，测测透鲛绡。", "相逢且喜，人圆玳席，月满丹霄。", "烂游胜赏，高低灯火，鼎沸笙箫。", "一年三百六十日，愿长似今宵。"]'),
('song-ci-796','人月圆','杨无咎','宋','宋词','song-ci','人月圆','[]','月华灯影光相射。',58,'宋词/ci.song.7000.json','["月华灯影光相射。", "还是元宵也。", "绮罗如画，笙歌递响，无限风雅。", "闹蛾斜插，轻衫乍试，闲趁尖耍。", "百年三万六千夜，愿长如今夜。"]'),
('song-ci-797','眼儿媚','杨无咎','宋','宋词','song-ci','眼儿媚','[]','柳腰花貌天然好，聪慧更温柔。',58,'宋词/ci.song.7000.json','["柳腰花貌天然好，聪慧更温柔。", "千娇百媚，一时半霎，不离心头。", "是人总道新来瘦，也著甚来由。", "假饶薄命，因何瘦了，剗地风流。"]'),
('song-ci-798','倒垂柳','杨无咎','宋','宋词','song-ci','倒垂柳','[]','南州初会遇。',98,'宋词/ci.song.7000.json','["南州初会遇。", "记惺惺、说底语。", "而今精神□，倾下越风措。", "雍门人独夜，客舍停杯处。", "馀香应未泯，凭君重唱金缕。", "移宫易羽。", "纵有离愁休怨诉。", "客里□凄凉，怕听断肠句。", "情山曲海，君已心相许。", "骖鸾乘月，正好同归去。"]'),
('song-ci-799','南歌子','杨无咎','宋','宋词','song-ci','南歌子','[]','露宠妆成态，风扶醉里身。',61,'宋词/ci.song.7000.json','["露宠妆成态，风扶醉里身。", "谩劳驿使走征尘。", "岭外陇头处、不知春。", "诗思如清水，毫端妙入神。", "可怜徒效越娘颦。", "为问吟哦摹写、几曾真。"]'),
('song-ci-800','南歌子','杨无咎','宋','宋词','song-ci','南歌子','["\u957f\u6c5f"]','小雨疏疏过，长江滚滚流。',64,'宋词/ci.song.7000.json','["小雨疏疏过，长江滚滚流。", "落霞残照晚明楼。", "又是一番重午，身寄南州。", "罗绮纷香陌，鱼龙漾彩舟。", "不堪回首凤池头。", "谁道於今霜鬓，犹自淹留。"]'),
('song-ci-801','南歌子','杨无咎','宋','宋词','song-ci','南歌子','[]','波静明如染，山光翠欲流。',64,'宋词/ci.song.7000.json','["波静明如染，山光翠欲流。", "晚来乘兴上章楼。", "楼外谁歌新唱，知有黄州。", "拟泛银可浪，聊乘藕叶舟。", "蓬山应自隐鳌头。", "借问谪仙何在，今为谁留。"]'),
('song-ci-802','南歌子','杨无咎','宋','宋词','song-ci','南歌子','[]','笛喷风前曲，歌翻意外声。',62,'宋词/ci.song.7000.json','["笛喷风前曲，歌翻意外声。", "年来老子厌风情。", "可是於君一见、眼双明。", "枕臂听残漏，停杯对短檠。", "直教笔底有文星。", "欲状此时情味、若为成。"]'),
('song-ci-803','南歌子','杨无咎','宋','宋词','song-ci','南歌子','[]','巾染乌烟碧，衣拖晓露鲜。',62,'宋词/ci.song.7000.json','["巾染乌烟碧，衣拖晓露鲜。", "盈盈风骨小神仙。", "特地勾牵处士、梦巫山。", "星宿罗胸次，牙签弄指端。", "凭君为算小行年。", "试问与伊结得、几生缘。"]'),
('song-ci-804','南歌子','杨无咎','宋','宋词','song-ci','南歌子','[]','彩缕牵肠断，明珠暗滴圆。',62,'宋词/ci.song.7000.json','["彩缕牵肠断，明珠暗滴圆。", "从头颗颗手亲穿。", "寄与仙乡同结、此生缘。", "和串拢瑜臂，连云坠雪肩。", "循环密数对沈烟。", "似我真情不断、永相联。"]'),
('song-ci-805','西江月','杨无咎','宋','宋词','song-ci','西江月','[]','沙上鸥群□戏，云端雁阵斜铺。',58,'宋词/ci.song.7000.json','["沙上鸥群□戏，云端雁阵斜铺。", "殷勤特为故人书。", "写尽衷肠情素。", "名字纵非俦匹，夤缘自合欢娱。", "尽教涂抹费工夫。", "到底翻成吃醋。"]'),
('song-ci-806','西江月','杨无咎','宋','宋词','song-ci','西江月','[]','态度雪香花瘦，情怀雨润云温。',58,'宋词/ci.song.7000.json','["态度雪香花瘦，情怀雨润云温。", "故将淡墨写精神。", "记得洗妆馀晕。", "只恐妖娆未似，谁云彼此难分。", "别来憔悴不堪论。", "相对无言有恨。"]'),
('song-ci-807','生查子','杨无咎','宋','宋词','song-ci','生查子','[]','秋深郎未归，月上人初静。',48,'宋词/ci.song.7000.json','["秋深郎未归，月上人初静。", "无语意迟迟，步转梧桐影。", "罗衣宽莫裁，云鬓松还整。", "谁与问相思，立尽清宵永。"]'),
('song-ci-808','生查子','杨无咎','宋','宋词','song-ci','生查子','[]','秋来愁更深，黛拂双蛾浅。',48,'宋词/ci.song.7000.json','["秋来愁更深，黛拂双蛾浅。", "翠袖怯春寒，修竹萧萧晚。", "此意有谁知，恨与孤鸿远。", "小立背西风，又是重门掩。"]'),
('song-ci-809','生查子','杨无咎','宋','宋词','song-ci','生查子','[]','妖娆百种宜，总在春风面。',48,'宋词/ci.song.7000.json','["妖娆百种宜，总在春风面。", "含笑又和嗔，莫作丹青现。", "问著却无言，觑了还回盼。", "底处奈思量，卷了还重展。"]'),
('song-ci-810','甘草子','杨无咎','宋','宋词','song-ci','甘草子','[]','秋暮。',57,'宋词/ci.song.7000.json','["秋暮。", "永夜西楼，冷月明窗户。", "梦破橹声中，忆在松江路。", "敧枕试寻曾游处。", "记历历、风光堪数。", "谁与浮家五湖去。", "尽醉眠秋雨。"]'),
('song-ci-811','鹧鸪天','杨无咎','宋','宋词','song-ci','鹧鸪天','[]','湖上风光直万金。',64,'宋词/ci.song.7000.json','["湖上风光直万金。", "芙蓉并蒂照清深。", "须知花意如人意，好在双心同一心。", "词共唱，酒俱斟。", "夜阑扶醉小亭阴。", "当时比翼连枝愿，未必风流得似今。"]'),
('song-ci-812','鹧鸪天','杨无咎','宋','宋词','song-ci','鹧鸪天','[]','休倩傍人为正冠。',64,'宋词/ci.song.7000.json','["休倩傍人为正冠。", "披襟散发最宜闲。", "水云况得平生趣，富贵何曾著眼看。", "低拍棹，称鸣銮。", "一尊长向枕边安。", "夜深贪钓波间月，睡起知他日几竿。"]'),
('song-ci-813','鹧鸪天','杨无咎','宋','宋词','song-ci','鹧鸪天','[]','不学真空不学仙。',64,'宋词/ci.song.7000.json','["不学真空不学仙。", "不居尘市不居山。", "时沽鲁酒供诗兴，莫管吴霜点鬓斑。", "只麽去，几时还。", "岂知魂梦□□间。", "凭君休作千年调，到处惟□一味闲。"]'),
('song-ci-814','鹧鸪天','杨无咎','宋','宋词','song-ci','鹧鸪天','[]','蕙性柔情忒可怜。',64,'宋词/ci.song.7000.json','["蕙性柔情忒可怜。", "盈盈真是女中仙。", "披图一见春风面，携手疑同玳瑁筵。", "挥象管，擘蛮笺。", "等闲写就碧云篇。", "风流意态犹难画，潇洒襟怀怎许传。"]'),
('song-ci-815','天下乐','杨无咎','宋','宋词','song-ci','天下乐','[]','雪后雨儿雨后雪。',67,'宋词/ci.song.7000.json','["雪后雨儿雨后雪。", "镇日价、长不歇。", "今番为寒忒太切。", "和天地、也来厮鳖。", "睡不著、身心自暗攧。", "这况味、凭谁说。", "枕衾冷得浑似铁。", "只心头、些个热。"]'),
('song-ci-816','玉抱肚','杨无咎','宋','宋词','song-ci','玉抱肚','[]','同行同坐。',174,'宋词/ci.song.7000.json','["同行同坐。", "同携同卧。", "正朝朝暮暮同欢，怎知终有抛亸。", "记江皋惜别，那堪被、流水无情送轻舸。", "有愁万种，恨未说破。", "知重见、甚时可。", "见也浑闲，堪嗟处、山遥水远，音书也无个。", "这眉头、强展依前锁。", "这泪珠、强抆依前堕。", "我平生、不识相思，为伊烦恼忒大。", "你还知麽。", "你知后、我也甘心受催挫。", "又只恐你，背盟誓、似风过。", "共别人、忘著我。", "把洋澜在，都卷尽与，杀不得、这心头火。"]'),
('song-ci-817','雨中花令','杨无咎','宋','宋词','song-ci','雨中花令','[]','惆怅红尘千里。',65,'宋词/ci.song.7000.json','["惆怅红尘千里。", "恨死拨、浮名浮利。", "欠我温存，少伊撋就，两处悬悬地。", "拟待归来伏不是。", "更与问、孤眠子细。", "月照纱窗，晓灯残梦，可㬠恶姿味。"]'),
('song-ci-818','雨中花令','杨无咎','宋','宋词','song-ci','雨中花令','[]','已是花魁柳冠。',65,'宋词/ci.song.7000.json','["已是花魁柳冠。", "更绝唱、不容同伴。", "画鼓低敲，红牙随应，著个人勾唤。", "慢引莺喉千样转。", "听过处、几多娇怨。", "换羽移宫，偷声减字，不愿人肠断。"]'),
('song-ci-819','雨中花令','杨无咎','宋','宋词','song-ci','雨中花令','[]','自是云温雨润。',65,'宋词/ci.song.7000.json','["自是云温雨润。", "诮不解、佯嗔偷闷。", "倾坐精神，忺人情性，眉际生春晕。", "语带京华清更韵。", "听娅姹、莺喉娇稳。", "别后相思，心头欲见，觅个灯花信。"]'),
('song-ci-820','夜行船','杨无咎','宋','宋词','song-ci','夜行船','[]','不假铅华嫌太白。',69,'宋词/ci.song.7000.json','["不假铅华嫌太白。", "玉搓成、体柔腰搦。", "明月堂深，莲花杯软，情重自斟琼液。", "寄语碔砆休并色。", "信秦城、未教轻易。", "绛阙楼成，蓝桥药就，好吹箫共乘鸾翼。"]'),
('song-ci-821','夜行船','杨无咎','宋','宋词','song-ci','夜行船','[]','醉袖轻拢檀板转。',68,'宋词/ci.song.7000.json','["醉袖轻拢檀板转。", "听声声、晓莺初啭。", "花落江南，柳青客舍，多少旧愁新怨。", "我也寻常听见惯。", "浑不似、这翻撩乱。", "调少情多，语娇声咽，曲与寸肠俱断。"]'),
('song-ci-822','夜行船','杨无咎','宋','宋词','song-ci','夜行船','[]','宝髻双垂烟一缕。',69,'宋词/ci.song.7000.json','["宝髻双垂烟一缕。", "年纪小、未周三五。", "压一精神，出群标格，偏向众中翘楚。", "记得谯门初见处。", "禁不定、乱魂飞去。", "掌托鞋儿，肩拖裙子，悔不做、闲男女。"]'),
('song-ci-823','夜行船','杨无咎','宋','宋词','song-ci','夜行船','[]','怪被东风相误。',67,'宋词/ci.song.7000.json','["怪被东风相误。", "落轻帆、暂停烟渚。", "桐树阴森，茅檐潇洒，元是那回来处。", "相与狂朋沽绿醑。", "听胡姬、隔窗言语。", "我既痴迷，君还留恋，明日慢移船去。"]'),
('song-ci-824','夜行船','杨无咎','宋','宋词','song-ci','夜行船','["\u897f\u6e56"]','夹岸绮罗欢聚。',67,'宋词/ci.song.7000.json','["夹岸绮罗欢聚。", "看喧喧、彩舟来去。", "晴放湖光，雨添山色，谁识总相宜处。", "输与骚人知胜趣。", "醉临流、戏评坡句。", "若把西湖比西子，这东湖、似东邻女。"]'),
('song-ci-825','两同心','杨无咎','宋','宋词','song-ci','两同心','[]','行看不足。',86,'宋词/ci.song.7000.json','["行看不足。", "坐看不足。", "柳条短、斜倚春风，海棠睡、醉敧红玉。", "清堪掬。", "桃李漫山，真成粗俗。", "遥夜几番相属。", "暗魂飞逐。", "深酌酒、低唱新声，密传意、解回娇目。", "知谁福。", "得似风流，可伊心曲。"]'),
('song-ci-826','两同心','杨无咎','宋','宋词','song-ci','两同心','[]','秋水明眸、翠螺堆发。',86,'宋词/ci.song.7000.json','["秋水明眸、翠螺堆发。", "却扇坐、羞落庭花，凌波步、尘生罗袜。", "芳心发。", "分付春风，恰当时节。", "渐解愁花怨月。", "忒贪娇劣。", "宁宁地、情态于人，惺惺处、语言低说。", "相思切。", "不见须臾，可堪离别。"]'),
('song-ci-827','两同心','杨无咎','宋','宋词','song-ci','两同心','[]','月可中庭，夜凉初燕。',87,'宋词/ci.song.7000.json','["月可中庭，夜凉初燕。", "见个人人、越格风流，饶济济、入时打扮。", "小从容，不似前回，匆匆得见。", "坐上不禁肠断。", "捧杯深劝。", "争敢望、白雪新声，唯啜得、秋波一眄。", "告从今，休要教人，千呼万唤。"]'),
('song-ci-828','两同心','杨无咎','宋','宋词','song-ci','两同心','[]','枕簟凉生秋早。',88,'宋词/ci.song.7000.json','["枕簟凉生秋早。", "梦魂忒好。", "见玉人、且喜且悲，挨琼脸、厮偎厮抱。", "信言多磨，刚被山禽，一声催晓。", "觉来满船清悄。", "愁恨多少。", "知是我、怜你心微，知是你、与我情厚。", "谢殷勤，不易山遥水远寻到。"]'),
('song-ci-829','乌夜啼','杨无咎','宋','宋词','song-ci','乌夜啼','[]','不禁枕簟新凉。',45,'宋词/ci.song.7000.json','["不禁枕簟新凉。", "夜初长。", "又是惊回好梦、叶敲窗。", "江南望。", "江北望。", "水茫茫。", "赢得一襟清泪、拌馀香。"]'),
('song-ci-830','朝天子','杨无咎','宋','宋词','song-ci','朝天子','[]','小阁宽如掌。',57,'宋词/ci.song.7000.json','["小阁宽如掌。", "占螺浦、山川夷旷。", "千奇万状。", "见云烟收放。", "更永夜、风生明月上。", "用取真成无尽藏。", "谁共赏。", "徙倚抚、危栏吟望。"]'),
('song-ci-831','步蟾宫','杨无咎','宋','宋词','song-ci','步蟾宫','[]','桂花馥郁清无寐。',71,'宋词/ci.song.7000.json','["桂花馥郁清无寐。", "觉身在、广寒宫里。", "忆吾家、妃子旧游，瑞龙脑、暗藏叶底。", "不堪午夜西风起。", "更飐飐、万丝斜坠。", "向晓来、却是给孤园，乍惊见、黄金布地。"]'),
('song-ci-832','步蟾宫','杨无咎','宋','宋词','song-ci','步蟾宫','[]','一斑两点从初起。',66,'宋词/ci.song.7000.json','["一斑两点从初起。", "这手脚、渐不灵利。", "背人只待暗搔爬，腥臭气、薰天炙地。", "下梢管取好脓水。", "要洁净、怎生堪洗。", "自身作坏匹如闲，更和傍人带累。"]'),
('song-ci-833','长相思','杨无咎','宋','宋词','song-ci','长相思','[]','急雨回风，淡云障日，乘闲携客登楼。',128,'宋词/ci.song.7000.json','["急雨回风，淡云障日，乘闲携客登楼。", "金桃带叶，玉李含朱，一尊同醉青州。", "福善桥头。", "记檀槽凄绝，春笋纤柔。", "窗外月西流。", "似浔阳、商妇邻舟。", "况得意情怀，倦妆模样，寻思可奈离愁。", "何妨乘逸兴，甚征帆、只抵芦洲。", "月却花羞。", "重见想、欢情更稠。", "问何时，佳期卜夜，如今双鬓惊秋。"]'),
('song-ci-834','曲江秋','杨无咎','宋','宋词','song-ci','曲江秋','[]','前山雨歇。',125,'宋词/ci.song.7000.json','["前山雨歇。", "爱竹树低阴，轩窗无热。", "珠箔半垂，清风细绕，萧萧吹华发。", "珍簟粲枕设。", "珊瑚瘦，琉璃滑。", "永日敧枕，知谁是伴，旧书重揭。", "清绝。", "轻云淡月。", "梦同泛、沧波万叠。", "杯盘狼籍处，相扶就枕，欢笑歌翻雪。", "转棹小溪湾，人家灯火断明灭。", "正携手，无端惊回，槛外数声鶗鴂。"]'),
('song-ci-835','曲江秋','杨无咎','宋','宋词','song-ci','曲江秋','[]','香消烬歇。',125,'宋词/ci.song.7000.json','["香消烬歇。", "换沈水重燃，薰炉犹热。", "银汉坠怀，冰轮转影，冷光侵毛发。", "随分且宴设。", "小槽酒，真珠滑。", "渐觉夜阑，乌纱露濡，画帘风揭。", "清绝。", "轻纨弄月。", "缓歌处、眉山怨叠。", "持杯须我醉，香红映脸，双腕凝霜雪。", "饮散晚归来，花梢指点流萤灭。", "睡未稳，东窗渐明，远树又闻鶗鴂。"]'),
('song-ci-836','曲江秋','杨无咎','宋','宋词','song-ci','曲江秋','[]','鸣鸠怨歇。',125,'宋词/ci.song.7000.json','["鸣鸠怨歇。", "对急雨过云，暗风吹热。", "漠漠稻田，差差柳岸，新沐青丝发。", "楼上素琴设。", "爱流水，随弦滑。", "深炷龙津，浓熏绛帏，博山频揭。", "超绝。", "遥岑吐月。", "照苍茜、重重叠叠。", "恍然身在处，浑疑同泛，花舫波喷雪。", "滉漾醉魂醒，惊呼不是沤生灭。", "伫望久，空叹无才可赋，厌听鶗鴂。"]'),
('song-ci-837','点绛唇','杨无咎','宋','宋词','song-ci','点绛唇','[]','小阁清幽，胆瓶高插梅千朵。',50,'宋词/ci.song.7000.json','["小阁清幽，胆瓶高插梅千朵。", "主宾欢坐。", "不速还容我。", "换羽移宫，绝唱谁能和。", "伊知麽。", "暂听些个。", "已觉丝成裹。"]'),
('song-ci-838','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','渐近青春，试寻红瓃，经年疏隔。',61,'宋词/ci.song.7000.json','["渐近青春，试寻红瓃，经年疏隔。", "小立风前，恍然初见，情如相识。", "为伊只欲颠狂，犹自把、芳心爱惜。", "传与东君，乞怜愁寂，不须要勒。"]'),
('song-ci-839','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','嫩蕊商量。',61,'宋词/ci.song.7000.json','["嫩蕊商量。", "无穷幽思，如对新妆。", "粉面微红，檀唇羞启，忍笑含香。", "休将春色包藏。", "抵死地、教人断肠。", "莫待开残，却随明月，走上回廊。"]'),
('song-ci-840','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','粉墙斜搭。',61,'宋词/ci.song.7000.json','["粉墙斜搭。", "被伊勾引，不忘时霎。", "一夜幽香，恼人无寐，可堪开币。", "晓来起看芳丛，只怕里、危梢欲压。", "折向胆瓶，移归芸阁，休薰金鸭。"]'),
('song-ci-841','柳梢青','杨无咎','宋','宋词','song-ci','柳梢青','[]','目断南枝。',61,'宋词/ci.song.7000.json','["目断南枝。", "几回吟绕，长怨开迟。", "雨浥风欺，雪侵霜妒，却恨离披。", "欲调商鼎如期。", "可奈向、骚人自悲。", "赖有毫端，幻成冰彩，长似芳时。"]'),
('song-ci-842','法曲散序・法曲','曹勋','宋','宋词','song-ci','法曲散序・法曲','[]','飞金走玉常奔驰。',105,'宋词/ci.song.7000.json','["飞金走玉常奔驰。", "日上还西。", "自古待著长绳系。", "算尘心、谩劳役堪悲。", "盘古到此际。", "桑田变海，海复成陆高低。", "噫嘻。", "下土是凡质容仪。", "寿考能消，几日支持。", "念一世。", "真若朝荣暮落难期。", "幸有志、日传得神仙希夷。", "希夷。", "堪为千古人师。"]'),
('song-ci-843','法曲歌头・法曲','曹勋','宋','宋词','song-ci','法曲歌头・法曲','[]','柱史乘车，青牛驾轭，紫云覆顶，函关令已前知。',176,'宋词/ci.song.7000.json','["柱史乘车，青牛驾轭，紫云覆顶，函关令已前知。", "西升稍驻，尹喜虔恭誓。", "求老子。", "亲谈道德微旨。", "五千馀言，俱救末俗，度脱令咸归生理。", "体元机。", "人间方解道术，兼明治身，与国阶梯。", "更有黄庭，专分二境，内外皆举璇题。", "羽客见者，倾诚恳诵合彝仪。", "万神潜礼。", "密奉二经，炷香静默，心无竞，靡端倪。", "得失扫去，意海澄流要体。", "内景防愆失。", "外景忘疲。", "阆风蓬岛岂能移。", "念诵灵辞。", "指群迷。"]'),
('song-ci-844','法曲遍第一・法曲','曹勋','宋','宋词','song-ci','法曲遍第一・法曲','[]','丽景早春时。',131,'宋词/ci.song.7000.json','["丽景早春时。", "正花漏初迟。", "东君出震，太和应物，恍惚中立丹基。", "天风卦成随象，记合成□□□□□□□必相契。", "三千六百火候，密运精微。", "蒸入肌肤，嫩红潮颊，自然旧容生辉。", "情志。", "鄙凡尘，瑶圃满眼，都看桃李。", "晴云万叠开异色。", "灵光湛湛增秀逸。", "与道合。", "真境丹房，随时沐浴，亦向朝夕。"]'),
('song-ci-845','法曲遍第二・法曲','曹勋','宋','宋词','song-ci','法曲遍第二・法曲','[]','向虚靖晨起。',136,'宋词/ci.song.7000.json','["向虚靖晨起。", "朝元意达，冲漠怡怡。", "三天澄映，九光霁碧，如有鹤舞鸾飞。", "泛空际。", "瑶室明辉。", "动与真期。", "至理常寂，户庭无远，欣欣端比。", "侍宴日在瑶池。", "师友多闲，抱琴沽酒度曲，笑采华芝。", "九节倚筇时。", "何须钓月眠石，寻觅占渊静逸。", "乐修持。", "澹然灵府泳真谛。", "怡养丹光里。", "春已收功，自育火枣交梨。"]'),
('song-ci-846','法曲遍第三・法曲','曹勋','宋','宋词','song-ci','法曲遍第三・法曲','[]','珠星璧月，昼景夜色相催。',124,'宋词/ci.song.7000.json','["珠星璧月，昼景夜色相催。", "正阳炎序火府，龙珠蕴照，冰海融澌。", "洞天春常好，日日琪花，琼蕊芳菲。", "绛景无别，惟似琉璃。", "平地环绕清泚。", "火中生莲，会成真物，更取海底龟儿。", "胜热涤暑风，全形莹若冰肌。", "常存道意。", "铄石流金无畏。", "共协混元一气。", "入冲极。", "觉自己。", "乾体还归。"]'),
('song-ci-847','法曲第四・法曲','曹勋','宋','宋词','song-ci','法曲第四・法曲','[]','南薰殿阁，卷窗户新翠。',107,'宋词/ci.song.7000.json','["南薰殿阁，卷窗户新翠。", "池沼十顷净，俯桥影横霓。", "龟鱼自乐，潺潺螭口，流水照碧，芰荷绿满长堤。", "柳烟水色，一派涟漪。", "松竹阴中，细风缓引凉吹。", "琴韵响，玉德凤轸，声传瑶徽。", "疏襟曳履。", "或行或凭几。", "待饮彻、玉鼎云英，怎更有炎曦。"]'),
('song-ci-848','法曲入破第一・法曲','曹勋','宋','宋词','song-ci','法曲入破第一・法曲','[]','秋容应节，渐肃景入窗扉。',103,'宋词/ci.song.7000.json','["秋容应节，渐肃景入窗扉。", "碧洞连翠微。", "商律回岩桂。", "金精壮盛时。", "拥蟾轮、生素辉。", "启口天为侣，是列仙行缀。", "心均太上，欲度世缘无亏。", "用定力坚持。", "奉真常，惟凝寂。", "忱诚贯斗极。", "赐长生，仍久视。", "洞达虚皇位。", "德寿高与天齐。"]'),
('song-ci-849','法曲入破第二・法曲','曹勋','宋','宋词','song-ci','法曲入破第二・法曲','[]','清昼静居香冷，风动万年枝。',105,'宋词/ci.song.7000.json','["清昼静居香冷，风动万年枝。", "凉应兑卦体。", "秋色鸣轻飔。", "冥心运正一。", "御铁牛、耕寸地。", "都种金钱花，秀色照戊己。", "新霜万物凋谢，我常无为。", "冲起浩然气。", "抱冲和，人间世。", "登高共赏宴，泛东篱。", "菊尽醉。", "谁会。", "登高意表、迥出凡尘外。"]'),
('song-ci-850','法曲入破第三・法曲','曹勋','宋','宋词','song-ci','法曲入破第三・法曲','[]','光铺晓曦。',102,'宋词/ci.song.7000.json','["光铺晓曦。", "云影拂霜低。", "空阔飞鸿过，两三行、向天际。", "晴景乍升，晃疏棂，蜂翅迷。", "密障红炉暖，香缕飘烟细。", "超然坐久，幽径试寻寒梅。", "酥点竹间稀。", "正疏蓓吐南枝。", "微阳动细蕊。", "任斜日、沈澹晖。", "惨惨寒威。", "晚知皓雪欲垂垂。"]'),
('song-ci-851','法曲入破第四・法曲','曹勋','宋','宋词','song-ci','法曲入破第四・法曲','[]','黄锺正严凛，飞舞屑琼瑰。',100,'宋词/ci.song.7000.json','["黄锺正严凛，飞舞屑琼瑰。", "清赏丰年瑞。", "云液喜传杯。", "阴爻会见复，动一阳、生浩气。", "谁问添宫线，炼功在金液。", "晴檐试暖，表里莹如无疵。", "庭柳漏春信，更萱色、侵苔砌。", "优游岁向晚，叹人间时序疾。", "还捧椒觞，羽衣礼无极。"]'),
('song-ci-852','法曲第五煞・法曲','曹勋','宋','宋词','song-ci','法曲第五煞・法曲','[]','多景推移。',81,'宋词/ci.song.7000.json','["多景推移。", "便似风灯里。", "将尘寰喻，尘里白驹过隙。", "今世过却，来生何处觅。", "失时节。", "生死到来嗟何及。", "勤而行之。", "竞力待与、锺吕相期。", "三千行满，连环脱下已。", "驾青鸾素鹤朝太微。"]'),
('song-ci-853','大椿','曹勋','宋','宋词','song-ci','大椿','[]','梅拥繁枝，香飘翠帘，钧奏严陈华宴。',120,'宋词/ci.song.7000.json','["梅拥繁枝，香飘翠帘，钧奏严陈华宴。", "诚孝感南极，老人星垂眷。", "东朝功崇庆远，享五福、长乐金殿。", "兹时寿协七旬，庆古今来稀见。", "慈颜绿发看更新，玉色粹温，体力加健。", "导引冲和气，觉春生酒面。", "龙章亲献龟台祝，与中宫、同诚欢忭。", "亿万斯年，当蓬莱、海波清浅。"]'),
('song-ci-854','花心动','曹勋','宋','宋词','song-ci','花心动','[]','椒柏称觞，抚寰瀛佳辰，正临端月。',123,'宋词/ci.song.7000.json','["椒柏称觞，抚寰瀛佳辰，正临端月。", "瑞应屡臻，宫篽多祥，气候暖回微冽。", "圣母七旬寿，敻无前、天心昭格。", "溥庆处，坤珍效祉，宴开清切。", "金殿箫韶备设。", "锵钧奏留云，舞容回雪。", "赭袍绣拥，褘翟同诚，递捧玉杯欢悦。", "愿将亿万喜，祝亿万、从兹无缺。", "太平主，永隆圣孝凤阙。"]'),
('song-ci-855','保寿乐','曹勋','宋','宋词','song-ci','保寿乐','[]','和气暖回元日，四海充庭琛贡至。',114,'宋词/ci.song.7000.json','["和气暖回元日，四海充庭琛贡至。", "仗卫俨东朝，郁郁葱葱，响传环佩。", "凤历无穷，庆慈闱上寿，皇情与天俱喜。", "念永锡难老，在昔难比。", "六宫嫔嫱罗绮。", "奉圣德、坤宁俱备。", "箫韶动钧奏，花似锦，广筵启。", "同祝宴赏处，从教月明风细。", "亿载享温凊，长生久视。"]'),
('song-ci-856','宴清都','曹勋','宋','宋词','song-ci','宴清都','[]','画幕明新晓。',127,'宋词/ci.song.7000.json','["画幕明新晓。", "晴日薄，小春微动花柳。", "宸闱荐祉，东朝诞育，载光坤厚。", "朱颜内鼎丹就。", "喜自得、长生妙有。", "奉冕旒、衣彩坤珍，同耀帕罗珠袖。", "钧奏。", "翠羽帘垂，三千粉色，花明如绣。", "歌声缓引，梁尘暗落，五云凝昼。", "龙香绕斟芳酒。", "尽夜饮、何妨禁漏。", "万万载、常向慈宁，俱献圣寿。"]'),
('song-ci-857','宴清都','曹勋','宋','宋词','song-ci','宴清都','[]','凤苑东风软。',128,'宋词/ci.song.7000.json','["凤苑东风软。", "春容早，岁端新律初转。", "宫云丽晓，人日应锺，庆符闺范。", "元妃懿德尊显。", "位四圣、晋芳避辇。", "佐圣主、美化重宣，光被海宇弥远。", "香满。", "帝渥恩隆，歌珠舞雪，俱陈丝管。", "彤闱共悦，天颜有喜，看寿觞亲劝。", "今年外家华焕。", "拥使节、新班侍宴。", "愿万载、永冠椒房，常奉舜殿。"]'),
('song-ci-858','一寸金','曹勋','宋','宋词','song-ci','一寸金','[]','霜落鸳鸯，绣隐芙蓉小春节。',133,'宋词/ci.song.7000.json','["霜落鸳鸯，绣隐芙蓉小春节。", "应运看，月魄分辉，坤顺同符，文母徽音芳烈。", "诞育乾坤主，均慈爱、练裙岂别。", "经沙塞、涉履烟尘，瑞色怡然更英发。", "上圣中兴，严恭问寝，宫庭正和悦。", "看寿筵高启，龙香低转，声入霓裳，檀槽新拨。", "翠衮同行乐，钧韶奏、喜盈绛阙。", "倾心愿、亿载慈宁，醉赏闲风月。"]'),
('song-ci-859','国香','曹勋','宋','宋词','song-ci','国香','[]','十月新阳。',121,'宋词/ci.song.7000.json','["十月新阳。", "喜桃杏秀发，宫殿春香。", "宝历开图，文母协应时康。", "诞庆欣逢令旦，向花闱、罄列嫔嫱。", "欢荣是九五，侍膳芳筵，翠扆龙章。", "天心人共喜，拱三钗瑞彩，同捧瑶觞。", "禁中和气，都入法部丝簧。", "一片神仙锦绣，正珠帘、高卷云光。", "遐龄祝亿载，永奉慈颜，地久天长。"]'),
('song-ci-860','国香','曹勋','宋','宋词','song-ci','国香','[]','红染芙蓉。',117,'宋词/ci.song.7000.json','["红染芙蓉。", "似晓霞丽日，秋满珠宫。", "瑞彩朝来，都做和气葱葱。", "共庆龟台降祉，化均凤历同风。", "升平助阴化，奉养馀闲，翰墨鸾龙。", "群仙移彩仗，尽红妆玉带，乐震霜空。", "响入千岩，芳桂香散房栊。", "劝寿天颜有喜，奉觞雁序雍容。", "蟠桃待从此，岁岁今朝，荐酒瑶锺。"]'),
('song-ci-861','齐天乐','曹勋','宋','宋词','song-ci','齐天乐','[]','芙蓉凝露青霞护，朝日绮疏风细。',124,'宋词/ci.song.7000.json','["芙蓉凝露青霞护，朝日绮疏风细。", "正是中秋，时候喜逢，中宫葱葱佳气。", "云龙庆会。", "赞真主当阳，辅成天地。", "暇日琴书，暂闲蚕馆见贤志。", "嫔嫱衣罗乍试。", "尽趋椒殿，喜芳绣筵初启。", "酒面腾红，香烟罩碧，恩满六宫金翠。", "何妨绛烛。", "任花敧玉侧，劝教沈醉。", "凤阙龙楼，夜色凉如水。"]'),
('song-ci-862','透碧霄','曹勋','宋','宋词','song-ci','透碧霄','[]','阆苑喜新晴。',144,'宋词/ci.song.7000.json','["阆苑喜新晴。", "正桂华、飘下太清。", "宝篽凉秋，梦祥明月，天开辅盈成。", "宫闱女职遵慈训，见海宇仪型。", "奉东朝、晨夕趋承。", "化内外、咸知柔顺，已看彤管赋和平。", "宴坤宁。", "香腾金猊，烟暖秘殿彩衣轻。", "六乐丝竹，绕云萦水，总按新声。", "天临帝幄，亲颁寿酒，恩意兼勤。", "雁行缀、宰府殊荣。", "愿万亿斯年，南山并永，坤厚赞尧明。"]'),
('song-ci-863','芰荷香','曹勋','宋','宋词','song-ci','芰荷香','[]','彩云闲。',120,'宋词/ci.song.7000.json','["彩云闲。", "正西瑶阿母，初驻非烟。", "晓空吹静，暑气清度薰弦。", "母仪万国，配帝德、直切天垣。", "阴化从此俱宣。", "六宫内壶，欣拜新班。", "况是关雎咏懿美，奉东朝晨夕，甘旨芳鲜。", "上膺慈训，下齐海宇均欢。", "坤宁暇日，庆盛旦、且款芳筵。", "永赞二圣当天。", "雍和化洽，亿万斯年。"]'),
('song-ci-864','玉连环・解连环','曹勋','宋','宋词','song-ci','玉连环・解连环','[]','庆云开霁，清华明昼，殿阁风度薰弦。',117,'宋词/ci.song.7000.json','["庆云开霁，清华明昼，殿阁风度薰弦。", "电虹敷瑞，应炎运当千。", "端景命、符圣德，三阶正、万国归化，远胜文思睿藻，问鲭寝格中天。", "深严。", "邃启芳筵。", "正花拥绛扆，瑶殿神仙。", "缓闻钧韶奏下，歌舞云边。", "宫闱罄和气，浃南山。", "罩翠霭、上寿烟。", "祝无疆御历万万年。"]'),
('song-ci-865','夏云峰','曹勋','宋','宋词','song-ci','夏云峰','[]','绍洪基，抚万宇，中兴宝运符千。',113,'宋词/ci.song.7000.json','["绍洪基，抚万宇，中兴宝运符千。", "枢电瑞绕，景命燕及云天。", "挺生真主，平四海、复禹山川。", "班列立、瞻云就日，职贡衣冠。", "欢均鳌禁鹓鸾。", "望花城粉黛，金兽祥烟。", "笙箫缓奏，化国日永留连。", "宝觞亲劝，须纵饮、歌舞韶妍。", "都是祝、南山圣寿，亿万斯年。"]'),
('song-ci-866','凤凰台上忆吹箫','曹勋','宋','宋词','song-ci','凤凰台上忆吹箫','[]','碧玉烟塘，绛罗艳卉，朱清炎驭升晹。',121,'宋词/ci.song.7000.json','["碧玉烟塘，绛罗艳卉，朱清炎驭升晹。", "正应运、真人诞节，宝绪灵光。", "海宇均颁湛露，环佩拱、北极称觞。", "欢声浃，三十六宫，齐奉披香。", "芬芳。", "宝薰如霭，仙仗捧椒扉，秀绕嫔嫱。", "上万寿、双鬟妙舞，一部丝簧。", "花满蓬莱殿里，光照坐、尊俎生凉。", "南山祝，常对化日舒长。"]'),
('song-ci-867','安平乐・安平乐慢','曹勋','宋','宋词','song-ci','安平乐・安平乐慢','[]','圣德如尧，圣心如舜，欣逢出震昌期。',128,'宋词/ci.song.7000.json','["圣德如尧，圣心如舜，欣逢出震昌期。", "中兴继体，抚有寰瀛，三阳方是炎曦。", "万国朝元，奉崇严宸扆，咫尺天威。", "瑞色满三墀。", "渐嵩呼、均庆彤闱。", "正金屋妆成，翠围红绕，香霭高散狻猊。", "东朝移雕辇，与坤仪、同奉瑶卮。", "阖殿花明，亿万载、咸歌寿祺。", "视天民，永祈宝历，垂衣端拱无为。"]'),
('song-ci-868','夜合花','曹勋','宋','宋词','song-ci','夜合花','[]','星拱尧眉，日临云幄，晓天初静炎曦。',122,'宋词/ci.song.7000.json','["星拱尧眉，日临云幄，晓天初静炎曦。", "香凝翠扆，花笼禁殿风迟。", "彩山高与云齐。", "奉明主、玉斝交挥。", "庆天申旦，九州四海，同咏昌时。", "今年麦有双歧。", "别有琅玕并节，深秀联枝。", "丰世瑞物，嘉祥效祉熙熙。", "坐中莫惜沈醉，仰三圣、玉德光辉。", "献南山寿，严宸万载，永奉垂衣。"]'),
('song-ci-869','绿头鸭・多丽','曹勋','宋','宋词','song-ci','绿头鸭・多丽','[]','喜雨薰泛景，翠云低柳。',175,'宋词/ci.song.7000.json','["喜雨薰泛景，翠云低柳。", "正凉生殿阁，梅润晓天，暑风时候。", "应乘乾、彩虹流渚，惊电绕、璇霄枢斗。", "大业辉光，益建火德，梯航四海尽奔走。", "六府焕修，多方平定，寰宇歌元首。", "凝九有。", "三辰拱北，万邦孚佑。", "对祥烟、霁色清和，凤韶九成仪昼。", "听山声、响传呼舞，腾紫府、香浓金兽。", "禁篽升平，慈闱燕适，褘衣共上玉觞酒。", "齐奉舜图，南山同永，合殿备金奏。", "祝圣寿。", "圣寿无疆，两仪并久。"]'),
('song-ci-870','赏松菊','曹勋','宋','宋词','song-ci','赏松菊','[]','凉飙应律惊潮韵，晓对彩蟾如水。',116,'宋词/ci.song.7000.json','["凉飙应律惊潮韵，晓对彩蟾如水。", "庆霄占梦月，已祥开天地。", "圣主中兴大业，二南化、恭勤辅翊。", "抚宫闱，看仪型，海宇尽成和气。", "禁掖西瑶宴席。", "泛天风、响钧韶空外。", "贵是至尊母，极人间崇贵。", "缓引长生丽曲，翠林正、香传瑞桂。", "向灵华，奉光尧，同万万岁。"]'),
('song-ci-871','瑞鹤仙','曹勋','宋','宋词','song-ci','瑞鹤仙','[]','小梅凝秀色，泛霁霭晴和，春容初透。',126,'宋词/ci.song.7000.json','["小梅凝秀色，泛霁霭晴和，春容初透。", "璇霄降仙格，觉葱葱佳气，先惊花柳。", "芝兰户牖。", "庆禀质、天长地久。", "有当熊避辇，嘉声懿德，六宫居右。", "清昼。", "文箫仪凤，妙舞低云，缓锵钧奏。", "香传绣幄，腾飞雾，上金兽。", "愿千龄遐算，三宫慈爱，长亭兹辰劝酒。", "向瑶台阆苑，芳音永嫔万寿。"]'),
('song-ci-872','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','翠帘迟晚，龙楼丽日，海宇明新霁。',127,'宋词/ci.song.7000.json','["翠帘迟晚，龙楼丽日，海宇明新霁。", "枢旋大电，虹流华渚，阳春天气。", "出震乘乾，保民立政，垂衣裳治。", "诞恩均九有，功兼七制，恢图抚、四荒外。", "威动殊邻万里。", "拥衣冠、称觞玉陛。", "虞韶缓度，龙香飞下，晴云如水。", "行见冰天，版图来上，诸侯盟会。", "奉怡颜宴罢，归移宝辇，向瑶池醉。"]'),
('song-ci-873','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','嫩凉微袅，秋容乍肃，迥觉凉如水。',127,'宋词/ci.song.7000.json','["嫩凉微袅，秋容乍肃，迥觉凉如水。", "重阳已近，岩华增秀，一钩天际。", "香动前星，气横文圃，荣光呈瑞。", "仰宸心密眷，行都正牧，兵民奉、神明治。", "金殿朝回燕适。", "肆武功、文德咸备。", "萧闲翰墨，惟亲书史，不寻罗绮。", "欢动宸严，宴开鹤禁，生朝和气。", "愿青宫布政，龙楼问寝，同千万岁。"]'),
('song-ci-874','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','傍阶红药，新梢翠竹，榭阁薰风静。',127,'宋词/ci.song.7000.json','["傍阶红药，新梢翠竹，榭阁薰风静。", "维神降岳，维熊占梦，姿仪玉聘。", "金殿趋庭，禁严衣彩，寝门温清。", "是宗藩帝子，天潢宝牒，当神武、侍明廷。", "为善先知最乐，咏诗书、存存成性。", "亲师讲道，摛华挥藻，水云高兴。", "一代荣观，觊尧显舜，古今难并。", "看青华蕊简，松乔比寿，佐南风政。"]'),
('song-ci-875','月上海棠慢・月上海棠','曹勋','宋','宋词','song-ci','月上海棠慢・月上海棠','[]','东风扬暖，渐是春半，海棠丽烟径。',113,'宋词/ci.song.7000.json','["东风扬暖，渐是春半，海棠丽烟径。", "似蜀锦晴展，翠红交映。", "嫩梢万点胭脂，移西溪、浣花真景。", "濛濛雨，黄鹂飞上，数声宜听。", "风定。", "朱阑夜悄，蟾华如水，初照清影。", "喜浓芳满地，暗香难并。", "悄如彩云光中，留翔鸾、静临芳镜。", "携酒去、何妨花边露冷。"]'),
('song-ci-876','松梢月','曹勋','宋','宋词','song-ci','松梢月','[]','院静无声。',119,'宋词/ci.song.7000.json','["院静无声。", "天边正、皓月初上重城。", "群木摇落，松路径暖风轻。", "喜揖蟾华当松顶，照榭阁、细影纵横。", "杖策徐步空明里，但襟袖皆清。", "恍若如临异境，漾凤沼岸阔，波净鱼惊。", "气入层汉，疑有素鹤飞鸣。", "夜色徘徊迟宫漏，渐坐久、露湿金茎。", "未忍归去，闻何处、重吹笙。"]'),
('song-ci-877','隔帘花','曹勋','宋','宋词','song-ci','隔帘花','[]','宿雨初晴，花艳迎阳，槛前如绣如绮。',118,'宋词/ci.song.7000.json','["宿雨初晴，花艳迎阳，槛前如绣如绮。", "向晓峭寒轻，窣真珠十二。", "正朝曦、桃杏暖，透影帘栊烘春霁。", "似暂隔、祥烟香雾，朝仙侣庭际。", "更值迟迟丽日。", "且休约寻芳，与开瑶席。", "未拟上金钩，尽围红遮翠。", "命佳名、坤殿喜，为写新声传新意。", "待向晚、迎香临月须卷起。"]'),
('song-ci-878','东风第一枝','曹勋','宋','宋词','song-ci','东风第一枝','[]','宝苑明春，青霞射晚，六幕云闲风静。',124,'宋词/ci.song.7000.json','["宝苑明春，青霞射晚，六幕云闲风静。", "茂林修竹昂霄，素月照人澄莹。", "梅花十顷，递暗香、琼瑶真景。", "散万斛金莲，崇山秀岭，尽开花径。", "真个好、月灯相映。", "真个乐、圣驾游幸。", "四部箫韶，群仙奏乐，万光耀境。", "玉华不夜，向洞天、暖烟回冷。", "好大家、酒色醺醺，任教漏移花影。"]'),
('song-ci-879','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','鉴天云敛壶中，昼暖乍喜薰风永。',126,'宋词/ci.song.7000.json','["鉴天云敛壶中，昼暖乍喜薰风永。", "轻纱渐试，香罗初褪，梅阴又□。", "广殿窗虚，翠帘卷起，一番清影。", "正新篁绿嫩，池光涨雨，鱼吹浪、燕飞径。", "好是九重邃密，有岚光、烟溪深静。", "升平暇日，长廊别院，笙歌缓整。", "宝辇迟留，玉觞时举，何妨乘兴。", "况一年好处，犹寒未暖，是清和景。"]'),
('song-ci-880','夏云峰','曹勋','宋','宋词','song-ci','夏云峰','[]','五云开，过夜来、初收几阵梅雨。',109,'宋词/ci.song.7000.json','["五云开，过夜来、初收几阵梅雨。", "画罗携芳扇，正喜逢重午。", "角黍星团，巧萦臂、龙纹轻缕。", "细祝降福天中，列箫韶歌舞。", "薰风凉殿开处。", "称绡裙雾縠，莲步俦侣。", "翠铺交枝艾，便手香微度。", "菖丝浮玉，向台榭、留连欢聚。", "笑语。", "自有冰姿消烦暑。"]'),
('song-ci-881','忆吹箫・凤凰台上忆吹箫','曹勋','宋','宋词','song-ci','忆吹箫・凤凰台上忆吹箫','[]','烦暑衣襟，乍凉院宇，梧桐吹下新秋。',120,'宋词/ci.song.7000.json','["烦暑衣襟，乍凉院宇，梧桐吹下新秋。", "望鹊羽、桥成上汉，绿雾初收。", "喜见西南月吐，帘尽卷、玉宇珠楼。", "银潢晚，应是绛河，已度牵牛。", "何妨翠烟深处，佳丽拥缯筵，斗巧嬉游。", "是向夕、穿针竞立，香霭飞浮。", "别有回廊影里，应钿合、钗股空留。", "江天晓，萧萧雨入潮头。"]'),
('song-ci-882','尾犯','曹勋','宋','宋词','song-ci','尾犯','[]','秋空过雨静，晚景澄明，天淡如水。',124,'宋词/ci.song.7000.json','["秋空过雨静，晚景澄明，天淡如水。", "渐看蟾彩，东山旋升，金饼上云际。", "轻烟散尽，莹皓色、消尘翳。", "倚琼楼，皎若瑶台阆风，翠阑十二。", "正好登临无外。", "满斟与、清光对。", "虽桂华飘下，玉轮移影，归兴犹未。", "待继日同宴赏，听秘乐、广寒宫里。", "惟怕却，明月阴晴未定，且宜欢醉。"]'),
('song-ci-883','秋蕊香','曹勋','宋','宋词','song-ci','秋蕊香','[]','秋色宫庭，黄花禁篽，西风乍透罗衣。',119,'宋词/ci.song.7000.json','["秋色宫庭，黄花禁篽，西风乍透罗衣。", "龙山意渐爽，瑶砌叶初飞。", "喜天宇、明洁晓晴时。", "翠楼都卷帘帷。", "奉宴赏，菊英环坐，金玉成围。", "凭阑海山万里，登望处，休论戏马台池。", "揽幽芳、泛酒面香凝，携手与、仙姿共游嬉。", "从他纱帽频敧。", "并宝马，何妨归路，月挂天西。"]'),
('song-ci-884','十六贤','曹勋','宋','宋词','song-ci','十六贤','[]','拱皇图，御宝历，上圣垂衣。',118,'宋词/ci.song.7000.json','["拱皇图，御宝历，上圣垂衣。", "旰食亲万机。", "海宇熙熙。", "登寿域，瑞霞彩云常捧日。", "花阴麦垅四民齐。", "宫卫仗肃，阆苑瑶池。", "台殿倚晴晖。", "当盛际。", "风俗美。", "寻胜事。", "人物总游嬉。", "太平何处，知不摇征旗摇酒旗。", "四方感格臻上瑞。", "官家闲暇宴芳菲。", "千万岁。", "嘉会明盛时。"]'),
('song-ci-885','金盏倒垂莲','曹勋','宋','宋词','song-ci','金盏倒垂莲','[]','谷雨初晴，对晓霞乍敛，暖风凝露。',112,'宋词/ci.song.7000.json','["谷雨初晴，对晓霞乍敛，暖风凝露。", "翠云低映，捧花王留住。", "满阑嫩红贵紫，道尽得、韶光分付。", "禁篽浩荡，天香巧随天步。", "群仙倚春似语。", "遮丽日、更著轻罗深护。", "半开微吐，隐非烟非雾。", "正宜夜阑秉烛，况更有、姚黄娇妒。", "徘徊纵赏，任放濛濛柳絮。"]'),
('song-ci-886','庆清朝','曹勋','宋','宋词','song-ci','庆清朝','[]','绛罗萦色，茸金丽蕊，秀格压尽群芳。',117,'宋词/ci.song.7000.json','["绛罗萦色，茸金丽蕊，秀格压尽群芳。", "人间第一娇妩，深紫轻黄。", "乍过夜来谷雨，盈盈明艳惹天香。", "春风暖，宝幄竞倚，名称花王。", "朝槛五云拥秀，护晓日、偏宜翠幕高张。", "秾姿露叶，临赏须趁韶光。", "最喜鉴鸾初试，数枝姚魏插宫妆。", "然绛蜡，共花拚醉，莫靳瑶觞。"]'),
('song-ci-887','花心动','曹勋','宋','宋词','song-ci','花心动','[]','密幄阴阴，正嘉花嘉木，尽成新翠。',123,'宋词/ci.song.7000.json','["密幄阴阴，正嘉花嘉木，尽成新翠。", "蕙圃过雨，牡丹初歇，怎见浅深相倚。", "好称花王侍。", "秀层台、重楼明丽。", "九重晓，狂香浩态，暖风轻细。", "堪想诗人赠意。", "喜芳艳卿云，嫩苞金蕊。", "要看秀色，收拾韶华，自做殿春天气。", "与持青梅酒，趁凝伫、晚妆相对。", "且频醉，芳菲向阑可惜。"]'),
('song-ci-888','花心动','曹勋','宋','宋词','song-ci','花心动','[]','玉井生寒，正枫落吴江，冷侵罗幕。',121,'宋词/ci.song.7000.json','["玉井生寒，正枫落吴江，冷侵罗幕。", "翠云翦叶，紫锦攒花，暗香遍熏珠阁。", "瑞非兰麝比，氤氲清彻寥廓。", "向燕寝，团团秀色，巧宜围却。", "宝槛浓开对列，蜂共蝶多情，未知花萼。", "爱玩置向窗几，时时更碾，建春浇著。", "最是关情处，惊梦回、酒醒初觉。", "楚梅早，前村任他暗落。"]'),
('song-ci-889','杏花天慢','曹勋','宋','宋词','song-ci','杏花天慢','[]','桃蕊初谢，双燕来后，枝上嫩苞时节。',127,'宋词/ci.song.7000.json','["桃蕊初谢，双燕来后，枝上嫩苞时节。", "绛萼滋浩露，照晓景、裁翦冰绡标格。", "烟传靓质。", "似淡拂、妆成香颊。", "看暖日、催吐繁英，占断上林风月。", "坛边曾见数枝，算应是真仙，故留春色。", "顿觉偏造化，且任他、桃李成蹊谁说。", "晴霁易雪。", "待对饮、清赏无歇。", "更爱惜、留引鹇禽，未须再折。"]'),
('song-ci-890','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','禁烟过也，正东风浓拂，来禽奇绝。',120,'宋词/ci.song.7000.json','["禁烟过也，正东风浓拂，来禽奇绝。", "翠叶修条千万点，轻染微红香雪。", "霁景烘云，暖梢吹绽，浩荡春容阔。", "棠阴已静，此花标韵终别。", "犹记宝帖开缄，如何春李，与佳名齐列。", "秀实甘芳莫待看，叶底匀圆堪折。", "且赏琼苞，繁英插鬓，淡伫留风月。", "宜将图画，有时凝想重阅。"]'),
('song-ci-891','风流子','曹勋','宋','宋词','song-ci','风流子','[]','中春膏雨歇，雕阑晓，最好海棠时。',135,'宋词/ci.song.7000.json','["中春膏雨歇，雕阑晓，最好海棠时。", "正新梢吐绿，万苞凝露，暖铺云锦，香点胭脂。", "向枝上，绪风开秀色，桃李尽成蹊。", "朱唇晕酒，脸红微透，翠纱轻卷，红映丰肌。", "严宸风光主，临赏处，玉殿丽日迟迟。", "天与造化西蜀，浓艳芳菲。", "待绣帘卷起，欢奉长乐，内梱多闲，同宴椒闱。", "须是对花满酌，不醉无归。"]'),
('song-ci-892','蜀溪春','曹勋','宋','宋词','song-ci','蜀溪春','[]','蜀景风迟，浣花溪边，谁种芬芳。',123,'宋词/ci.song.7000.json','["蜀景风迟，浣花溪边，谁种芬芳。", "天与蔷薇，露华匀脸，繁蕊竞拂娇黄。", "枝上标韵别，浑不染、铅粉红妆。", "念杜陵、曾见时，也为赋篇章。", "如今盛开禁掖，千万朵莺羽，先借朝阳。", "待得君王，看花明艳，都道赭袍同光。", "须趁排宴席，偏宜带、疏雨笼香。", "占上苑，留住春，奉玉觞。"]'),
('song-ci-893','倚阑人','曹勋','宋','宋词','song-ci','倚阑人','[]','清明池馆，芳菲渐晚，晴香满架笼永昼。',136,'宋词/ci.song.7000.json','["清明池馆，芳菲渐晚，晴香满架笼永昼。", "翠拥柔条，玉铺繁蕊，袅袅舞低襟袖。", "秀蓓凝浩露，疑挂六铢衣绉。", "檀点芳心，体薰清馥，粉容宜拈春风手。", "肯与芝兰共嗅。", "向夜阑凝月，洞户花、别是素芳依旧。", "翦取长梢，青蛟喷雪，挽住晓云争秀。", "楼上人未去，常恐风欺雨瘦。", "红绡收取，举觞犹喜，窨得醺醺酒。"]'),
('song-ci-894','夹竹桃花','曹勋','宋','宋词','song-ci','夹竹桃花','[]','绛彩娇春，苍筠静锁，掩映夭姿凝露。',122,'宋词/ci.song.7000.json','["绛彩娇春，苍筠静锁，掩映夭姿凝露。", "花腮藏翠，高节穿花遮护。", "重重蕊叶相怜，似青帔艳妆神仙侣。", "正武陵溪暗，淇园晓色，宜望中烟雨。", "向暖景、谁见斜枝处。", "喜上苑韶华渐布。", "又似瑞霞低拥，却恐随风飞去。", "要留最妍丽，须且闲凭佳句。", "更秀容、分付徐熙，素屏画图取。"]'),
('song-ci-895','峭寒轻','曹勋','宋','宋词','song-ci','峭寒轻','[]','照溪流清浅，正万梅都开，峭寒天气。',128,'宋词/ci.song.7000.json','["照溪流清浅，正万梅都开，峭寒天气。", "才过了元宵，渐昼长禁宇，迤逦佳时。", "断肠枝上雪，残英已、片影初飞。", "苒苒随风，送春到、便烂漫香迟。", "凝睇。", "迎芳菲至。", "觉欣欣桃李，嫩色依微。", "应是有新酸，向嫩梢定须，一点藏枝。", "乍晴还又冷，从尊前、自落轻细。", "寄与高楼，夜笛声、且缓吹。"]'),
('song-ci-896','竹马子・竹马儿','曹勋','宋','宋词','song-ci','竹马子・竹马儿','[]','喜韶景才回，章台向晓，官柳舒香缕。',128,'宋词/ci.song.7000.json','["喜韶景才回，章台向晓，官柳舒香缕。", "正和烟带雨，遮桃映杏，东君先与。", "乍引柔条萦路。", "娇黄照水，经渭城朝雨。", "翠惹丝垂，玉阑干风静，轻轻搭住。", "到此曾追想，陶潜旧隐，忆隋堤津渡。", "三眠昼永凝露。", "更许黄鹂娇语。", "似怕日暖，飞花成絮，拟雪堆绣户。", "待放教婆娑，如眉处、笼歌舞。"]'),
('song-ci-897','二色莲','曹勋','宋','宋词','song-ci','二色莲','[]','凤沼湛碧，莲影明洁，清泛波面。',116,'宋词/ci.song.7000.json','["凤沼湛碧，莲影明洁，清泛波面。", "素肌鉴玉，烟脸晕红深浅。", "占得薰风弄色，照醉眼、梅妆相间。", "堤上柳垂轻帐，飞尘尽教遮断。", "重重翠荷净，列向横塘暖。", "争映芳草岸。", "画船未桨，清晓最宜遥看。", "似约鸳鸯并侣，又更与、舂锄为伴。", "频宴赏，香成阵、瑶池任晚。"]'),
('song-ci-898','八音谐','曹勋','宋','宋词','song-ci','八音谐','[]','芳景到横塘，官柳阴低覆，新过疏雨。',122,'宋词/ci.song.7000.json','["芳景到横塘，官柳阴低覆，新过疏雨。", "望处藕花密，映烟汀沙渚。", "波静翠展琉璃，似伫立、飘飘川上女。", "弄晓色，正鲜妆照影，幽香潜度。", "水阁薰风对万姝，共泛泛红绿，闹花深处。", "移棹采初开，嗅金缨留取。", "趁时凝赏池边，预后约、淡云低护。", "未饮且凭阑，更待满、荷珠露。"]'),
('song-ci-899','清风满桂楼','曹勋','宋','宋词','song-ci','清风满桂楼','[]','凉飙霁雨。',124,'宋词/ci.song.7000.json','["凉飙霁雨。", "万叶吟秋，团团翠深红聚。", "芳桂月中来，应是染、仙禽顶砂匀注。", "晴光助绛色，更都润、丹霄风露。", "连朝看、枝间粟粟，巧裁霞缕。", "烟姿照琼宇。", "上苑移时，根连海山佳处。", "回看碧岩边，薇露过，残黄韵低尘污。", "诗人谩自许。", "道曾向、蟾宫折取。", "斜枝戴，惟称瑶池伴侣。"]'),
('song-ci-900','雁侵云慢','曹勋','宋','宋词','song-ci','雁侵云慢','[]','晓云低。',117,'宋词/ci.song.7000.json','["晓云低。", "是残暑渐消，凉意初至。", "翠帘燕去，觉商飙天气。", "凝华吹、动绣额，乍殿阁、金茎风细。", "夜雨笼微阴，满绮窗、疏影响清吹。", "轻飔嫩细透衣。", "想宵长漏迟，香动罗袂。", "戏曾计日，忆宾鸿来期。", "杯盘排备宴适，乍好景、心情先喜。", "待淡月疏烟里，试寻岩桂蕊。"]'),
('song-ci-901','锦标归','曹勋','宋','宋词','song-ci','锦标归','[]','风搅长空，冷入寒云，正是严凝初至。',132,'宋词/ci.song.7000.json','["风搅长空，冷入寒云，正是严凝初至。", "围炉坐久，珠帘卷起，准拟六花飞砌。", "渐苒苒晴烟，更暗觉、远天开霁。", "阻琼瑶、不舞蓝田，但有蟾华铺地。", "想像如今剡溪，应误幽人访客，轻舟闲舣。", "翠幕登临处，散无限清兴，顿孤沈醉。", "念好景佳时，谩望极、祥霙为瑞。", "却梅花、知我心情，故把飞英飘坠。"]'),
('song-ci-902','索酒','曹勋','宋','宋词','song-ci','索酒','[]','乍喜惠风初到，上林翠红，竞开时候。',125,'宋词/ci.song.7000.json','["乍喜惠风初到，上林翠红，竞开时候。", "四吹花香扑鼻，露裁烟染，天地如绣。", "渐觉南薰，总冰绡纱扇避烦昼。", "共游凉亭消暑，细酌轻讴须酒。", "江枫装锦雁横秋，正皓月莹空，翠阑侵斗。", "况素商霜晓，对径菊、金玉芙蓉争秀。", "万里彤云，散飞霙，炉中焰红兽。", "便须点水傍边，最宜著酉。"]'),
('song-ci-903','凤箫吟・芳草','曹勋','宋','宋词','song-ci','凤箫吟・芳草','[]','列旗常。',125,'宋词/ci.song.7000.json','["列旗常。", "中宵天净，郊丘展采圆苍。", "肇禋三岁礼，圣天子为民，致福穰穰。", "凝旒亲奠玉，粲珠联、星斗垂芒。", "渐月转燔柴，露重烟断坛旁。", "欢康。", "青霞催晓，六乐均调，响逐新阳。", "辇回天仗肃，庆千官抃舞，绣锦成行。", "鸡竿双凤阙，肆颁宣、恩动荣光。", "赞永御，萝图霈泽，常抚殊方。"]'),
('song-ci-904','六花飞','曹勋','宋','宋词','song-ci','六花飞','[]','寅杓乍正，瑞云开晓，罩紫府宫殿。',116,'宋词/ci.song.7000.json','["寅杓乍正，瑞云开晓，罩紫府宫殿。", "圣孝虔恭，率宸庭冠剑。", "上徽称、天明地察，奉玉检、璇耀金辉，仰吾君，亲被衮龙，当槛俯旒冕。", "中兴明天子，舜心温凊，示未尝闲燕。", "礼无前比，出渊衷深念。", "赞木父金母至乐，万亿载、日月荣光俱欢忭。", "罗绮管弦开寿宴。"]'),
('song-ci-905','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','禁篽芙蓉秋气凉。',48,'宋词/ci.song.7000.json','["禁篽芙蓉秋气凉。", "新枨启待满林霜。", "旨甘初荐摘青黄。", "乍剖金肤藏嫩玉，吴盐兼味发清香。", "圣心此意与天长。"]'),
('song-ci-906','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','春到皇居景晏温。',48,'宋词/ci.song.7000.json','["春到皇居景晏温。", "冰轮驾玉上祥云。", "烛龙衔耀九重门。", "宫掖两仪临舜殿，金莲万斛奉尧尊。", "官家慈孝格乾坤。"]'),
('song-ci-907','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','初过西风烟雨微。',48,'宋词/ci.song.7000.json','["初过西风烟雨微。", "霓光留景正团枝。", "月中新彩与增辉。", "霞影分丹乘浩露，珊瑚秀色满彤墀。", "凉飙吹上赭红衣。"]'),
('song-ci-908','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','春晓于飞彩仗明。',48,'宋词/ci.song.7000.json','["春晓于飞彩仗明。", "西园嘉瑞格和鸣。", "花王特地献双英。", "并蒂轻黄宜淡淡，联芳竞秀巧盈盈。", "飞琼萼绿两倾城。"]'),
('song-ci-909','临江仙','曹勋','宋','宋词','song-ci','临江仙','[]','连夜阴云开晓景，中秋胜事偏饶。',70,'宋词/ci.song.7000.json','["连夜阴云开晓景，中秋胜事偏饶。", "十分晴莹碧天高。", "台升吴岫顶，乐振海门潮。", "桂影一庭香渐远，四并都向今朝。", "宸欢得句付风骚。", "围棋消白日，赏月度清宵。"]'),
('song-ci-910','临江仙','曹勋','宋','宋词','song-ci','临江仙','[]','嫩绿阴阴台榭映，南风初送清微。',70,'宋词/ci.song.7000.json','["嫩绿阴阴台榭映，南风初送清微。", "扬州花市进芳菲。", "丝头开万朵，玉叶衬繁枝。", "自是诗人佳赠意，花王香借馀姿。", "翠红深展奉瑶卮。", "何妨沈醉赏，天与绊春晖。"]'),
('song-ci-911','西江月','曹勋','宋','宋词','song-ci','西江月','[]','霞绮浓披翡翠，晨光巧上珊蝴。',58,'宋词/ci.song.7000.json','["霞绮浓披翡翠，晨光巧上珊蝴。", "丹林偏许下清都。", "香占深岩烟雨。", "秋到九华宫殿，赭袍红借繁珠。", "广寒桂与世花殊。", "不带人间风露。"]'),
('song-ci-912','西江月','曹勋','宋','宋词','song-ci','西江月','[]','连夜六花飞舞，清晨玉境瑶阶。',58,'宋词/ci.song.7000.json','["连夜六花飞舞，清晨玉境瑶阶。", "湖山寒雾隐楼台。", "难画西园真态。", "月殿九华同到，雕舆乘兴俱来。", "浮春帘密锦筵开。", "不是山阴访戴。"]'),
('song-ci-913','诉衷情','曹勋','宋','宋词','song-ci','诉衷情','[]','西都花市锦云同。',54,'宋词/ci.song.7000.json','["西都花市锦云同。", "谷雨贡黄封。", "天心故偏雨露，名品满深宫。", "开国艳，正春融。", "露香中。", "绮罗金殿，醉赏浓春，贵紫娇红。"]'),
('song-ci-914','武陵春','曹勋','宋','宋词','song-ci','武陵春','[]','元夕晴和中禁好，梅影玉阑干。',56,'宋词/ci.song.7000.json','["元夕晴和中禁好，梅影玉阑干。", "峭窄春衫试嫩寒。", "金翠会群仙。", "移下一天星斗璨，喜色动宸颜。", "行乐风光莫放闲。", "月在凤凰山。"]'),
('song-ci-915','四槛花','曹勋','宋','宋词','song-ci','四槛花','[]','鸳瓦霜浓，兽炉烟冷，琐窗渐明。',121,'宋词/ci.song.7000.json','["鸳瓦霜浓，兽炉烟冷，琐窗渐明。", "芙蓉红晕减，疏篁晓风清。", "睡觉犹眠，怯新寒，仍宿酒，尚有馀酲。", "拥闲衾。", "先记早梅糁糁，流水泠泠。", "须记岁月堪惊。", "最难管、苍华满镜生。", "心地常自乐，谁能问枯荣。", "一味情尘、揩摩尽，人间世，更没亏成。", "惟萧散，眠食外，且乐升平。"]'),
('song-ci-916','花心动','曹勋','宋','宋词','song-ci','花心动','[]','绿结阴浓，渐南风初到、旧家庭院。',127,'宋词/ci.song.7000.json','["绿结阴浓，渐南风初到、旧家庭院。", "细麦落花，圆荷浮叶，翠径受风新燕。", "乍晴还雨香罗怯，惜柳絮、已将春远。", "最好处，清和气暖，喜拈轻扇。", "好对层轩邃馆。", "供极目晴云，晓江横练。", "煮酒试尝，梅子团青，草草也休辞劝。", "待等闲暇寻胜去，又闲事、有时萦绊。", "且趁取良辰，醉后莫管。"]'),
('song-ci-917','胜胜令','曹勋','宋','宋词','song-ci','胜胜令','[]','梅风吹粉，柳影摇金。',83,'宋词/ci.song.7000.json','["梅风吹粉，柳影摇金。", "渐看春意入芳林。", "波明草嫩，据征鞍，晚烟沈。", "向野馆、愁绪怎禁。", "过了烧灯，醉别院，阻同寻。", "琐窗还是冷瑶琴。", "灯花灺也，拥春寒，掩闲衾。", "念翠屏、应倚夜深。"]'),
('song-ci-918','玉蹀躞・解蹀躞','曹勋','宋','宋词','song-ci','玉蹀躞・解蹀躞','[]','红绿烟村惨淡，市井初经虏。',90,'宋词/ci.song.7000.json','["红绿烟村惨淡，市井初经虏。", "舍馆人家，凄凄但尘土。", "依旧春色撩人，柳花飞处，犹听几声莺语。", "黯无绪。", "匹马三游四楚。", "行路漫怀古。", "可惜风月，佳时尚羁旅。", "归处应及荼䕷，与插云鬓，此恨醉时分付。"]'),
('song-ci-919','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','海榴红暖。',127,'宋词/ci.song.7000.json','["海榴红暖。", "圆荷翠小，榭阁薰风浅。", "真人抚运，云龙相际，真贤载诞。", "鲁国元勋，相门接踵，传家非远。", "辅中兴大业，折冲邻壤，扶红日、上霄汉。", "端是清明重见。", "范陶熔、咸收群彦。", "垂绅正笏，炉烟不动，宸廷闲燕。", "天地平成，父尧子舜，永膺宸眷。", "赐我公岁岁，恩荣锡命，向黄金殿。"]'),
('song-ci-920','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','晓云阁雨。',126,'宋词/ci.song.7000.json','["晓云阁雨。", "疏梅缀玉，麈尾闻谈吐。", "精忠许国，才华摛锦，尘劳释去。", "六印雄图，百川明辩，苏张谁数。", "有奇谋欲下，阴山族帐，惟英卫、可接武。", "想见临戎丰度。", "慨然定、中原疆土。", "果惊一坐，折冲遐裔，嘉言循古。", "安抚疲民，静摧骄虏，无烦旗鼓。", "看功成、入辅中兴，永佐乾坤主。"]'),
('song-ci-921','宴清都','曹勋','宋','宋词','song-ci','宴清都','[]','野水澄空，远山随眼，笋舆乘兴庐阜。',126,'宋词/ci.song.7000.json','["野水澄空，远山随眼，笋舆乘兴庐阜。", "天池最极，云溪最隐，翠迷归路。", "三峡两龙翔翥。", "尽半月、犹贪杖屦。", "闲引杯，相赏好处奇处，险处清处。", "凝伫。", "道友重陪，西山胜迹，玉隆风御。", "滕阁下临，晴峰万里，水云千古。", "飞觞且同豪举。", "喜醉客、龙吟度曲。", "待记成佳话，归时从头细数。"]'),
('song-ci-922','江神子・江城子','曹勋','宋','宋词','song-ci','江神子・江城子','[]','帝俞赓载下方壶。',86,'宋词/ci.song.7000.json','["帝俞赓载下方壶。", "雨随车。", "旷时无。", "尽道南丰，仙骨秀而都。", "光照丹丘人快睹，金騕袅，玉蟾蜍。", "自怜老景病仍癯。", "芘微躯。", "驻安舆。", "暗润赤城，风露喜踟蹰。", "行矣相门还入相，看惠爱，咏猗欤。"]'),
('song-ci-923','满庭芳','曹勋','宋','宋词','song-ci','满庭芳','[]','白氎行缠，青巾包结，几年且混常流。',118,'宋词/ci.song.7000.json','["白氎行缠，青巾包结，几年且混常流。", "寰中谁见，心地自清幽。", "雨散昆仑顶上，香润遍、琼圃无忧。", "灵芽长，如今寒暑，饥渴总何愁。", "诸公，须著力，尘缘扫尽，师旨坚求。", "看天边、飞金走玉难留。", "住个庵儿不大，争恋得、月馆青楼。", "台山里，从人一任，说个好苏州。"]'),
('song-ci-924','满庭芳','曹勋','宋','宋词','song-ci','满庭芳','[]','玉景明心，木鸡修性，要须和会三家。',118,'宋词/ci.song.7000.json','["玉景明心，木鸡修性，要须和会三家。", "未知头面，何处认摩耶。", "自有身中异境，藏巨浪、一点笼纱。", "升沈际，难将赋得，有限逐无涯。", "时时，须点检，随缘遣性，何更兴嗟。", "那浩然独得，迥绝痕瑕。", "妙占熙风惠日，乘正气、三缕明霞。", "真机运，连环放下，无处不光华。"]'),
('song-ci-925','满庭芳','曹勋','宋','宋词','song-ci','满庭芳','[]','风搅长空，霜飞平野，冷云常带遥山。',118,'宋词/ci.song.7000.json','["风搅长空，霜飞平野，冷云常带遥山。", "乱鸦声断，烟霭有无间。", "气与寒威共凛，深绣户、帘幕重关。", "梅枝亚，纤纤秀色，疏影小阑干。", "相携，同好景，窥檐望雪，呵手低鬟。", "笑语里、都言雪意非悭。", "有个红炉暖处，围兽炭、不管宵残。", "从教醉，添香倚玉，门外任清寒。"]'),
('song-ci-926','选冠子','曹勋','宋','宋词','song-ci','选冠子','[]','细柳排空，高榆拥岸，乍觉楚天秋意。',136,'宋词/ci.song.7000.json','["细柳排空，高榆拥岸，乍觉楚天秋意。", "凉随夜雨，望极长淮，孤馆漫成留滞。", "天净无云，浪痕清影，窗户闲临烟水。", "叹驱驰尘事，殊喜萧散，暂来闲适。", "常思念、圣主垂衣，临朝北顾，泛遣聊宽忧寄。", "輶轩载揽，虎节严持，谈笑挂帆千里。", "凭仗皇威，滥陪枢管，一语折冲遐裔。", "待归来，瞻对龙颜，须知有喜。"]'),
('song-ci-927','选冠子','曹勋','宋','宋词','song-ci','选冠子','[]','秀木撑空，凝云藏岫，处处群山横翠。',137,'宋词/ci.song.7000.json','["秀木撑空，凝云藏岫，处处群山横翠。", "霜风冽面，酒力潜消，征辔暂指天际。", "红叶黄花，水光山色，常爱晓云晴霁。", "念尘埃眯眼，年华易老，觉远行非易。", "常自感、羽客难寻，蓬莱难到，强作林泉活计。", "鱼依密藻，雁过烟空，家信渐遥千里。", "还是关河冷落，斜阳衰草，苇村山驿。", "又鸡声茅店，鸦啼露井重唤起。"]'),
('song-ci-928','定风波','曹勋','宋','宋词','song-ci','定风波','[]','雪后篱边冷未晴。',73,'宋词/ci.song.7000.json','["雪后篱边冷未晴。", "江天浓淡暗还明。", "断续流香传玉蓓。", "心醉。", "临风嗅蕊不胜清。", "映竹幽姿深有思。", "何似。", "照溪真色更多情。", "待得微酸藏傅粉。", "黄嫩。", "湿云潜放雨轻轻。"]'),
('song-ci-929','祝英台・祝英台近','曹勋','宋','宋词','song-ci','祝英台・祝英台近','[]','晚寒浓，残雪重，春意在何许。',95,'宋词/ci.song.7000.json','["晚寒浓，残雪重，春意在何许。", "萼绿仙姿，海上未飞去。", "粲粲玉立丰标，天寒日暮，笑东风、不曾轻付。", "几凝伫。", "闲为写出横斜，无声断肠句。", "常对幽情，何事更重赋。", "待约他日貂裘，玉溪清夜，喷龙吟、月明徐步。"]'),
('song-ci-930','二郎神','曹勋','宋','宋词','song-ci','二郎神','[]','半阴未雨。',127,'宋词/ci.song.7000.json','["半阴未雨。", "霁晓寒、轻烟薄暮。", "乍过了挑青，名园深院，把酒偏宜细步。", "满槛梅花，绕堤溪柳，径暖迁莺相语。", "春澹澹，渐觉清明，相傍小桃才吐。", "凝伫。", "山村水馆，难堪羁旅。", "甚觑著花开，频惊屈指，谩写奚奴丽句。", "幸有家山，青鸾应报，为我整齐歌舞。", "一任待，醉倚群红，花沾酒污。"]'),
('song-ci-931','满路花・促拍满路花','曹勋','宋','宋词','song-ci','满路花・促拍满路花','[]','清都山水客，何事入临安。',106,'宋词/ci.song.7000.json','["清都山水客，何事入临安。", "珍祠天赐与，半生闲。", "曲池人静，水击赤乌蟠。", "飞上烟岚顶，三缕明霞照晚，时对胎仙。", "圃中有个小庭轩。", "才到便绦然。", "坐来闲看了，篆香残。", "道人活计，休道出尘难。", "归去后、安排著，一緉麻鞋，定期踏遍名山。"]'),
('song-ci-932','木兰花慢','曹勋','宋','宋词','song-ci','木兰花慢','[]','断虹收霁雨，卷帘幕、与风期。',126,'宋词/ci.song.7000.json','["断虹收霁雨，卷帘幕、与风期。", "正燕子将雏，莺儿弄巧，日影迟迟。", "荼䕷。", "牡丹过也，但游丝、上下网晴晖。", "三月韶华，转头易失，密阴匀齐。", "常思。", "入夏景偏奇。", "是梅雨霏微。", "更乍著轻纱，凉摇素羽，翠点清池。", "还思。", "故山旧隐，想葱茏、翠竹锁窗扉。", "独倚西楼谩久，此怀冷淡谁知。"]'),
('song-ci-933','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','公家世德，建凌烟勋业，中兴长策。',121,'宋词/ci.song.7000.json','["公家世德，建凌烟勋业，中兴长策。", "三十年来，皆帝扆殊选，金瓯名迹。", "眷倚江南，澄清一道，遴柬惟公得。", "西清严秘，龙头高动奎壁。", "深殿衣惹天香，皇华原野，接萧萧秋色。", "六管均输行奏课，唐室家声皆识。", "老我相逢，萍蓬飘转，晚景俱头白。", "西山南浦，溯风衰泪横臆。"]'),
('song-ci-934','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','瑑冰铸雪，赋神情天壤，无伦香泽。',121,'宋词/ci.song.7000.json','["瑑冰铸雪，赋神情天壤，无伦香泽。", "月女霜娥，直是有如许，清明姿色。", "细玉钗梁，温琼环佩，语好新音发。", "相逢一笑，桂宫连夜寒彻。", "应是第一瑶台，水晶宫殿里，飞升仙列。", "小谪尘寰缘契合，同饮银浆凝结。", "醉里归来，魂清骨醒，乍向层城别。", "晓风吹袂，冷香犹带残月。"]'),
('song-ci-935','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','五门照日，是真人膺箓，炎图家国。',121,'宋词/ci.song.7000.json','["五门照日，是真人膺箓，炎图家国。", "二百年来，抚四海安乐，六服承德。", "虎旅横江，胡尘眯眼，恨有中原隔。", "宫城缺处，望来消尽金碧。", "征辔暂款神州，期宽北顾，且驰驱朝夕。", "皓彩流天宁忍见，双阙笼秋月色。", "欲饮无憀，还成长叹，清泪空横臆。", "请缨无路，异时林下犹忆。"]'),
('song-ci-936','沁园春','曹勋','宋','宋词','song-ci','沁园春','[]','春点烟红，露晞新绿，土膏渐香。',140,'宋词/ci.song.7000.json','["春点烟红，露晞新绿，土膏渐香。", "散懒慵情性，寻幽选静，一筇烟雨，几处松篁。", "恨我求闲，已成迟暮，石浅泉甘难屡尝。", "犹堪去，向清风皓月，南涧东冈。", "如今雁断三湘。", "念酒伴、不来梅自芳。", "幸隐居药馆，孙登啸咏，从容云水，无负年光。", "且共山间，琴书朋旧，时饮无何游醉乡。", "归常是，趁前村桑柘，犹挂残阳。"]'),
('song-ci-937','沁园春','曹勋','宋','宋词','song-ci','沁园春','["\u5e90\u5c71"]','五老横峰，二林云衲，自古洞天。',140,'宋词/ci.song.7000.json','["五老横峰，二林云衲，自古洞天。", "喷玉龙飞，下三峡水，望香炉暗霭，如起非烟。", "有个真人，拨云峰下，宴坐修真不记年。", "明亭诏，看龙翔凤翥，宸制奎篇。", "君臣际会诚难。", "耸翠阁、频颁宝墨鲜。", "众妙门皆向，微言显启，两朝天德，甘涌神泉。", "道化承平，应稽升举，且向人间寻有缘。", "掀髯笑，做庐山隐逸，大宋神仙。"]'),
('song-ci-938','青玉案','曹勋','宋','宋词','song-ci','青玉案','[]','东风冉冉迟芳昼。',82,'宋词/ci.song.7000.json','["东风冉冉迟芳昼。", "渐黄缀、疏疏柳。", "为惜春来通安否。", "可能相就，径须图醉，莫问伤春瘦。", "陶然共酌新醅酒。", "咏好句、须还凤楼手。", "唱了新词归来后。", "琐窗香暗，语声和笑，喜入灯花秀。"]'),
('song-ci-939','青玉案','曹勋','宋','宋词','song-ci','青玉案','[]','尘埃踏遍长安道。',82,'宋词/ci.song.7000.json','["尘埃踏遍长安道。", "念云水、归来好。", "趁得梅花先春到。", "冷云疏雨，暗香寒艳，万玉明清晓。", "青鞋黄帽从渠笑。", "粲十里、冰姿步时绕。", "正怕和风都过了。", "已输高士，锦囊翻句，醉后先倾倒。"]'),
('song-ci-940','虞美人','曹勋','宋','宋词','song-ci','虞美人','[]','风流贺监栽培好。',66,'宋词/ci.song.7000.json','["风流贺监栽培好。", "梅最妍姿巧。", "娟娟占得入时妆。", "秀影横斜香并、彩鸳鸯。", "汉皋解佩当时遇。", "绿满经行处。", "如今清梦已惊残。", "赖向君家窗户、得重看。"]'),
('song-ci-941','虞美人','曹勋','宋','宋词','song-ci','虞美人','[]','芙蓉露下闲庭晚。',66,'宋词/ci.song.7000.json','["芙蓉露下闲庭晚。", "犹觉秋容浅。", "惊心莫道岁华赊。", "已有官梅轻放、小春花。", "西风河汉溪流月。", "月下疏疏雪。", "新妆喜是寿阳人。", "鸾鉴不劳呵手、对寒云。"]'),
('song-ci-942','阮郎归','曹勋','宋','宋词','song-ci','阮郎归','[]','谁将春信到长安。',56,'宋词/ci.song.7000.json','["谁将春信到长安。", "江南腊向残。", "玉妃何事在人间。", "冰肌莹素颜。", "新月上，怯轻寒。", "香心破紫檀。", "数枝斜傍小亭闲。", "黄昏人倚阑。"]'),
('song-ci-943','阮郎归','曹勋','宋','宋词','song-ci','阮郎归','[]','玉宸赐得水云身。',56,'宋词/ci.song.7000.json','["玉宸赐得水云身。", "初欣不佩绅。", "烟霞一任著衣巾。", "朝中散袒人。", "湖水静，了无尘。", "语兼天上春。", "道人相见肯情亲。", "银钩墨尚新。"]'),
('song-ci-944','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','乱山影直危楼起。',52,'宋词/ci.song.7000.json','["乱山影直危楼起。", "天涯目断雕阑倚。", "寂寞过东风。", "行宫烟雨中。", "长安何处日。", "城郭今寒食。", "谁待翠华归。", "片云天际飞。"]'),
('song-ci-945','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','天台不是登长道。',52,'宋词/ci.song.7000.json','["天台不是登长道。", "浑如弱水烟波渺。", "楼上指归程。", "春风无限情。", "石桥书不到。", "雁阵横空杳。", "愁绪比遥峰。", "依依千万重。"]'),
('song-ci-946','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','琴堂窗户清无暑。',52,'宋词/ci.song.7000.json','["琴堂窗户清无暑。", "宫妆争捧黄金注。", "劝我醉秋风。", "难辞两脸红。", "别来三堕叶。", "同是修门客。", "十载叹萍蓬。", "方欣一笑同。"]'),
('song-ci-947','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','去年春破。',54,'宋词/ci.song.7000.json','["去年春破。", "强半途中过。", "日日篷窗眠了坐。", "饱听吴音楚些。", "今年犹在天涯。", "客情触处思家。", "柳密何人深院，竹疏特地桃花。"]'),
('song-ci-948','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','风休雨罢。',54,'宋词/ci.song.7000.json','["风休雨罢。", "三五春寒夜。", "翠额重帘何妨下。", "一炷非兰非麝。", "红莲开遍吴宫。", "华灯小试房栊。", "客里愁须强遣，从来我辈情锺。"]'),
('song-ci-949','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','春前别后。',54,'宋词/ci.song.7000.json','["春前别后。", "常是双眉皱。", "生怕莺声催残漏。", "梦破闲衾堆绣。", "又还玉露金风。", "秋声先到房栊。", "川上不传尺素，云间犹望飞鸿。"]'),
('song-ci-950','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','秋雨弥空，冷侵窗户琴书润。',50,'宋词/ci.song.7000.json','["秋雨弥空，冷侵窗户琴书润。", "四檐成韵。", "孤坐无人问。", "壮志消沈，喜入清闲运。", "常安分。", "炷烟飘尽。", "更拨馀香烬。"]'),
('song-ci-951','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','惨惨春阴，画桡寒漾梅风去。',50,'宋词/ci.song.7000.json','["惨惨春阴，画桡寒漾梅风去。", "冷风吹度。", "愁入淮山路。", "歌扇归期，只恐春城暮。", "人何处。", "柳汀烟渚。", "听尽篷窗雨。"]'),
('song-ci-952','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','晓日浓阴，冷云遮断山无数。',50,'宋词/ci.song.7000.json','["晓日浓阴，冷云遮断山无数。", "雁飞筝柱。", "都向愁边去。", "帘影沈沈，一缕芳香度。", "深庭户。", "且寻欢聚。", "雪意还成雨。"]'),
('song-ci-953','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','昏旦交时，个中已有甘香味。',50,'宋词/ci.song.7000.json','["昏旦交时，个中已有甘香味。", "咽同真液。", "便觉温温地。", "八一高蟠，光动重楼外。", "但留意。", "自然和气。", "香满昆仑水。"]'),
('song-ci-954','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','翠袖携持婉有情。',48,'宋词/ci.song.7000.json','["翠袖携持婉有情。", "湘筠犀轴巧装成。", "声随一苇更分明。", "倚竹双丝明玉细，低眉数曲语莺轻。", "转移新韵几多声。"]'),
('song-ci-955','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','玉柱檀槽立锦筵。',48,'宋词/ci.song.7000.json','["玉柱檀槽立锦筵。", "低眉信手曲初传。", "凤凰飞上四条弦。", "杨柳已吹三叠韵，何须人在九江船。", "夜凉人与月婵娟。"]'),
('song-ci-956','酒泉子','曹勋','宋','宋词','song-ci','酒泉子','[]','霜护云低，竹外斜枝初璀璨，仙风吹堕玉钿新。',53,'宋词/ci.song.7000.json','["霜护云低，竹外斜枝初璀璨，仙风吹堕玉钿新。", "度清芬。", "叹寒冰艳了无尘。", "不占纷纷桃李径，一庭疏影冷摇春。", "月黄昏。"]'),
('song-ci-957','酒泉子','曹勋','宋','宋词','song-ci','酒泉子','[]','爱景催暄。',53,'宋词/ci.song.7000.json','["爱景催暄。", "初向晴梢舒玉点，修筠霭霭隔婵娟。", "更清妍。", "东风欲到冷霜天。", "常记孤山残雪路，一枝流水小桥边。", "卧疏烟。"]'),
('song-ci-958','酒泉子','曹勋','宋','宋词','song-ci','酒泉子','[]','惨惨西风。',53,'宋词/ci.song.7000.json','["惨惨西风。", "人与两州俱不见，一江残照落霞红。", "橹声中。", "汀花苹草六朝空。", "人向赏心增远恨，闲云犹绕建康宫。", "古今同。"]'),
('song-ci-959','酒泉子','曹勋','宋','宋词','song-ci','酒泉子','[]','帘幕闲垂。',53,'宋词/ci.song.7000.json','["帘幕闲垂。", "密密围毡红兽暖，有人陌上冷征衣。", "未成归。", "檐间鹊语卜归期。", "应是疑人犹驻马，琐窗日影又还西。", "翠眉低。"]'),
('song-ci-960','朝中措','曹勋','宋','宋词','song-ci','朝中措','[]','一封清诏下金鸾。',57,'宋词/ci.song.7000.json','["一封清诏下金鸾。", "临遣讲邻欢。", "谁问火云挥汗，要看易水摇寒。", "何妨谈笑，平生志节，可障狂澜。", "预约黄花前后，殊庭瞻对宸颜。"]'),
('song-ci-961','朝中措','曹勋','宋','宋词','song-ci','朝中措','[]','宝筝偏劝酒杯深。',57,'宋词/ci.song.7000.json','["宝筝偏劝酒杯深。", "歌舞乍沈沈。", "秀指十三弦上，挑吟击玉锵金。", "牙台锦面，轻移雁柱，低转新音。", "妙是不须银甲，向人说尽芳心。"]'),
('song-ci-962','朝中措','曹勋','宋','宋词','song-ci','朝中措','[]','鸣珂揽辔玉霄东。',57,'宋词/ci.song.7000.json','["鸣珂揽辔玉霄东。", "持节散陈红。", "子舍已先多士，一鞭同袅春风。", "西瓯旧治，棠阴秀茂，竹马迎逢。", "正焙行驰金殿，仙班看缀夔龙。"]'),
('song-ci-963','西江月','曹勋','宋','宋词','song-ci','西江月','[]','弦泛龙香细拨，声回花底莺雏。',58,'宋词/ci.song.7000.json','["弦泛龙香细拨，声回花底莺雏。", "低眉信手巧工夫。", "犹带巫烟楚雨。", "人占东风秀色，花笼宝髻真珠。", "锦绦金凤要人扶。", "只恐乘鸾飞去。"]'),
('song-ci-964','西江月','曹勋','宋','宋词','song-ci','西江月','[]','春绣东风疑早，映檐翠箔低笼。',58,'宋词/ci.song.7000.json','["春绣东风疑早，映檐翠箔低笼。", "氤氲不是梦云空。", "叶密香翻侵冻。", "折桂广寒手段，移来点检珍丛。", "醉归满载紫云浓。", "抱膝庵中仙种。"]'),
('song-ci-965','菩萨蛮','胡铨','宋','宋词','song-ci','菩萨蛮','[]','银河牛女年年渡。',52,'宋词/ci.song.7000.json','["银河牛女年年渡。", "相逢未款还忧去。", "珠斗欲阑干。", "盈盈一水间。", "玉人偷拜月。", "苦恨匆匆别。", "此意愿天怜。", "今宵长似年。"]'),
('song-ci-966','减字木兰花','胡铨','宋','宋词','song-ci','减字木兰花','[]','渭阳佳梦。',52,'宋词/ci.song.7000.json','["渭阳佳梦。", "瓦变成璋真妙弄。", "不是勾回。", "汤饼冤家唤得来。", "不分利市。", "要我开尊真倒置。", "试问坡翁。", "此事如何著得侬。"]'),
('song-ci-967','醉落魄・一斛珠','胡铨','宋','宋词','song-ci','醉落魄・一斛珠','[]','百年强半。',67,'宋词/ci.song.7000.json','["百年强半。", "高秋犹在天南畔。", "幽怀已被黄花乱。", "更恨银蟾，故向愁人满。", "招呼诗酒颠狂伴。", "羽觞到手判无算。", "浩歌箕踞巾聊岸。", "酒欲醒时，兴在庐仝碗。"]'),
('song-ci-968','醉落魄・一斛珠','胡铨','宋','宋词','song-ci','醉落魄・一斛珠','["\u897f\u6e56"]','千岩竞秀。',67,'宋词/ci.song.7000.json','["千岩竞秀。", "西湖好是春时候。", "谁知梅雪飘零久。", "藏白收香，空袖和羹手。", "天涯万里情难逗。", "眉峰岂为伤春皱。", "片愁未信花能绣。", "若说相思，只恐天应瘦。"]'),
('song-ci-969','鹧鸪天','胡铨','宋','宋词','song-ci','鹧鸪天','[]','梦绕松江属玉飞。',64,'宋词/ci.song.7000.json','["梦绕松江属玉飞。", "秋风莼美更鲈肥。", "不因入海求诗句，万里投荒亦岂宜。", "青箬笠，绿荷衣。", "斜风细雨也须归。", "崖州险似风波海，海里风波有定时。"]'),
('song-ci-970','鹧鸪天','胡铨','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','一忆西湖太瘦生。',64,'宋词/ci.song.7000.json','["一忆西湖太瘦生。", "十年不到梦曾行。", "空濛山色烟霏晚，淡沲湖光雾縠轻。", "芳草远，暮云平。", "雨馀空翠入帘明。", "梦回一饷难存济，这错都因自打成。"]'),
('song-ci-971','朝中措','胡铨','宋','宋词','song-ci','朝中措','[]','崖州何有水连空。',57,'宋词/ci.song.7000.json','["崖州何有水连空。", "人在浪花中。", "月屿一声横竹，云帆万里雄风。", "多情太守，三千珠履，二肆歌锺。", "日下即归黄霸，海南长想文翁。"]'),
('song-ci-972','采桑子','胡铨','宋','宋词','song-ci','采桑子','[]','山浮海上青螺远，决眦归鸿。',52,'宋词/ci.song.7000.json','["山浮海上青螺远，决眦归鸿。", "闲倚东风。", "叠叠层云欲荡胸。", "弄琴细写清江引，一洗愁容。", "木杪黄封。", "贤圣都堪日日中。"]'),
('song-ci-973','临江仙','胡铨','宋','宋词','song-ci','临江仙','[]','我与梅花真莫逆，别来长恐因循。',69,'宋词/ci.song.7000.json','["我与梅花真莫逆，别来长恐因循。", "几年不见岭头春。", "栩然蝴蝶梦，魂梦竟非真。", "浪蕊浮花空满眼，愁眉不展长颦。", "此君还似不羁人。", "月边风畔，千里淡相亲。"]'),
('song-ci-974','如梦令','胡铨','宋','宋词','song-ci','如梦令','[]','谁念新州人老。',40,'宋词/ci.song.7000.json','["谁念新州人老。", "几度斜阳芳草。", "眼雨欲晴时，梅雨故来相恼。", "休恼。", "休恼。", "今岁荔枝能好。"]'),
('song-ci-975','玉楼春','胡铨','宋','宋词','song-ci','玉楼春','[]','十年目断鲸波阔。',64,'宋词/ci.song.7000.json','["十年目断鲸波阔。", "万里相逢歌怨咽。", "髻鬟春雾翠微重，眉黛秋山烟雨抹。", "小槽旋滴真珠滑。", "断送一生花十八。", "醉中扶上木肠儿，酒醒梦回空对月。"]'),
('song-ci-976','清平乐','胡铨','宋','宋词','song-ci','清平乐','[]','深深花院。',54,'宋词/ci.song.7000.json','["深深花院。", "雨虐风饕遍。", "只欠画屏并羽扇。", "谁领略春风面。", "愁须诗酒相禁。", "少陵底事慵吟。", "不是为梅牵兴，怕渠恼乱春心。"]'),
('song-ci-977','青玉案','胡铨','宋','宋词','song-ci','青玉案','[]','宜霜开尽秋光老。',82,'宋词/ci.song.7000.json','["宜霜开尽秋光老。", "感节物、愁多少。", "尘事难逢开口笑。", "满林风雨，一江烟水，飒爽惊吹帽。", "玉堂金马何须道。", "且斗取、尊前玉山倒。", "燕寝香清官事了。", "紫萸黄菊，皂罗红袂，花与人俱好。"]'),
('song-ci-978','好事近','胡铨','宋','宋词','song-ci','好事近','[]','富贵本无心，何事故乡轻别。',53,'宋词/ci.song.7000.json','["富贵本无心，何事故乡轻别。", "空使猿惊鹤怨，误薜萝风月。", "囊锥刚要出头来，不道甚时节。", "欲驾巾车归去，有豺狼当辙。"]'),
('song-ci-979','“僮至”念奴娇','俞处','宋','宋词','song-ci','“僮至”念奴娇','[]','残蝉断雁，政西风萧索，夕阳流水。',120,'宋词/ci.song.7000.json','["残蝉断雁，政西风萧索，夕阳流水。", "落木无边幽眺处，云拥登山屐齿。", "岁月如驰，古今同梦，惟有悲欢异。", "绿尊空对，故人相望千里。", "追念淮海当年，五云行殿，咫尺天颜喜。", "清晓胪传仙仗里，衣染玉龙香细。", "今日天涯，黄花零乱，满眼重阳泪。", "艰难多病，二陵无奈秋思。"]'),
('song-ci-980','小重山','岳飞','宋','宋词','song-ci','小重山','[]','昨夜寒蛩不住鸣。',70,'宋词/ci.song.7000.json','["昨夜寒蛩不住鸣。", "惊回千里梦，已三更。", "起来独自绕阶行。", "人悄悄，帘外月胧明。", "白首为功名。", "旧山松竹老，阻归程。", "欲将心事付瑶琴。", "知音少，弦断有谁听。"]'),
('song-ci-981','满江红','岳飞','宋','宋词','song-ci','满江红','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','怒发冲冠，凭阑处、潇潇雨歇。',115,'宋词/ci.song.7000.json','["怒发冲冠，凭阑处、潇潇雨歇。", "抬望眼、仰天长啸，壮怀激烈。", "三十功名尘与土，八千里路云和月。", "莫等闲、白了少年头，空悲切。", "靖康耻，犹未雪。", "臣子恨，何时灭。", "驾长车踏破，贺兰山缺。", "壮志饥餐胡虏肉，笑谈渴饮匈奴血。", "待从头、收拾旧山河，朝天阙。"]'),
('song-ci-982','满江红','岳飞','宋','宋词','song-ci','满江红','[]','遥望中原，荒烟外、许多城郭。',115,'宋词/ci.song.7000.json','["遥望中原，荒烟外、许多城郭。", "想当年、花遮柳护，凤楼龙阁。", "万岁山前珠翠绕，蓬壶殿里笙歌作。", "到而今、铁骑满郊畿，风尘恶。", "兵安在，膏锋锷。", "民安在，填沟壑。", "叹江山如故，千村寥落。", "何日请缨提锐旅，一鞭直渡清河洛。", "却归来、再续汉阳游，骑黄鹤。"]'),
('song-ci-983','满庭芳','邵缉','宋','宋词','song-ci','满庭芳','[]','落日旌旗，清霜剑戟，塞角声唤严更。',117,'宋词/ci.song.7000.json','["落日旌旗，清霜剑戟，塞角声唤严更。", "论兵慷慨，齿颊带风生。", "坐拥貔貅十万，衔枚勇、云槊交横。", "笑谈顷，匈奴授首，千里静欃枪。", "荆襄，人按堵，提壶劝酒，布谷催耕。", "芝夫荛子，歌舞威名。", "好是轻裘缓带，驱营阵、绝漠横行。", "功谁纪，风神宛转，麟阁画丹青。"]'),
('song-ci-984','水调歌头','吴芾','宋','宋词','song-ci','水调歌头','[]','九月二十六，公相纪生辰。',114,'宋词/ci.song.7000.json','["九月二十六，公相纪生辰。", "橙黄橘绿时候，天气暖於春。", "奎画有堂辉焕，中著台星一点，长伴寿星明。", "衮衮有家庆，未羡古徐卿。", "谢元枢，营绿野，避洪名。", "六年裁剸国事，曾费几精神。", "歇了傅岩霖雨，闲了孤舟野渡，旒冕合知心。", "吾道苟尊尚，元不在蒲轮。"]'),
('song-ci-985','滴滴金','孙道绚','宋','宋词','song-ci','滴滴金','[]','月光飞入林前屋。',60,'宋词/ci.song.7000.json','["月光飞入林前屋。", "风策策，度庭竹。", "夜半江城击柝声，动寒梢栖宿。", "等闲老去年华促。", "只有江梅伴幽独。", "梦绕夷门旧家山，恨惊回难续。"]'),
('song-ci-986','醉蓬莱','孙道绚','宋','宋词','song-ci','醉蓬莱','[]','看鸥翻波溅，苹末风轻，水轩消暑。',120,'宋词/ci.song.7000.json','["看鸥翻波溅，苹末风轻，水轩消暑。", "云叠奇峰，破桐阴亭午。", "列岫连环，溜泉鸣玉，对幅巾芒履。", "况有清时，风流故人，剧谈挥麈。", "才冠一时，论高两汉，书扇豪踪，吐凤辞语。", "昼锦归来，庆长年老母。", "且尽绿尊，莫怀归兴，听扇歌高举。", "会见登庸，泥封诏下，促朝天去。"]'),
('song-ci-987','菩萨蛮','孙道绚','宋','宋词','song-ci','菩萨蛮','[]','栏干六曲天围碧。',52,'宋词/ci.song.7000.json','["栏干六曲天围碧。", "松风亭下梅初白。", "腊尽见春回。", "寒梢花又开。", "曲琼闲不卷。", "沈燎看星转。", "凝伫小徘徊。", "云间征雁来。"]'),
('song-ci-988','少年游','孙道绚','宋','宋词','song-ci','少年游','[]','雨晴云敛，烟花澹荡，遥山凝碧。',58,'宋词/ci.song.7000.json','["雨晴云敛，烟花澹荡，遥山凝碧。", "驱车问征路，赏春风南陌。", "正雨后、梨花幽艳白。", "悔匆匆、过了寒食。", "归家渐春暮，探酴醿消息。"]'),
('song-ci-989','忆秦娥','孙道绚','宋','宋词','song-ci','忆秦娥','[]','秋寂寞。',56,'宋词/ci.song.7000.json','["秋寂寞。", "秋风夜雨伤离索。", "伤离索。", "老怀无奈，泪珠零落。", "故人一去无期约。", "迟书忽寄西飞鹤。", "西飞鹤。", "故人何在，水村山郭。"]'),
('song-ci-990','醉思仙','孙道绚','宋','宋词','song-ci','醉思仙','[]','晚霞红。',111,'宋词/ci.song.7000.json','["晚霞红。", "看山迷暮霭，烟暗孤松。", "动翩翩风袂，轻若惊鸿。", "心似鉴，鬓如云，弄清影，月明中。", "谩悲凉，岁冉冉，蕣华潜改衰容。", "前事销凝久，十年光景匆匆。", "念云轩一梦，回首春空。", "彩凤远，玉箫寒，夜悄悄，恨无穷。", "叹黄尘久埋玉，断肠挥泪东风。"]'),
('song-ci-991','如梦令','孙道绚','宋','宋词','song-ci','如梦令','[]','翠柏红蕉影乱。',40,'宋词/ci.song.7000.json','["翠柏红蕉影乱。", "月上朱栏一半。", "风自碧空来，吹落歌珠一串。", "不见。", "不见。", "人被绣帘遮断。"]'),
('song-ci-992','清平乐','孙道绚','宋','宋词','song-ci','清平乐','[]','悠悠扬扬。',54,'宋词/ci.song.7000.json','["悠悠扬扬。", "做尽轻模样。", "半夜萧萧窗外响。", "多在梅边竹上。", "朱楼向晓帘开。", "六花片片飞来。", "无奈熏炉烟雾，腾腾扶上金钗。"]'),
('song-ci-993','临江仙','何蓑衣道人','宋','宋词','song-ci','临江仙','[]','在世为仙须有分，不须素食持斋。',69,'宋词/ci.song.7000.json','["在世为仙须有分，不须素食持斋。", "寸丝不著挂形骸。", "蓑衣为伴侣，箬笠作家怀。", "行满三千上界，奉敕宣至金台。", "传言问汝有何哉。", "人生长富贵，阴骘种将来。"]'),
('song-ci-994','夜游宫','陆凝之','宋','宋词','song-ci','夜游宫','[]','东风捏就腰儿细。',67,'宋词/ci.song.7000.json','["东风捏就腰儿细。", "系滴粉裙儿不起。", "从来只惯掌中看，怎忍在、烛花影里。", "酒红应是铅华褪。", "暗蹙损、眉峰双翠。", "夜深点緉绣鞋儿，靠那个、屏风立地。"]'),
('song-ci-995','念奴娇','陆凝之','宋','宋词','song-ci','念奴娇','[]','远山一带，溯晴空、极目天涯浮白。',120,'宋词/ci.song.7000.json','["远山一带，溯晴空、极目天涯浮白。", "枫落鸦翻谈笑处，不觉云涛横席。", "酒病方苏，睡魔犹殢，一扫无留迹。", "吴帆越棹，恍然飞上空碧。", "长记草赋梁园，凌云笔势，倒三江秋色。", "对此惊心空怅望，老作红尘闲客。", "别浦烟平，小楼人散，回首千波寂。", "西风归路，为君重喷霜笛。"]'),
('song-ci-996','采莲延遍・采莲令','史浩','宋','宋词','song-ci','采莲延遍・采莲令','[]','霞霄上，有寿乡广袤无际。',96,'宋词/ci.song.7000.json','["霞霄上，有寿乡广袤无际。", "东极沧海，缥缈虚无，蓬莱弱水。", "风生屋浪，鼓楫扬旍，不许凡人得至。", "甚幽邃。", "试右望金枢外。", "西母楼阁，玉阙瑶池。", "万顷琉璃。", "双成倩巧，方朔诙谐。", "来往徜徉，霓裳飘摇宝砌。", "更稀奇。"]'),
('song-ci-997','采莲摇捱遍・采莲令','史浩','宋','宋词','song-ci','采莲摇捱遍・采莲令','[]','南邻幄丹宫，赤伏显符记。',92,'宋词/ci.song.7000.json','["南邻幄丹宫，赤伏显符记。", "朱陵曜绮绣，箕翼炯、瑞光腾起。", "每岁秋分老人见，表皇家、袭庆迎祺。", "天子当膺，无疆万岁。", "北窥玄冥，魁杓拥佳气。", "长拱极、终古无移。", "论南北东西。", "相直何啻千万里。", "信难计。"]'),
('song-ci-998','采莲入破・采莲令','史浩','宋','宋词','song-ci','采莲入破・采莲令','[]','璇穹层云上覆，光景如梭逝。',96,'宋词/ci.song.7000.json','["璇穹层云上覆，光景如梭逝。", "惟此过隙缓征辔。", "垂象森列昭回。", "碧落卓然躔度，炳曜更腾辉。", "永永清光晔炜。", "绵四野、金璧为地。", "蕊珠馆，琼玖室，俱高峙。", "千种奇葩，松椿可比。", "暗香幽馥，岁岁长春，阳乌何曾西委。"]'),
('song-ci-999','采莲衮遍・采莲令','史浩','宋','宋词','song-ci','采莲衮遍・采莲令','[]','遍此境，人乐康，挟难老术，悟长生理。',101,'宋词/ci.song.7000.json','["遍此境，人乐康，挟难老术，悟长生理。", "尽阿僧祗劫，赤松王令安期。", "彭篯盛矣。", "尚为婴稚。", "鹤算龟龄，绛老休夸甲子。", "鲐背耸、黄发垂髻。", "更童颜，长鼓腹、同游戏。", "真是华胥。", "行有歌，坐有乐，献笑都是神仙，时见群翁启齿。"]'),
('song-ci-0','采莲实催・采莲令','史浩','宋','宋词','song-ci','采莲实催・采莲令','[]','露华霞液，云桨椒醑，姿玉斝金罍。',96,'宋词/ci.song.8000.json','["露华霞液，云桨椒醑，姿玉斝金罍。", "交酬成雅会。", "拚沈醉。", "中山千日，未为长久，今此陶陶一饮，动经万祀。", "陈果蓏，皆是奇异。", "似瓜如斗尽备。", "三千岁。", "一熟珍味。", "饤坐中，莹似玉、爽口流涎，三偷不枉，西真指议。"]'),
('song-ci-1','采莲衮・采莲令','史浩','宋','宋词','song-ci','采莲衮・采莲令','[]','有珍馔，时时馈。',100,'宋词/ci.song.8000.json','["有珍馔，时时馈。", "滑甘丰腻。", "紫芝荧煌，嫩菊秀媚。", "贮玛瑙琥珀精器。", "延年益寿莫拟。", "人间烹饪徒费。", "休说龙肝凤髓。", "动妙乐、仙音鼎沸。", "玉箫清，瑶瑟美。", "龙笛脆。", "杂还飞鸾，花裀上、趁拍红牙，馀韵悠扬，竟海变桑田未止。"]'),
('song-ci-2','采莲歇拍・采莲令','史浩','宋','宋词','song-ci','采莲歇拍・采莲令','[]','其间有洞天侣，思游尘世。',92,'宋词/ci.song.8000.json','["其间有洞天侣，思游尘世。", "珠葆摇曳。", "华表真人，清江使者，相从密议。", "此老遨嬉。", "我辈应须随侍。", "正举步、忽思同类。", "十八公、方耸壑，宜邀致。", "夙驾星言，人争图绘。", "朅来鄞山甬水。", "因此崇成，四明里第。"]'),
('song-ci-3','采莲煞衮・采莲令','史浩','宋','宋词','song-ci','采莲煞衮・采莲令','[]','吾皇喜。',85,'宋词/ci.song.8000.json','["吾皇喜。", "光宠无贰。", "玉带金鱼荣贵。", "或者疑之。", "岂识圣明，曾主斯乡，尝相与尽缱绻，胶漆何可相离。", "今日风云合契。", "此实天意。", "吾皇圣寿无极，享晏粲千载相逢，我翁亦昌炽。", "永作升平上瑞。"]'),
('song-ci-4','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','练光浮，烟敛澄波渺。',112,'宋词/ci.song.8000.json','["练光浮，烟敛澄波渺。", "燕脂湿、靓妆初了。", "绿云伞上露滚滚，的皪真珠小。", "笼娇媚、轻盈伫眺。", "无言不见仙娥，凝望蓬岛。", "玉阙葱葱，镇锁佳丽春难老。", "银潢急、星槎飞到。", "暂离金砌，为爱此、极目香红绕。", "倚兰棹。", "清歌缥缈。", "隔花初见，楚楚风流年少。"]'),
('song-ci-5','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','蕊沼清冷涓滴水。',72,'宋词/ci.song.8000.json','["蕊沼清冷涓滴水。", "迢迢烟浪三千里。", "微孕青房包绣绮。", "薰风里。", "幽芳洗尽闲桃李。", "羽氅飘萧尘外侣。", "相呼短棹轻偎倚。", "一片清歌天际起。", "声尤美。", "双双惊起鸳鸯睡。"]'),
('song-ci-6','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','翠盖参差森玉柄。',72,'宋词/ci.song.8000.json','["翠盖参差森玉柄。", "迎风浥露香无定。", "不著尘沙真体净。", "芦花径。", "酒侵酥脸霞相映。", "棹拨木兰烟水暝。", "月华如练秋空静。", "一曲悠扬沙鹭听。", "牵清兴。", "香红已满蒹葭艇。"]'),
('song-ci-7','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','草软沙平风掠岸。',72,'宋词/ci.song.8000.json','["草软沙平风掠岸。", "青蓑一钓烟江畔。", "荷叶为裀花作幔。", "知谁伴。", "醇醪只把鲈鱼换。", "盘缕银丝杯自暖。", "篷窗醉著无人唤。", "逗得醒来横脆管。", "清歌缓。", "彩鸾飞去红云乱。"]'),
('song-ci-8','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','太华峰头冰玉沼。',72,'宋词/ci.song.8000.json','["太华峰头冰玉沼。", "开花十丈干云杪。", "风散天香闻四表。", "知多少。", "亭亭碧叶何曾老。", "试问霏烟登鸟道。", "丹崖步步祥光绕。", "折得一枝归月峤。", "蓬莱岛。", "霞裾侍女争言好。"]'),
('song-ci-9','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','珠露漙漙清玉宇。',72,'宋词/ci.song.8000.json','["珠露漙漙清玉宇。", "霞标绰约消烦暑。", "时驭清风之帝所。", "寻旧侣。", "三千仙仗临烟渚。", "舴艋飘摇来复去。", "渔翁问我居何处。", "笑把红蕖呼鹤驭。", "回头语。", "壶中自有朝天路。"]'),
('song-ci-10','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','彤霞出水弄幽姿。',59,'宋词/ci.song.8000.json','["彤霞出水弄幽姿。", "娉婷玉面相宜。", "棹歌先得一枝枝。", "波上画鲸飞。", "向此画堂高会，幽馥散、堪引瑶卮。", "幸然逢此太平时。", "不醉可无归。"]'),
('song-ci-11','采莲舞','史浩','宋','宋词','song-ci','采莲舞','[]','蕊宫阆苑。',73,'宋词/ci.song.8000.json','["蕊宫阆苑。", "听钧天帝乐，知他几遍。", "争似人间，一曲采莲新传。", "柳腰轻，莺舌啭。", "逍遥烟浪谁羁绊。", "无奈天阶，早已催班转。", "却驾彩鸾，芙蓉斜盼。", "愿年年，陪此宴。"]'),
('song-ci-12','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','武陵自古神仙府。',55,'宋词/ci.song.8000.json','["武陵自古神仙府。", "有渔人迷路。", "洞户迸寒泉，泛桃花容与。", "寻花逶逦见灵光，舍扁舟、飘然入去。", "注目渺红霞，有人家无数。"]'),
('song-ci-13','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','须臾却有人相顾。',55,'宋词/ci.song.8000.json','["须臾却有人相顾。", "把肴桨来聚。", "礼数既雍容，更衣冠淳古。", "渔人方问此何乡，众颦眉、皆能深诉。", "元是避嬴秦，共携家来住。"]'),
('song-ci-14','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','当时脱得长城苦。',55,'宋词/ci.song.8000.json','["当时脱得长城苦。", "但熙熙朝暮。", "上帝锡长生，任跳丸乌兔。", "种桃千万已成阴，望家乡、杳然何处。", "从此与凡人，隔云霄烟雨。"]'),
('song-ci-15','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','渔舟之子来何所。',55,'宋词/ci.song.8000.json','["渔舟之子来何所。", "尽相猜相语。", "夜宿玉堂空，见火轮飞舞。", "凡心有虑尚依然，复归指、维舟沙浦。", "回首已茫茫，叹愚迷不悟。"]'),
('song-ci-16','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','我今来访烟霞侣。',55,'宋词/ci.song.8000.json','["我今来访烟霞侣。", "沸华堂箫鼓。", "疑是奏钧天，宴瑶池金母。", "却将桃种散阶除，俾华实、须看三度。", "方记古人言，信有缘相遇。"]'),
('song-ci-17','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','云軿羽幰仙风举。',55,'宋词/ci.song.8000.json','["云軿羽幰仙风举。", "指丹霄烟雾。", "行作玉京朝，趁两班鹓鹭。", "玲珑环佩拥霓裳，却自有、箫韶随步。", "含笑嘱芳筵，后会须来赴。"]'),
('song-ci-18','太清舞','史浩','宋','宋词','song-ci','太清舞','[]','游尘世、到仙乡。',55,'宋词/ci.song.8000.json','["游尘世、到仙乡。", "喜君王。", "跻治虞唐。", "文德格遐荒。", "四裔尽来王。", "干戈偃息岁丰穰。", "三万里农桑。", "归去告穹苍。", "锡圣寿无疆。"]'),
('song-ci-19','柘枝舞','史浩','宋','宋词','song-ci','柘枝舞','[]','□人奉圣□□朝□□□□主□□□□□留伊。',52,'宋词/ci.song.8000.json','["□人奉圣□□朝□□□□主□□□□□留伊。", "得荷云戏、幸遇文明，尧阶上、太平时。", "□□□□何不罢岁□征舞柘枝。"]'),
('song-ci-20','柘枝舞','史浩','宋','宋词','song-ci','柘枝舞','[]','我是柘枝娇女。',58,'宋词/ci.song.8000.json','["我是柘枝娇女。", "□□多风措。", "□□□、□住深□，妙学得柘枝舞。", "□□头戴凤冠，□□□纤腰束素。", "□□遍体锦衣装，来献呈歌舞。"]'),
('song-ci-21','柘枝舞','史浩','宋','宋词','song-ci','柘枝舞','[]','回头却望尘寰去。',59,'宋词/ci.song.8000.json','["回头却望尘寰去。", "喧画堂箫鼓。", "整云鬟、摇曳青绡，爱一曲柘枝舞。", "好趁华封盛祝笑，共指南山烟雾。", "蟠桃仙酒醉升平，望凤楼归路。"]'),
('song-ci-22','花舞','史浩','宋','宋词','song-ci','花舞','[]','贵客之名从此有。',35,'宋词/ci.song.8000.json','["贵客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-23','花舞','史浩','宋','宋词','song-ci','花舞','[]','嘉客之名从此有。',35,'宋词/ci.song.8000.json','["嘉客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-24','花舞','史浩','宋','宋词','song-ci','花舞','[]','素客之名从此有。',35,'宋词/ci.song.8000.json','["素客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-25','花舞','史浩','宋','宋词','song-ci','花舞','[]','幽客之名从此有。',35,'宋词/ci.song.8000.json','["幽客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-26','花舞','史浩','宋','宋词','song-ci','花舞','[]','野客之名从此有。',35,'宋词/ci.song.8000.json','["野客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-27','花舞','史浩','宋','宋词','song-ci','花舞','[]','雅客之名从此有。',35,'宋词/ci.song.8000.json','["雅客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-28','花舞','史浩','宋','宋词','song-ci','花舞','[]','净客之名从此有。',35,'宋词/ci.song.8000.json','["净客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-29','花舞','史浩','宋','宋词','song-ci','花舞','[]','仙客之名从此有。',35,'宋词/ci.song.8000.json','["仙客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-30','花舞','史浩','宋','宋词','song-ci','花舞','[]','寿客之名从此有。',35,'宋词/ci.song.8000.json','["寿客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-31','花舞','史浩','宋','宋词','song-ci','花舞','[]','清客之名从此有。',35,'宋词/ci.song.8000.json','["清客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-32','花舞','史浩','宋','宋词','song-ci','花舞','[]','近客之名从此有。',35,'宋词/ci.song.8000.json','["近客之名从此有。", "多谢风流，飞驭陪尊酒。", "持此一卮同劝后。", "愿花长在人长寿。"]'),
('song-ci-33','花舞','史浩','宋','宋词','song-ci','花舞','[]','算仙家，真巧数，能使众芳长绣组。',64,'宋词/ci.song.8000.json','["算仙家，真巧数，能使众芳长绣组。", "羽軿芝葆，曾到世间，谁共凡花为伍。", "桃李漫夸艳阳，百卉又无香可取。", "岁岁年年长是春，何用芳菲分四序。"]'),
('song-ci-34','花舞','史浩','宋','宋词','song-ci','花舞','[]','对芳辰，成良聚，珠服龙妆环宴俎。',64,'宋词/ci.song.8000.json','["对芳辰，成良聚，珠服龙妆环宴俎。", "我御清风，来此纵观，还须折枝归去。", "归去蕊珠绕头，一一是东君为主。", "隐隐青冥怯路遥，且向台中寻伴侣。"]'),
('song-ci-35','花舞','史浩','宋','宋词','song-ci','花舞','[]','叹尘寰，乌兔走，花谢花开能几许。',65,'宋词/ci.song.8000.json','["叹尘寰，乌兔走，花谢花开能几许。", "十分春色，一半遣愁，那堪飘零风雨。", "争似此花自然，悄不待、根生下土。", "花既无凋春又长，好带花枝倾寿醑。"]'),
('song-ci-36','花舞','史浩','宋','宋词','song-ci','花舞','[]','是非场，名利海，得丧炎凉徒自苦。',65,'宋词/ci.song.8000.json','["是非场，名利海，得丧炎凉徒自苦。", "至乐陶陶，唯有醉乡，谁向此间知趣。", "花下一杯一杯，且莫把、光阴虚度。", "八极神游长寿仙，蜾蠃螟蠕休更觑。"]'),
('song-ci-37','剑舞','史浩','宋','宋词','song-ci','剑舞','[]','荧荧巨阙。',54,'宋词/ci.song.8000.json','["荧荧巨阙。", "左右凝霜雪。", "且向玉阶掀舞，终当有、用时节。", "唱彻。", "人尽说。", "宝此制无折。", "内使奸雄落胆，外须遣、豺狼灭。"]'),
('song-ci-38','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','细雨斜风都不管。',36,'宋词/ci.song.8000.json','["细雨斜风都不管。", "柔蓝软绿烟堤畔。", "鸥鹭忘机为主伴。", "无羁绊。", "等闲莫许金章换。"]'),
('song-ci-39','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','好景侬家披得去。',36,'宋词/ci.song.8000.json','["好景侬家披得去。", "前村雪屋云深处。", "一棹清歌归晚浦。", "真佳趣。", "知谁画得归缣素。"]'),
('song-ci-40','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','济涉还渠渔父子。',36,'宋词/ci.song.8000.json','["济涉还渠渔父子。", "生涯只在烟波里。", "练静忽然风又起。", "赢得底。", "吹来别浦看桃李。"]'),
('song-ci-41','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','万斛黄金迷俯仰。',36,'宋词/ci.song.8000.json','["万斛黄金迷俯仰。", "轻舠不碍飞双桨。", "光透碧霄千万丈。", "真堪赏。", "恰如镜里人来往。"]'),
('song-ci-42','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','已见白鱼翻翠荇。',36,'宋词/ci.song.8000.json','["已见白鱼翻翠荇。", "任公一掷波千顷。", "不是六鳌休便领。", "清昼永。", "悠扬要在神仙境。"]'),
('song-ci-43','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','一引修鳞吾事了。',36,'宋词/ci.song.8000.json','["一引修鳞吾事了。", "棹船归去歌声杳。", "门俯清湾山更好。", "眠到晓。", "鸣榔艇子方云扰。"]'),
('song-ci-44','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','试倩霜刀登玉缕。',36,'宋词/ci.song.8000.json','["试倩霜刀登玉缕。", "银鳞不忍供盘俎。", "掷向清波方圉圉。", "休更取。", "小槽且听真珠雨。"]'),
('song-ci-45','渔夫舞','史浩','宋','宋词','song-ci','渔夫舞','[]','莫惜清尊长在手。',36,'宋词/ci.song.8000.json','["莫惜清尊长在手。", "圣朝化洽民康阜。", "说与渔家知得否。", "齐稽首。", "太平天子无疆寿。"]'),
('song-ci-46','望海潮','史浩','宋','宋词','song-ci','望海潮','[]','烟笼香径，霞舒花砌，东君绣出芳辰。',129,'宋词/ci.song.8000.json','["烟笼香径，霞舒花砌，东君绣出芳辰。", "蝶羽弄轻，鸾声啭巧，嬉嬉舞态歌唇。", "纶制出严宸。", "曳耀春品服，荣锡绯银。", "向此华涂要路，颜色倍精神。", "珠帘碧甃方新。", "有兰堂快目，水榭通津。", "玉斝蘸清，金虬蔼翠，轮蹄尽集簪绅。", "偕老指双椿。", "望武林咫尺，同上青云。", "异日重为此会，应羡凤池人。"]'),
('song-ci-47','望海潮','史浩','宋','宋词','song-ci','望海潮','[]','烟浓柳径，霞蒸花砌，春深特地芳辰。',129,'宋词/ci.song.8000.json','["烟浓柳径，霞蒸花砌，春深特地芳辰。", "蝶侣斗狂，莺雏弄巧，嬉嬉舞态歌唇。", "西铺集簪绅。", "正桂薰兰玉，天寿松椿。", "竞捧瑶觥潋滟，来祝纵怀人。", "当年辍侍严宸。", "有星轺问俗，熊轼临民。", "康阜政成，蕃宣治美，归休燕处申申。", "行庆紫泥新。", "起钓璜国老，东海之滨。", "屈指重开此宴，应已拜平津。"]'),
('song-ci-48','望海潮','史浩','宋','宋词','song-ci','望海潮','[]','熊罴嘉梦，风云享会，磻溪应卜之年。',129,'宋词/ci.song.8000.json','["熊罴嘉梦，风云享会，磻溪应卜之年。", "黄菊萃英，红萸酿馥，安排预赏芳筵。", "环佩拥神仙。", "向粉额两字，金缕红鲜。", "最好花裀展处，双凤舞翩翩。", "人人竞擘香笺。", "璨珠玑溢目，祝颂无边。", "彭祖一分，庄椿十倍，千秋未足多言。", "日驭且停鞭。", "把燕闲欢乐，分付壶天。", "笑享亲朋岁岁，春酒庆团圆。"]'),
('song-ci-49','感皇恩','史浩','宋','宋词','song-ci','感皇恩','[]','健卒走红尘，芝封飞到。',81,'宋词/ci.song.8000.json','["健卒走红尘，芝封飞到。", "金缕斜斜印三道。", "舞鸾翔凤，犹带御炉烟袅。", "茜衣新象笏，银章好。", "对此况当，莺花缭绕。", "画栋翬翬映蓬岛。", "绣帘初卷，共指松椿偕老。", "浩歌拚烂醉，金尊倒。"]'),
('song-ci-50','感皇恩','史浩','宋','宋词','song-ci','感皇恩','[]','风雨揽元宵，收灯方了。',81,'宋词/ci.song.8000.json','["风雨揽元宵，收灯方了。", "深院红莲尚围绕。", "德星同聚，更有祥光临照。", "始知真洞府，春长好。", "应是化工，偏怜衰老。", "剩把青藜作荣耀。", "正须沈醉，拚却玉山频倒。", "寄声更漏子，休催晓。"]'),
('song-ci-51','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','烘锦花堤，铺绵柳巷，晓来膏雨初晴。',118,'宋词/ci.song.8000.json','["烘锦花堤，铺绵柳巷，晓来膏雨初晴。", "画堂初建，碧沼映朱楹。", "最好芙蓉绣褥，交辉敞、孔雀金屏。", "那堪更，华裾满坐，和气动欢声。", "冰清。", "真美行，棠阴善政，槐市高名。", "今朝消受得，茜服光荣。", "况是齐眉并寿，谁云道、乐事难并。", "相将见，飞凫过阙，除目下彤庭。"]'),
('song-ci-52','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','爱日轻融，阴云初敛，一番雪意阑珊。',118,'宋词/ci.song.8000.json','["爱日轻融，阴云初敛，一番雪意阑珊。", "柳摇金缕，梅绽五腮寒。", "知是东皇翠葆，飞星汉、来止人间。", "开新宴，笙歌逗晓，和气满城寰。", "风光，偏舜水，贤侯政美，棠荫多欢。", "更圜扉草鞠，木索长闲。", "休向今朝惜醉，红妆映、群玉颓山。", "相将见，宜春帖子，清夜写金銮。"]'),
('song-ci-53','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','微霰疏飘，骄云轻簇，短檠暗淡笼纱。',118,'宋词/ci.song.8000.json','["微霰疏飘，骄云轻簇，短檠暗淡笼纱。", "冷禁兰帐，清晓忽飞花。", "已是平芜步阔，那堪更、折竹如蓑。", "凭栏处，关心一叶，归兴渺无涯。", "为瑞，已多少，适从狼子，来自龙沙。", "赖吾皇神武，薄海为家。", "尽扫腥风杀气，依然放、红日光华。", "回头看，山蹊水坞，缟带不随车。"]'),
('song-ci-54','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','鲸海波澄，棠阴日永，正宜坐啸雍容。',118,'宋词/ci.song.8000.json','["鲸海波澄，棠阴日永，正宜坐啸雍容。", "岁丰民乐，无讼到庭中。", "试数循良自古，龚黄外、谁可追踪。", "那堪更，恩均髦寿，良会此宵同。", "璇穹。", "占瑞处，荧煌五马，璀璨群公。", "盛笙歌落绮，共引髯翁。", "祗恐芝泥趣召，双旌展、猎猎飞红。", "须知道，君王渴见，名久在屏风。"]'),
('song-ci-55','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','十载江湖，一朝簪组，宠荣曷称衰容。',118,'宋词/ci.song.8000.json','["十载江湖，一朝簪组，宠荣曷称衰容。", "圣恩不许，归卧旧庐中。", "慨念东山伴侣，烟霞外、久阔仙踪。", "今何幸，相逢故里，谈笑一尊同。", "吾州，真幸会，湖边贺监，海上黄公。", "胜渭川遗老，绛县仙翁。", "纵饮何辞烂醉，脸霞转、一笑生红。", "从今后，婆娑化国，千岁乐皇风。"]'),
('song-ci-56','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','油幕初开，騂旄前导，暂归梓里舂容。',118,'宋词/ci.song.8000.json','["油幕初开，騂旄前导，暂归梓里舂容。", "致身槐揆，功在鼎彝中。", "自是襟怀绝俗，今犹记、笔砚陈踪。", "张高会，君恩厚赐，乐与故人同。", "把麾，鄞水上，相看青眼，谁复如公。", "况亲陪尊俎，笑接群翁。", "坐上笙歌屡合，须拚到、晓日酣红。", "公今去，恩波四海，桃李尽东风。"]'),
('song-ci-57','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','玉阙朝回，沙堤烟晓，碧幢光动军容。',118,'宋词/ci.song.8000.json','["玉阙朝回，沙堤烟晓，碧幢光动军容。", "虎符熊轼，行指七闽中。", "假道吾乡我里，挥金事、思蹑前踪。", "倾怀处，萤窗雪案，犹说昔年同。", "相看，俱老大，襟期道义，不为王公。", "念儿时聚戏，今已成翁。", "敢借玉壶美酒，还为寿、金盏翻红。", "仍频祝，中书二纪，寰海振淳风。"]'),
('song-ci-58','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','复拥旌麾，重歌褥裤，满城长自春容。',118,'宋词/ci.song.8000.json','["复拥旌麾，重歌褥裤，满城长自春容。", "搢绅耆旧，欢溢笑谈中。", "尽道邦君恺悌，逍遥遂、湖海遐踪。", "今朝会，公真乐善，屈意与人同。", "恩勤，东道主，挥金汉傅，怀绶朱公。", "引群仙环拱，欲寿吾翁。", "春瓮初澄盎绿，春衫更、轻染香红。", "持杯愿，归登绛阙，花萼醉春风。"]'),
('song-ci-59','满庭芳','史浩','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','鹤冷风亭，鸿迷烟渚，晓来雪意填空。',118,'宋词/ci.song.8000.json','["鹤冷风亭，鸿迷烟渚，晓来雪意填空。", "酿成佳瑞，端为兆年丰。", "况有神娲妙手，调和得、云彩皆同。", "楼台上，铺琼缀玉，随步广寒宫。", "天公。", "开地轴，八紘混一，莫辨堤封。", "又须教、归禽狡兽沈踪。", "坐见花敷万木，谁知道、春已输工。", "三杯酒，西湖父老，相与话时雍。"]'),
('song-ci-60','庆清朝','史浩','宋','宋词','song-ci','庆清朝','[]','翠竹茎疏，碧溪流浅，绮窗为尔时开。',117,'宋词/ci.song.8000.json','["翠竹茎疏，碧溪流浅，绮窗为尔时开。", "依稀远岸，才见一点寒梅。", "冷定半疑是雪，因风还度暗香来。", "醉清兴，瘦策过桥，黄帽青鞋。", "繁枝正微雨后，似怨人知晚，泪浥冰腮。", "殷勤百绕，留连踏遍莓苔。", "报道玉人睡觉，菱花初试晓妆台。", "携归去，粉额殢人，比并轻抬。"]'),
('song-ci-61','蓦山溪','史浩','宋','宋词','song-ci','蓦山溪','[]','清淡无限，林下逢人少。',102,'宋词/ci.song.8000.json','["清淡无限，林下逢人少。", "骑马踏红尘，恁区区、何时是了。", "名场利海，毕竟白头翁，山簇翠，水拖蓝，只个生涯好。", "君侯洒落，卜筑开冰沼。", "三径直危楼，遍岩隈、幽花香草。", "风勾月引，馀事作诗人，词歌雪，气凌云，寒瘦伦郊岛。"]'),
('song-ci-62','青玉案','史浩','宋','宋词','song-ci','青玉案','[]','玉姬曾向瑶池舞。',80,'宋词/ci.song.8000.json','["玉姬曾向瑶池舞。", "轻掷霓裳忤王母。", "从此烟消飞鹤驭。", "一来人世，有缘相遇，得得为鸳侣。", "年年此际霞觞举。", "彩笔香笺染新句。", "休饵灵砂奔月去。", "齐眉不老，直须携手，同上青冥路。"]'),
('song-ci-63','青玉案','史浩','宋','宋词','song-ci','青玉案','[]','涌金斜转青云路。',82,'宋词/ci.song.8000.json','["涌金斜转青云路。", "溯衮衮、红尘去。", "春色勾牵知几度。", "月帘风幌，有人应在，唾线馀香处。", "年来不梦巫山暮。", "但苦忆、江南断肠句。", "一笑匆匆何尔许。", "客情无奈，夜阑归去，簌簌红空雨。"]'),
('song-ci-64','青玉案','史浩','宋','宋词','song-ci','青玉案','[]','年来减却风情大。',82,'宋词/ci.song.8000.json','["年来减却风情大。", "百样收心待不作。", "恰恨仙翁停画舸。", "雪中把酒，美人频为，浅破樱桃颗。", "清歌谁许阳春和。", "悄不放、遥空片云过。", "惊落梁尘浑可可。", "一声啭处，故园春近，桃李还知麽。"]'),
('song-ci-65','西江月','史浩','宋','宋词','song-ci','西江月','[]','红蓼千堤挺蕊，苍梧一叶辞柯。',58,'宋词/ci.song.8000.json','["红蓼千堤挺蕊，苍梧一叶辞柯。", "夜阑清露泻银河。", "洗出芙蓉半朵。", "解带初开粉面，绕梁还听珠歌。", "心期端的在秋波。", "想得今宵只我。"]'),
('song-ci-66','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','凤阙朱旗展，弄罢五弦，南薰敲竹。',127,'宋词/ci.song.8000.json','["凤阙朱旗展，弄罢五弦，南薰敲竹。", "雨糁桃蹊，钱浮荷沼，一瞬染成新绿。", "玉皇香案吏，曾是时、鹤飞江国。", "对此际，每丹霄效瑞，非烟郁郁。", "卜筑。", "陶山曲，风榭月台，图画应难足。", "绿绮春浓，青蛇星烂，肯便稳栖烟麓。", "玳筵称寿，清皓齿、霏霏珠玉。", "竞屈指，看芝封紫检，鸣驺入谷。"]'),
('song-ci-67','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','征鸿回北。',126,'宋词/ci.song.8000.json','["征鸿回北。", "正雪洗烧痕，千岩匀绿。", "鱼纵新漪，梅繁断岸，春到鉴湖一曲。", "满城绣帘珠幌，暖响聒天丝竹。", "渐向晚，放芙蕖千顷，交辉华烛。", "贤牧。", "棠阴静，康阜政成，褒诏来黄屋。", "玉笋光寒，紫荷香润，人道此装须趣。", "且出催花银漏，恣饮宝觥醽醁。", "向明岁，看传柑归去，腰横金粟。"]'),
('song-ci-68','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','才过元夕。',126,'宋词/ci.song.8000.json','["才过元夕。", "送宴赏未阑，欢娱无极。", "且莫收灯，仍休止酒，留取凤笙龙笛。", "金马玉堂学士，当此同开华席。", "最堪爱，是兰膏光在，金釭连壁。", "难觅。", "交欢处，杯吸百川，雅量皆勍敌。", "老子衰迟，居然怀感，厚意怎生酬得。", "况已倦游客路，一志归安泉石。", "但屈指，愿诸贤衮绣，联飞鹏翼。"]'),
('song-ci-69','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','谯门残月。',126,'宋词/ci.song.8000.json','["谯门残月。", "正画角晓寒，梅花吹彻。", "瑞日烘云，和风解冻，青帝乍临东阙。", "暖响土牛箫鼓，夹路珠帘高揭。", "最好是，看彩幡金胜，钗头双结。", "奇绝。", "开宴处，珠履玳簪，俎豆争罗列。", "舞袖翩翻，歌声缥缈，压倒柳腰莺舌。", "劝我应时纳祜，还把金炉香爇。", "愿岁岁，这一卮春酒，长陪佳节。"]'),
('song-ci-70','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','雪消春浅。',126,'宋词/ci.song.8000.json','["雪消春浅。", "听爆竹送穷，椒花待旦，系马合簪，鸣鸦列炬，几处玳筵开宴。", "介我百千眉寿，齐捧玉壶金盏。", "最奇绝，是小桃新坼，争妍粉面。", "女伴。", "频告语，守岁通宵，莫放笙歌散。", "酒晕朝霞，寒欺重翠，却忆凤屏香暖。", "笑拂满身花影，遥指珠帘深院。", "待到了，道一声稳睡，明年相见。"]'),
('song-ci-71','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','["\u897f\u6e56"]','凭高寓目。',126,'宋词/ci.song.8000.json','["凭高寓目。", "爱屹起四窗，云南云北。", "缥缈烟霞，萧森松竹，多少洞天岩谷。", "著向十洲三岛，入海何妨登陆。", "要知处，在皇家新赐，西湖一曲。", "林麓。", "真胜概，樊榭鹿亭，百卉生幽馥。", "绿绮春浓，青蛇星烂，隔断世间尘俗。", "笑呼羡门俦侣，时引宝觞醽醁。", "醉和醒，但南山之寿，难忘勤祝。"]'),
('song-ci-72','点绛唇','史浩','宋','宋词','song-ci','点绛唇','[]','我为劳生，自怜浪迹天涯遍。',50,'宋词/ci.song.8000.json','["我为劳生，自怜浪迹天涯遍。", "如今春换。", "又是孤萍断。", "谁信年时，老子情非浅。", "思量见。", "画楼天远。", "花倚夕阳院。"]'),
('song-ci-73','点绛唇','史浩','宋','宋词','song-ci','点绛唇','[]','千里欢谣，使君美政高三辅。',50,'宋词/ci.song.8000.json','["千里欢谣，使君美政高三辅。", "沸天箫鼓。", "笑拥锋车去。", "卧辙攀辕，漫拟双旌住。", "还知否。", "禁林深处。", "已辟金闺路。"]'),
('song-ci-74','点绛唇','史浩','宋','宋词','song-ci','点绛唇','[]','翠幄园林，火云方绽南薰起。',50,'宋词/ci.song.8000.json','["翠幄园林，火云方绽南薰起。", "玉轮天外。", "夜色凉如水。", "况有清歌，劝我尊浮蚁。", "拚沈醉。", "万花丛里。", "一枕朦胧睡。"]'),
('song-ci-75','点绛唇','史浩','宋','宋词','song-ci','点绛唇','[]','曾到蟾宫，玉轮乞得长随手。',50,'宋词/ci.song.8000.json','["曾到蟾宫，玉轮乞得长随手。", "数声轻叩。", "已有锵琼玖。", "最好长清，浑不惊秋候。", "歌阑后。", "那回辞酒。", "笑把遮檀口。"]'),
('song-ci-76','木兰花慢','史浩','宋','宋词','song-ci','木兰花慢','[]','喜阳和应律，启佳气、满寰瀛。',121,'宋词/ci.song.8000.json','["喜阳和应律，启佳气、满寰瀛。", "正雪洗疏梅，云浮淡月，昨夜生明。", "熊罴信占梦好，当年相阀再蟠英。", "收拾仙风道韵，萃兹一点台星。", "功名。", "壮岁逢真。", "主紫橐、耀西清。", "向玉笋光中，瑶林宴里，来拥双旌。", "青毡家旧物，看长参、鼎鼎乐升平。", "春醑休辞介寿，鹤书已播彤廷。"]'),
('song-ci-77','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','衮绣蝉联三重客，朝回晓日曈昽。',70,'宋词/ci.song.8000.json','["衮绣蝉联三重客，朝回晓日曈昽。", "绿杨门巷拥花骢。", "喜承天上语，来作主人公。", "况值瑶林风露爽，冰轮碾上晴空。", "桂香和影堕金锺。", "莫辞通夕醉，明日是秋中。"]'),
('song-ci-78','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','槛竹敲风初破睡，楚台梦雨精神。',70,'宋词/ci.song.8000.json','["槛竹敲风初破睡，楚台梦雨精神。", "背屏斜映小腰身。", "山明双翦水，香满一钗云。", "炉袅金丝帘窣地，绮窗秋静无尘。", "半钩春笋带湘筠。", "兰亭初写就，愁杀卫夫人。"]'),
('song-ci-79','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','绣幕罗裙风冉冉，象床毡幄低垂。',70,'宋词/ci.song.8000.json','["绣幕罗裙风冉冉，象床毡幄低垂。", "兽炉香袅锦屏围。", "不贪敧钿枕，偏爱倚花枝。", "软玉红绡轻暖透，温温翠袖扶持。", "正忺安稳坐移时。", "雨云忘峡梦，身境是瑶池。"]'),
('song-ci-80','鹧鸪天','史浩','宋','宋词','song-ci','鹧鸪天','[]','画角梅花曲未终。',64,'宋词/ci.song.8000.json','["画角梅花曲未终。", "霜严飞落五更风。", "谁知林外鸡三唱，推出红轮海上峰。", "官一品，禄千锺。", "此时分付荷重瞳。", "更教赐子云南境，绝胜湖边九里松。"]'),
('song-ci-81','鹧鸪天','史浩','宋','宋词','song-ci','鹧鸪天','[]','我本飘然出岫云。',64,'宋词/ci.song.8000.json','["我本飘然出岫云。", "挂冠归去岸纶巾。", "但教名利休缰锁，心地何时不是春。", "竹叶美，菊花新。", "百杯且听绕梁尘。", "故乡父老应相贺，林下方今见一人。"]'),
('song-ci-82','鹧鸪天','史浩','宋','宋词','song-ci','鹧鸪天','[]','孔雀双飞敞画屏。',64,'宋词/ci.song.8000.json','["孔雀双飞敞画屏。", "锦花茵上舞娉婷。", "红绡袖暖琉璃滑，金鸭炉香椒桂馨。", "丹脸渥，秀眉青。", "平生阴德在遐龄。", "如今便好添龟鹤，元是南箕一寿星。"]'),
('song-ci-83','鹧鸪天','史浩','宋','宋词','song-ci','鹧鸪天','[]','晓日曈昽花露稀。',64,'宋词/ci.song.8000.json','["晓日曈昽花露稀。", "明光已报敞金扉。", "三千彩仗翔鸾舞，数百银袍振鹭飞。", "开雉扇，正垂衣。", "奏篇初得上彤墀。", "胪传绕殿天颜喜，先折东风第一枝。"]'),
('song-ci-84','蝶恋花','史浩','宋','宋词','song-ci','蝶恋花','[]','桂影团团光正满。',70,'宋词/ci.song.8000.json','["桂影团团光正满。", "更似菱花，齐把匀娇面。", "非镜非蟾君细看。", "元来却是吴姬扇。", "一曲阳春犹未遍。", "惊落梁尘，不数莺喉啭。", "好著红绡笼玉腕。", "轻敲引入笙歌院。"]'),
('song-ci-85','宝鼎现','史浩','宋','宋词','song-ci','宝鼎现','[]','霞霄丹阙，瑞霭佳气，青葱如绮。',192,'宋词/ci.song.8000.json','["霞霄丹阙，瑞霭佳气，青葱如绮。", "才半月、东君雨露，无限韶华生宝砌。", "渐向晚、放烛龙掀舞，周币红蕖绀蕊。", "况对峙、鳌峰贔屓，不隔蓬莱弱水。", "圣主有乐升平意。", "引芝华、双辇凝翠。", "纷万俗、歌谣弦管，声混莺吟喧凤吹。", "更漏永、正冰轮掩映，光接康衢万里。", "似移下、一天星斗，妆点都城表里。", "清警跸、忽登楼，簇彩仗、锦襦丝履。", "看柑传万颗，恩浃王公近侍。", "散异卉覆千官醉。", "竞捧瑶觞起。", "愿岁岁、今宵宴赏，春满山河百二。"]'),
('song-ci-86','最高楼','史浩','宋','宋词','song-ci','最高楼','[]','当年尚父，一个便兴周。',103,'宋词/ci.song.8000.json','["当年尚父，一个便兴周。", "今十倍，更何忧。", "冲融道貌丹为脸，扶疏漆发黑盈头。", "世方知，非熊老，聚吾州。", "有智略、可从兹日用，有志愿、可从兹日酬。", "天付我，怎教休。", "琼浆且共飞千斛，蟠桃应得见三偷。", "谅吾皇，恢复后，尽封侯。"]'),
('song-ci-87','明月逐人来','史浩','宋','宋词','song-ci','明月逐人来','[]','莫嫌春浅。',75,'宋词/ci.song.8000.json','["莫嫌春浅。", "寒威俱敛。", "阳和至此时方见。", "木君敷令，把雪霜扫断。", "要集德星胜伴。", "为有仙翁，正尔名喧蕃汉。", "眉寿比、聃彭更远。", "兼资勋业，已中双雕箭。", "清步槐庭影满。"]'),
('song-ci-88','踏莎行','史浩','宋','宋词','song-ci','踏莎行','[]','歌舌莺娇，舞腰蜂细。',68,'宋词/ci.song.8000.json','["歌舌莺娇，舞腰蜂细。", "华堂是处皆颐指。", "四弦独擅席中春，移船出塞声能继。", "慢拈幽情，轻拢柔思。", "其中有口传心事。", "主人灯火下楼时，偏渠领略深深意。"]'),
('song-ci-89','生查子','史浩','宋','宋词','song-ci','生查子','[]','双蛟画鼓催，一水银蟾满。',48,'宋词/ci.song.8000.json','["双蛟画鼓催，一水银蟾满。", "见夺锦标回，却倚花枝看。", "已擘冷金笺，更酹玻璃碗。", "归去诧乡关，不负平生眼。"]'),
('song-ci-90','江城子','史浩','宋','宋词','song-ci','江城子','[]','片帆初落甬勾东。',86,'宋词/ci.song.8000.json','["片帆初落甬勾东。", "碧湖空。", "满汀风。", "回首一川，银浪飐孤篷。", "且驾两椽烟雨里，凭曲槛，浥空濛。", "闲移拄杖上晴峰。", "莫匆匆。", "伴冥鸿。", "笑指家山，苹叶藕花中。", "脚力倦时呼小艇，归棹稳，月朦胧。"]'),
('song-ci-91','浪淘沙令','史浩','宋','宋词','song-ci','浪淘沙令','[]','祝寿祝寿。',69,'宋词/ci.song.8000.json','["祝寿祝寿。", "筵开锦绣。", "拈起香来玉也似手。", "拈起盏来金也似酒。", "祝寿祝寿。", "命比乾坤久。", "长寿长寿。", "松椿自此碧森森底茂。", "乌兔从他汨轳轳底走。", "长寿长寿。"]'),
('song-ci-92','瑞鹤仙','史浩','宋','宋词','song-ci','瑞鹤仙','[]','霁光春未晓。',127,'宋词/ci.song.8000.json','["霁光春未晓。", "拥绛蜡攒星，霜蹄轻袅。", "皇居耸云杪。", "霭祥烟瑞气，青葱缭绕。", "金门羽葆。", "听胪唱、千官并到。", "庆三朝、雉扇开时，拜舞仰瞻天表。", "荣耀。", "万方图籍，四裔明王，赆賝珍宝。", "椒盘颂好。", "称寿斝，祝难老。", "更传宣锡坐，钧天妙乐，声遏行运缥缈。", "逗归来、酒晕生霞，此恩怎报。"]'),
('song-ci-93','水龙吟','史浩','宋','宋词','song-ci','水龙吟','[]','翠空缥缈虚无，算唯海上蓬瀛好。',125,'宋词/ci.song.8000.json','["翠空缥缈虚无，算唯海上蓬瀛好。", "琼瑶宫阙，蕊珠台榭，玲珑缭绕。", "弱水沈冥，瑞云遮隔，几人曾到。", "四明中，自有神仙洞府，烟霞里、知多少。", "堪笑当年狂客，爱休官、何须入道。", "婆娑绿发垂肩，著甚黄冠乌帽。", "花底金船，月边玉局，尽能迟老。", "待丹成九转，飘然驾鹤，却游三岛。"]'),
('song-ci-94','水龙吟','史浩','宋','宋词','song-ci','水龙吟','[]','平湖渺渺烟波，是中只许神仙住。',126,'宋词/ci.song.8000.json','["平湖渺渺烟波，是中只许神仙住。", "人间空爱，夭桃繁李，雪飞红雨。", "谁信壶天，靓妆玉貌，春光容与。", "似佳人才子，青冥步稳，同携手、成欢聚。", "老子时来宴赏，拥笙歌、留连尊俎。", "乌纱压倒，香云簪遍，知他几度。", "多谢东君，肯教满架，长情相处。", "更须拚痛饮，年年此际，作芳菲主。"]'),
('song-ci-95','永遇乐','史浩','宋','宋词','song-ci','永遇乐','[]','鄞有壶天，景传图画，声著海县。',128,'宋词/ci.song.8000.json','["鄞有壶天，景传图画，声著海县。", "四面攒峰，皆七十二，各在窗中见。", "祥云拥蔽，飞泉缭绕，咫尺似天涯远。", "如今向、仙家觅得，挈来十洲东畔。", "虚无缥缈，蓬莱方丈，所喜只居隔岸。", "羽幰垂珠，琼车织翠，长是陪嘉宴。", "豺狼远迹，风波不作，日月御轮须缓。", "且衔杯、称贤乐圣，度兹岁晚。"]'),
('song-ci-96','迎仙客','史浩','宋','宋词','song-ci','迎仙客','[]','瑞云绕。',70,'宋词/ci.song.8000.json','["瑞云绕。", "四窗好。", "何须隔水寻蓬岛。", "日常晓。", "春不老。", "玉蕊楼台，果是无尘到。", "没智巧。", "没华妙。", "个中只喜风波少。", "清尊倒。", "朱颜笑。", "回首行人，犹在长安道。"]'),
('song-ci-97','南浦','史浩','宋','宋词','song-ci','南浦','[]','一箭舜弦风，向晓来、轻寒初报麦秀。',127,'宋词/ci.song.8000.json','["一箭舜弦风，向晓来、轻寒初报麦秀。", "蝶股歇花须，韶光老，莺声倦闻呼友。", "池塘绿暗，数竿粉节天然瘦。", "对兹美景，爱清歌妙曲，千锺芳酒。", "谁知别是壶中，缭画阁朱栏，烟谷云岫。", "三岛十洲东，青霄上，神工幻成岩窦。", "瑶台阆苑，翠旌羽葆频相就。", "世凡洗断，教乌兔从今，迟迟飞走。"]'),
('song-ci-98','夜合花','史浩','宋','宋词','song-ci','夜合花','[]','三岛烟霞，十洲风月，四明古号仙乡。',121,'宋词/ci.song.8000.json','["三岛烟霞，十洲风月，四明古号仙乡。", "萦纡雉堞，中涵一片湖光。", "绕岸异卉奇芳。", "跨虹桥、隐映垂杨。", "玉楼珠阁，冰帘卷起，无限红妆。", "龙舟两两飞扬。", "见飘翻绣旗，歌杂笙簧。", "清尊满泛，休辞饮到斜阳。", "直须画蜡荧煌。", "况夜深、不阻城隍。", "且拚沈醉，归途便教，彻晓何妨。"]'),
('song-ci-99','人月圆','史浩','宋','宋词','song-ci','人月圆','[]','夕阳影里东风软，骄马趁香车。',59,'宋词/ci.song.8000.json','["夕阳影里东风软，骄马趁香车。", "看花妆镜，藏春绣幕，百万人家。", "夜阑归去，星繁绛蜡，珠翠鲜华。", "笙歌不散，疏锺隐隐，月在梅丫。"]'),
('song-ci-100','人月圆','史浩','宋','宋词','song-ci','人月圆','[]','骄云不向天边聚，密雪自飞空。',59,'宋词/ci.song.8000.json','["骄云不向天边聚，密雪自飞空。", "佳人纤手，霎时造化，珠走盘中。", "六街灯市，争圆斗小，玉碗频供。", "香浮兰麝，寒消齿颊，粉脸生红。"]'),
('song-ci-101','粉蝶儿','史浩','宋','宋词','song-ci','粉蝶儿','[]','一箭和风，秾熏许多春意。',94,'宋词/ci.song.8000.json','["一箭和风，秾熏许多春意。", "闹蛾儿、满城都是。", "向深闺，争翦碎、吴绫蜀绮。", "点妆成，分明是、粉须香翅。", "玉容似花，全胜故园桃李。", "最相宜、鬓云秋水。", "怎教他，却去与、庄周同睡。", "愿年年，伴星球、烂游灯市。"]'),
('song-ci-102','粉蝶儿','史浩','宋','宋词','song-ci','粉蝶儿','[]','玉屑轻盈，鲛绡霎时铺遍。',92,'宋词/ci.song.8000.json','["玉屑轻盈，鲛绡霎时铺遍。", "看仙娥、骋些神变。", "咄嗟间，如撒下、真珠一串。", "火方然，汤初滚、尽浮锅面。", "歌楼酒垆，今宵任伊索唤。", "那佳人、怎生得见。", "更添糖，拚折本、供他几碗。", "浪儿门，得我这些方便。"]'),
('song-ci-103','教池回','史浩','宋','宋词','song-ci','教池回','[]','云淡天低，疏雨乍霁，桃溪嫩绿蒙茸。',119,'宋词/ci.song.8000.json','["云淡天低，疏雨乍霁，桃溪嫩绿蒙茸。", "珠帘映画毂，金勒耀花骢。", "绕湖上、罗衣隘香风。", "擘波双引蛟龙。", "寻奇处，高标锦段，各骋英雄。", "缥缈初登彩舫，箫鼓沸，群仙玉佩丁东。", "夕阳中、拚一饮千锺。", "看看见、璧月穿林杪，十洲三岛舂容。", "醉归去，双旌摇曳，夹路金笼。"]'),
('song-ci-104','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','小院春风不老。',40,'宋词/ci.song.8000.json','["小院春风不老。", "鹊碧霓裳缥缈。", "雪脸间朱颜，各自一般轻妙。", "忒掉。", "忒掉。", "真个一双两好。"]'),
('song-ci-105','洞仙歌','史浩','宋','宋词','song-ci','洞仙歌','[]','琼肌太白，浅著鹅黄罩。',102,'宋词/ci.song.8000.json','["琼肌太白，浅著鹅黄罩。", "金缕檀心更天巧。", "算同时、虽有似火红榴，争比得、淡妆伊家轻妙。", "兴来清赏处，无限真香，可惜生教生闽峤。", "这消息、纵使移向蒸沈，终不似凭栏，披襟一笑。", "若归去长安诧标容，单道胜、酴醿水仙风貌。"]'),
('song-ci-106','醉蓬莱','史浩','宋','宋词','song-ci','醉蓬莱','[]','纪今辰高会，屈指三朝，更逢重九。',120,'宋词/ci.song.8000.json','["纪今辰高会，屈指三朝，更逢重九。", "珠履瑶簪，聚一天星斗。", "菊蕊含芳，桂花笼艳，有美容争秀。", "衮绣堂中，蓬壶影里，异香喷兽。", "况是清朝，太平真主，治享雍熙，眷深耆旧。", "恩锡兼金，遣星轺东走。", "咫尺威光，下拜归美，愿我皇眉寿。", "自此重裁，谢笺千纸，年年回奏。"]'),
('song-ci-107','声声慢','史浩','宋','宋词','song-ci','声声慢','[]','风收淅沥，雾隐森罗。',119,'宋词/ci.song.8000.json','["风收淅沥，雾隐森罗。", "群山万玉嵯峨。", "禁街车马，银杯缟带相过。", "胥涛晚来息怒，练光浮、都不扬波。", "最好处，是渔翁归去，鼓棹披蓑。", "况是东堂锡宴，龙墀骤，貂珰宣劝金荷。", "庆此嘉瑞，明岁黍稌应多。", "天家预知混一，把琼瑶、铺遍山河。", "这宴饮，罄华戎、同醉泰和。"]'),
('song-ci-108','秋蕊香','史浩','宋','宋词','song-ci','秋蕊香','[]','玉露瀼瀼，秋色似画，东堂宴席初开。',116,'宋词/ci.song.8000.json','["玉露瀼瀼，秋色似画，东堂宴席初开。", "红萸泛寿斝，紫菊上妆台。", "倚栏见、新雁已南来。", "落霞孤鹜徘徊。", "最奇处，重阳将近，凉满襟怀。", "萧洒秀眉，华发丹脸，映双瞳、的皪如孩。", "擘香笺、听丽句新裁。", "池上三回蟠桃熟，玉纤时捧琼杯。", "但愿得，年年此会满蓬莱。"]'),
('song-ci-109','渔家傲','史浩','宋','宋词','song-ci','渔家傲','[]','春恨不禁听杜宇。',72,'宋词/ci.song.8000.json','["春恨不禁听杜宇。", "买舟忽觅东鄞路。", "一笑轻帆同野渡。", "频回顾。", "吴山夜岫俱眉妩。", "何事匆匆分袂去。", "夫君小隐临烟渚。", "明夜月华来竹坞。", "相思处。", "还应梦属清江橹。"]'),
('song-ci-110','花心动','史浩','宋','宋词','song-ci','花心动','[]','迟日轻阴，雨初收，花枝湿红犹滴。',127,'宋词/ci.song.8000.json','["迟日轻阴，雨初收，花枝湿红犹滴。", "玉镫绣鞯，才得新晴，柳岸往来如织。", "画楼几处珠帘卷，风光遍、神仙瑶席。", "萃佳景，分明管领，一陂澄碧。", "忽见波涛噀激。", "苍烟际、双龙起为勍敌。", "桂楫拨云，鼍鼓轰雷，竞夺锦标千尺。", "恁时彩舰虹桥畔，舂容引、宝觥霞液。", "兴浓处，笙歌又还竟夕。"]'),
('song-ci-111','水龙吟','史浩','宋','宋词','song-ci','水龙吟','[]','雪中蓓蕾嫣然，美人莫恨春容少。',126,'宋词/ci.song.8000.json','["雪中蓓蕾嫣然，美人莫恨春容少。", "化工消息，只须些子，阳和便了。", "文杏徒繁，牡丹虽贵，敢夸妍妙。", "看冰肌玉骨，诗家漫道，银蟾莹、白驹皎。", "楼上角声催晓。", "是东皇、丝纶新草。", "青旗苍辂，欲临东阙，遣伊先到。", "排斥风霜，扫除氛雾，直教闻早。", "算功高调鼎，不如竹外，一枝斜好。"]'),
('song-ci-112','瑞鹤仙','史浩','宋','宋词','song-ci','瑞鹤仙','[]','是花堪爱惜。',127,'宋词/ci.song.8000.json','["是花堪爱惜。", "谢天教、花信添花颜色。", "花红衬花碧。", "灿朝阳花露，鲛珠频滴。", "花光的皪。", "映花下、□茵百尺。", "趁花时，手拈花枝，饱嗅此花消息。", "常恐，一番花褪，失了花容，怎生寻觅。", "花神效力。", "将花貌，尽留得。", "更移花并植，仙家玉圃，不许花阴过隙。", "向花前，长把蕉花，为花主席。"]'),
('song-ci-113','喜迁莺','史浩','宋','宋词','song-ci','喜迁莺','[]','三春正美。',126,'宋词/ci.song.8000.json','["三春正美。", "是霁景融和，韶华如绮。", "夹岸香红，登墙粉白，开遍故园桃李。", "画舸绣帘高卷，锦毂朱轩低倚。", "对此际，向池台好处，争倾绿蚁。", "醉里。", "须醒悟，些子芳菲，造物都谩你。", "一瞬光阴，霎时蜂蝶，还付落花流水。", "我有大丹九转，真个长春不死。", "待得了，把高歌清赏，随缘而已。"]'),
('song-ci-114','菩萨蛮','史浩','宋','宋词','song-ci','菩萨蛮','[]','提壶漫欲寻芳去。',52,'宋词/ci.song.8000.json','["提壶漫欲寻芳去。", "桃红柳绿年年事。", "唯有列仙翁。", "清明本在躬。", "何须从外讨。", "皮里阳秋好。", "堪羡个中人。", "无时不是春。"]'),
('song-ci-115','南浦','史浩','宋','宋词','song-ci','南浦','[]','天气正清和，庆西乾、释迦如来出世。',126,'宋词/ci.song.8000.json','["天气正清和，庆西乾、释迦如来出世。", "毓质向金盆，祥云布、层霄九龙喷水。", "东传震旦，正令此日人人记。", "露盘百卉拥金容，香汤争来拂洗。", "谁知这个因缘，化众生令求，尘埃脱离。", "一点本昭昭，当须向、兹时便知瞥地。", "何烦费手，自然作个惺惺底。", "若犹未晤，且管令师僧，八丈十二。"]'),
('song-ci-116','青玉案','史浩','宋','宋词','song-ci','青玉案','[]','银涛渐溢江南路。',80,'宋词/ci.song.8000.json','["银涛渐溢江南路。", "泛短棹、轻帆去。", "破块跳珠知几度。", "竹窗新粉，藕池香碧，应在云深处。", "萧萧鹤发虽云暮。", "曾得神仙悟真句。", "久视长生亲见语。", "离愁扫尽，更无慵困，怕甚黄梅雨。"]'),
('song-ci-117','花心动','史浩','宋','宋词','song-ci','花心动','[]','槐夏阴浓，笋成竿、红榴正堪攀折。',127,'宋词/ci.song.8000.json','["槐夏阴浓，笋成竿、红榴正堪攀折。", "菖歜碎琼，角黍堆金，又赏一年佳节。", "宝觥交劝殷勤愿，把玉腕、彩丝双结。", "最好是，龙舟竞夺，锦标方彻。", "此意凭谁向说。", "纷两岸，游人强生区别。", "胜负既分，些个悲欢，过眼尽归休歇。", "到头都是强阳气，初不悟、本无生灭。", "见破底，何须更求指诀。"]'),
('song-ci-118','卜算子','史浩','宋','宋词','song-ci','卜算子','[]','符箓玉搔头，艾虎青丝鬓。',52,'宋词/ci.song.8000.json','["符箓玉搔头，艾虎青丝鬓。", "一曲清歌倒酒莲，尚有香蒲晕。", "角簟碧纱厨，挥扇消烦闷。", "唯有先生心地凉，不怕炎曦近。"]'),
('song-ci-119','永遇乐','史浩','宋','宋词','song-ci','永遇乐','[]','日永绣工，减却一线，节临短至。',128,'宋词/ci.song.8000.json','["日永绣工，减却一线，节临短至。", "幸有杯盘，随分快乐，□得醺醺醉。", "寻思尘世，寒来暑往，冻极又还热炽。", "恰如个、脾家疟疾，比著略长些子。", "人生百岁，一年一发，且是不通医治。", "两鬓青丝，皆伊染就，今已星星地。", "除非炉内，龙盘虎绕，养得大丹神水。", "却从他、阴阳自变，卦分泰否。"]'),
('song-ci-120','鹊桥仙','史浩','宋','宋词','song-ci','鹊桥仙','[]','金乌玉兔，时当几望，只是光明相与。',68,'宋词/ci.song.8000.json','["金乌玉兔，时当几望，只是光明相与。", "天孙河鼓事应同，又启比、人间男女。", "精神契合，风云交际，不在一宵欢聚。", "乘槎曾得问星津，为我说、因缘如此。"]'),
('song-ci-121','瑞鹤仙','史浩','宋','宋词','song-ci','瑞鹤仙','[]','霁天风露好。',129,'宋词/ci.song.8000.json','["霁天风露好。", "乍暑退西郊，凉生秋早。", "银潢炯云杪。", "拥香车鹊翅，凌波初到。", "清歌缥缈。", "凭危阁、新蟾吐曜。", "有盈尊美酒，蛛丝钿合，拜舞竞分天巧。", "堪笑。", "世间痴绝，不识人中，拙是珍宝。", "多愁易老。", "都缘是，不闻道。", "骋些儿机智，遭他驱使，毕竟辛勤到了。", "又何如，百事无能，是非较少。"]'),
('song-ci-122','念奴娇','史浩','宋','宋词','song-ci','念奴娇','[]','碧天似水，看常娥摩出，一轮寒璧。',120,'宋词/ci.song.8000.json','["碧天似水，看常娥摩出，一轮寒璧。", "桂魄扶疏光照耀，尘界都成银色。", "万象森罗，羞明卷彩，黯淡唯今夕。", "风高露重，井梧湿翠时滴。", "谁信鹤发婆娑，鄮峰真隐，对影为三益。", "虎绕龙盘丹就后，一颗清辉的国。", "不养银蟾，不关玉兔，到处无亏蚀。", "三千行满，也能飞上璇极。"]'),
('song-ci-123','芰荷香','史浩','宋','宋词','song-ci','芰荷香','[]','过横塘。',120,'宋词/ci.song.8000.json','["过横塘。", "见红妆翠盖，柄柄擎香。", "月娥有意，暮霭收尽银潢。", "一轮高挂，且放同、千里清光。", "秋中气爽天凉。", "露凝玉臂，风拂云裳。", "老子通宵不忍睡，把青尊小酌，仍更思量。", "自家活计，幸有无限珍藏。", "大千世界，静极后、普现十方。", "圆明不损毫芒。", "精神会处，独坐胡床。"]'),
('song-ci-124','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','池台非雾。',54,'宋词/ci.song.8000.json','["池台非雾。", "缥缈双溪路。", "家在江南佳丽处。", "看取谢公风度。", "蟠桃酒酝千秋。", "金焦欲上迟留。", "笑待锦花裀上，双鸾舞彻梁州。"]'),
('song-ci-125','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','翠蛾雪柳。',54,'宋词/ci.song.8000.json','["翠蛾雪柳。", "鬓影春风透。", "灯火千门辉绮绣。", "移下一天星斗。", "剩拚连夜欢游。", "金波欲上迟留。", "且看香梅影底，双鸾舞彻梁州。"]'),
('song-ci-126','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','石头虎踞。',54,'宋词/ci.song.8000.json','["石头虎踞。", "骄虏何能渡。", "曾是六朝雄胜处。", "瑞绕碧江云路。", "当时霸国多贤。", "风流只解遗鞭。", "便好扬舲北伐，举头即见长安。"]'),
('song-ci-127','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','万花如绣。',54,'宋词/ci.song.8000.json','["万花如绣。", "淑景熏晴昼。", "一曲齐称千岁寿。", "欢拥两行红袖。", "当年西府横翔。", "急流稳上仙乡。", "笑阅磻溪日月，行看尚父鹰扬。"]'),
('song-ci-128','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','槐庭元老。',54,'宋词/ci.song.8000.json','["槐庭元老。", "四海真师表。", "曲为故人敦久要。", "隔巷不嫌时到。", "虚堂已入凉飔。", "一觥为寿何辞。", "看即关河恢复，千秋永辅淳熙。"]'),
('song-ci-129','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','当年桂籍。',54,'宋词/ci.song.8000.json','["当年桂籍。", "同展摩云翼。", "位冠洪枢情似昔。", "肯共一尊瑶席。", "经纶素韫胸中。", "筹帷小试成功。", "已殄黄池小丑，行收沙漠肤功。"]'),
('song-ci-130','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','吾皇睿哲。',54,'宋词/ci.song.8000.json','["吾皇睿哲。", "廷有真三杰。", "同向清时扬茂烈。", "掩迹皋陶夔契。", "联镳忽访山樊。", "凉生花底清尊。", "太史明朝日奏，台星皆聚柴门。"]'),
('song-ci-131','清平乐','史浩','宋','宋词','song-ci','清平乐','[]','南阳宾友。',54,'宋词/ci.song.8000.json','["南阳宾友。", "道旧须尊酒。", "一曲为公千岁寿。", "弦索春风纤手。", "忠谋黼黻明昌。", "英词锦绣甘肠。", "帝所盛推颇牧，人间尤重班扬。"]'),
('song-ci-132','朝中措','史浩','宋','宋词','song-ci','朝中措','[]','冻云著地静无风。',57,'宋词/ci.song.8000.json','["冻云著地静无风。", "簌蔌坠遥空。", "无限人间险秽，一时为尔包容。", "凭高试望，楼台改观，山径迷踪。", "唯有碧江千里，依然不住流东。"]'),
('song-ci-133','七娘子','史浩','宋','宋词','song-ci','七娘子','[]','东篱寿菊金犹浅。',71,'宋词/ci.song.8000.json','["东篱寿菊金犹浅。", "对南山、把酒开新宴。", "绛阙丛霄，玉书丹篆。", "坐间俱是神仙伴。", "童颜绿发何曾变。", "喜婴儿姹女交相恋。", "寄语诗翁，茱萸重看。", "明年此会人人健。"]'),
('song-ci-134','惜黄花','史浩','宋','宋词','song-ci','惜黄花','[]','秋光将老。',88,'宋词/ci.song.8000.json','["秋光将老。", "黄花开早。", "露浥清晓，金钱万叠犹小。", "簪遍碧云鬟，压倒乌纱帽。", "更把来、玉觞同釂。", "过□添炉鼎，朱颜愈少。", "壮道骨，长仙风，养成灵宝。", "今日去登高，谩说龙山好。", "悄不如、自家蓬岛。"]'),
('song-ci-135','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','翠馆银罂下紫清。',48,'宋词/ci.song.8000.json','["翠馆银罂下紫清。", "内家闻说庆嘉平。", "柳条萱草眼偏明。", "小阁数杯成酩酊，醒来不爱佩环声。", "为通幽梦到蓬瀛。"]'),
('song-ci-136','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','腊月正当三十夜，几人到此惺惺。',70,'宋词/ci.song.8000.json','["腊月正当三十夜，几人到此惺惺。", "一轮明月本圆明。", "朗然无挂碍，何用问前程。", "况有长生真秘□，岁华虽换休惊。", "但将歌酒乐升平。", "尘缘如未了，明日贺新正。"]'),
('song-ci-137','感皇恩','史浩','宋','宋词','song-ci','感皇恩','[]','结柳送穷文，驱傩吓鬼。',81,'宋词/ci.song.8000.json','["结柳送穷文，驱傩吓鬼。", "爆火熏天漫儿戏。", "自家炉鼎，有却冷清清地。", "腊月三十日，如何避。", "且与做些，神仙活计。", "铅汞收添结灵水。", "跳丸日月，一任东生西委。", "玉颜长向此，迎新岁。"]'),
('song-ci-138','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','梅萼冰融，柳丝金浅，绪风还报初春。',118,'宋词/ci.song.8000.json','["梅萼冰融，柳丝金浅，绪风还报初春。", "木君青旆，猎猎下苍旻。", "亲捧虚皇妙旨，将枯朽、咸与维新。", "须臾见，芳郊乐圃，生气遍无垠。", "青丝，行白玉，一杯介寿，红浪粼粼。", "便安排歌舞，蝶翅莺唇。", "别有神仙窟宅，乾坤内、充满氤氲。", "功成处，花开不老，酒熟镇甘醇。"]'),
('song-ci-139','扑胡蝶・扑蝴蝶','史浩','宋','宋词','song-ci','扑胡蝶・扑蝴蝶','[]','光阴转指。',93,'宋词/ci.song.8000.json','["光阴转指。", "百岁知能几。", "儿时童稚，老来将耄矣。", "就中些子强壮，又被浮名牵系。", "良辰尽成轻弃。", "此何理。", "若有惺惺活底，必解自为计。", "清尊在手，且须拚烂醉。", "醉乡不涉风波地。", "睡到花阴正午，笙歌又还催起。"]'),
('song-ci-140','蝶恋花','史浩','宋','宋词','song-ci','蝶恋花','[]','玉瓮新醅翻绿蚁。',70,'宋词/ci.song.8000.json','["玉瓮新醅翻绿蚁。", "滴滴真珠，便有香浮鼻。", "欲把盈尊成雅会。", "更须寻个无愁地。", "况是赏心多乐事。", "美景良辰，又复来相值。", "料得天家深有意。", "教人长寿花前醉。"]'),
('song-ci-141','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','自古圣贤皆寂寞，祗教饮者留名。',70,'宋词/ci.song.8000.json','["自古圣贤皆寂寞，祗教饮者留名。", "万花丛里酒如渑。", "池台仍旧贯，歌管有新声。", "欲识醉乡真乐地，全胜方丈蓬瀛。", "是非荣辱不关情。", "百杯须痛饮，一枕拚春酲。"]'),
('song-ci-142','粉蝶儿','史浩','宋','宋词','song-ci','粉蝶儿','[]','一盏阳和，分明至珍无价。',94,'宋词/ci.song.8000.json','["一盏阳和，分明至珍无价。", "解教人、囉哩哩囉。", "把胸中，些磊块，一时熔化。", "悟从前，恁区区，总成虚假。", "何妨竟夕，交酬玉觞金斝。", "更休辞、醉眠花下。", "待明朝，红日上，三竿方罢。", "引笙歌，拥珠玑，笑扶归马。"]'),
('song-ci-143','瑞鹤仙','史浩','宋','宋词','song-ci','瑞鹤仙','[]','瑞烟笼绣幕。',126,'宋词/ci.song.8000.json','["瑞烟笼绣幕。", "正玳席欢燕，觥筹交错。", "高情动寥廓。", "恣清谈雄辩，珠玑频落。", "锵锵妙乐。", "且赢取、升平快乐。", "又何辞、醉玉颓山，是处有人扶著。", "追念抟风微利，画饼浮名，久成离索。", "输忠素约。", "没材具，漫担阁。", "怅良辰美景，花前月下，空把欢游蹉却。", "到如今、对酒当歌，怎休领略。"]'),
('song-ci-144','永遇乐','史浩','宋','宋词','song-ci','永遇乐','[]','桃李繁华，芰荷清净，景物相继。',130,'宋词/ci.song.8000.json','["桃李繁华，芰荷清净，景物相继。", "霜后橙黄，雪中梅绽，迤逦春还至。", "寻思天气，寒暄凉燠，各有一时乐地。", "如何被、浮名牵役，此欢逐成抛弃。", "如今醒也，扁舟短棹，更有篮舆胡倚。", "到处为家，山肴社酒，野老为宾侣。", "三杯之后，吴歌楚舞，忘却曳金穿履。", "虽逢个、清朝贵客，也须共来一醉。"]'),
('song-ci-145','青玉案','史浩','宋','宋词','song-ci','青玉案','[]','闲忙两字无多子。',80,'宋词/ci.song.8000.json','["闲忙两字无多子。", "叹举世、皆由此。", "逐利争名忙者事。", "廛中得丧，仕中宠辱，无限非和是。", "谁人解识闲中味。", "雪月烟云自能致。", "世态只如风过耳。", "三杯两盏，眼朦胧地，长向花前醉。"]'),
('song-ci-146','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','和靖重湖，知章一曲，浙江左右为邻。',118,'宋词/ci.song.8000.json','["和靖重湖，知章一曲，浙江左右为邻。", "绣鞯彩舰，只许日寻春。", "正好厌厌夜饮，都寂静、没个游人。", "夫何故，欢阑兴阻，只为隔城闉。", "堪嘉，唯甬水，回环雉堞，中峙三神。", "更楼台缭岸，花柳迷津。", "不惜频添画烛，更深看、舞上华裀。", "拚沈醉，从他咿喔，金距报凌晨。"]'),
('song-ci-147','满庭芳','史浩','宋','宋词','song-ci','满庭芳','[]','柴作疏篱，茅编小屋，绕堤苦竹黄芦。',118,'宋词/ci.song.8000.json','["柴作疏篱，茅编小屋，绕堤苦竹黄芦。", "老翁蜗处，却自乐清虚。", "理钓何妨钩直，据琴又、不管弦无。", "逍遥处，都捐世虑，忘我亦忘渠。", "雨馀。", "添美景，眉横山妩，脸媚花腴。", "笑凡间粉黛，浓抹轻涂。", "客至三杯薄酒，欲眠后、一枕蘧蘧。", "起来见，龟翻鹤舞，却是寿星图。"]'),
('song-ci-148','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','曾向泗滨浮玉质，也居十二峰前。',70,'宋词/ci.song.8000.json','["曾向泗滨浮玉质，也居十二峰前。", "飞来藓发尚如拳，郁纷因出岫，巧镂是谁镌。", "挈榼凭栏成胜赏，老夫亦自颓然。", "坐疑霭霭上瑶天。", "已为苏旱雨，却放老龙眠。"]'),
('song-ci-149','好事近','史浩','宋','宋词','song-ci','好事近','[]','敧枕不成眠，得句十分清绝。',53,'宋词/ci.song.8000.json','["敧枕不成眠，得句十分清绝。", "一夜酸风阁花，酝江天飞雪。", "晓来的皪看枝头，老蚌剖明月。", "帝所待调金鼎，莫教人轻折。"]'),
('song-ci-150','好事近','史浩','宋','宋词','song-ci','好事近','[]','对竹擘吟笺，正是赏梅时节。',53,'宋词/ci.song.8000.json','["对竹擘吟笺，正是赏梅时节。", "便把这些清致，作东湖三绝。", "帝家金鼎待调羹，何似且休折。", "却爱玉楼清弄，褪霏霏香雪。"]'),
('song-ci-151','念奴娇','史浩','宋','宋词','song-ci','念奴娇','[]','银潢耿耿，正露零仙掌，尘空天幕。',120,'宋词/ci.song.8000.json','["银潢耿耿，正露零仙掌，尘空天幕。", "碧玉扶疏□万朵，偏称水村山郭。", "巧酝檀英，密包金粟，只待清秋著。", "三春桃李，自应束在高阁。", "好是月窟奇标，东堂幽韵，不管西风恶。", "独立盈盈回首笑，白苇丹枫索索。", "折向冰壶，莫教纱帽，醉里轻簪却。", "浓芳长在，□疑身在云壑。"]'),
('song-ci-152','念奴娇','史浩','宋','宋词','song-ci','念奴娇','[]','枝头蓓蕾，褪红绡微露，江南春色。',120,'宋词/ci.song.8000.json','["枝头蓓蕾，褪红绡微露，江南春色。", "多谢东风吹半朵，来入骚人瑶席。", "粉脸轻红，芳心羞吐，别有真消息。", "妆台帘卷，寿阳著意留得。", "好是雪满群山，玉纤频拈，泛清波文鹢。", "深院相逢人尽道，标格都从天锡。", "梦蝶徒劳，霜禽休妒，争奈伊怜惜。", "高楼谁倚，寄言休为横笛。"]'),
('song-ci-153','念奴娇','史浩','宋','宋词','song-ci','念奴娇','[]','银塘江上，展鲛绡初见，长天一色。',120,'宋词/ci.song.8000.json','["银塘江上，展鲛绡初见，长天一色。", "风拭菱花光照眼，谁许红尘轻积。", "转盼冯夷，奔云起电，两岸惊涛拍。", "振空破地，水龙争喷吟笛。", "客有步屧江干，胸吞奇观，寄英词元白。", "素壁淋浪翻醉墨，飘洒神仙踪迹。", "好待波匀，横飞小艇，快引香筒碧。", "烟消月出，不眠拚了通夕。"]'),
('song-ci-154','白苎','史浩','宋','宋词','song-ci','白苎','[]','腊天寒，晓风劲，幽香频吐。',151,'宋词/ci.song.8000.json','["腊天寒，晓风劲，幽香频吐。", "精神绰约，谁羡姑射居处。", "江南探春独步。", "恨无侣。", "微语。", "又谁管、雪势霜威埋妒。", "且图少陵东阁作诗苦。", "拟烦玉纤轻拗、宁相许。", "惜取。", "栏干遍倚，月淡黄昏，水边清浅，不放红尘染污。", "似名画手丹青，罢施缃素。", "不随艳卉，强媚韶光一瞬，飘荡无据。", "只恐金门，宝鼎方调，时时来觑。", "便把枝头，豆颗朝天去。"]'),
('song-ci-155','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','一握钩儿能几何。',48,'宋词/ci.song.8000.json','["一握钩儿能几何。", "弓弓珠蹙杏红罗。", "即时分惠谢奴哥。", "香压幽兰兰尚浅，样窥初月月仍多。", "只堪掌上恹琼波。"]'),
('song-ci-156','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','珠履三千巧斗妍。',48,'宋词/ci.song.8000.json','["珠履三千巧斗妍。", "就中弓窄只迁迁。", "恼伊剗袜转堪怜。", "舞罢有香留绣褥，步馀无迹在金莲。", "好随云雨楚峰前。"]'),
('song-ci-157','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','湿翠湖山收晚烟。',48,'宋词/ci.song.8000.json','["湿翠湖山收晚烟。", "月华如练水如天。", "兴来催上钓鱼船。", "青箬一尊汀草畔，霜筠数曲渚花边。", "更於何处觅神仙。"]'),
('song-ci-158','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','梁武憨痴达摩呆。',48,'宋词/ci.song.8000.json','["梁武憨痴达摩呆。", "个中消息岂容猜。", "九年面壁口慵开。", "双履却寻归路止，一花原不是君栽。", "这回枉了一遭来。"]'),
('song-ci-159','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','索得玄珠也是呆。',48,'宋词/ci.song.8000.json','["索得玄珠也是呆。", "人人有分莫胡猜。", "顶门一眼镇长开。", "路断玉关无辙迹，雪埋葱岭没根栽。", "始称达摩不曾来。"]'),
('song-ci-160','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','胜概朱楹俯碧湖。',48,'宋词/ci.song.8000.json','["胜概朱楹俯碧湖。", "萧萧风月一尘无。", "只堪绿蚁满尊浮。", "况是小春天正爽，杖藜相与探梅初。", "半皴枝上未成珠。"]'),
('song-ci-161','浣溪沙','史浩','宋','宋词','song-ci','浣溪沙','[]','远岫数堆苍玉髻。',48,'宋词/ci.song.8000.json','["远岫数堆苍玉髻。", "平湖千顷碧琉璃。", "笙歌催我上船时。", "载月有如浮玉鉴，采莲还复拥燕脂。", "更於何处觅瑶池。"]'),
('song-ci-162','武陵春','史浩','宋','宋词','song-ci','武陵春','[]','报道东皇初弭节，芳思满凌晨。',56,'宋词/ci.song.8000.json','["报道东皇初弭节，芳思满凌晨。", "争看钗头彩胜新。", "金字写宜春。", "四坐行盘堆白玉，纤手自和匀。", "恰似蟾宫妙丽人。", "将月出浮云。"]'),
('song-ci-163','千秋岁','史浩','宋','宋词','song-ci','千秋岁','[]','吾乡我里。',87,'宋词/ci.song.8000.json','["吾乡我里。", "偕老真无比。", "宴席展，欢声起。", "蕊宫仙子绕，玉砌莱衣戏。", "称贺处，眉心竞指朱书字。", "忆昔西周吕。", "年纪虽相似。", "独自个，谁为侣。", "如今双凤老，堪引同螺醉。", "彭祖寿，十分方一从头纪。"]'),
('song-ci-164','新荷叶','史浩','宋','宋词','song-ci','新荷叶','[]','真隐先生，家居近在东湖。',102,'宋词/ci.song.8000.json','["真隐先生，家居近在东湖。", "茅屋三椽，自有一种清虚。", "秫来酿酒，便无后、也解赊沽。", "只愁客至，不能拚此芳壶。", "且乐天真，醉乡里、无限欢娱。", "时倚花枝，困来著枕蘧蘧。", "回观昨梦，徒然使、心剿形癯。", "始知今日，得闲却是良图。"]'),
('song-ci-165','醉蓬莱','史浩','宋','宋词','song-ci','醉蓬莱','[]','喜泉通碧甃。',120,'宋词/ci.song.8000.json','["喜泉通碧甃。", "秫刈黄云，酿成芳酎。", "瑞霭凝香，更阳和锺秀。", "晓瓮寒光，夜槽清响，听颔珠频溜。", "昼锦堂深，聚星筵启，一觥为寿。", "况此神仙，蕊宫俦侣，玉殿英游，尽皆亲旧。", "赢得开怀，对良辰握手。", "醉席淋漓笑语，都不问、欲残更漏。", "绣幕春风，轻丝美韵，明朝还又。"]'),
('song-ci-166','瑶台第一层','史浩','宋','宋词','song-ci','瑶台第一层','[]','寥廓澄清。',121,'宋词/ci.song.8000.json','["寥廓澄清。", "人正在、瑶台第一层。", "瑞霭深处，蕊宫掩映，金碧觚棱。", "异花非世种，蔼剩馥、紫雾飞腾。", "有仙驾，过吾庐环堵，少驻云軿。", "俄惊。", "重壶叠巘，顿然潇洒俗尘清。", "佩环声里，宝觥潋滟，舞态娉婷。", "祝言千岁寿，仍更予、五福川增。", "返蓬瀛。", "问今朝兹会，昔日谁曾。"]'),
('song-ci-167','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','摘索衣裳宫样。',40,'宋词/ci.song.8000.json','["摘索衣裳宫样。", "生得脸儿福相。", "容止忒精神，一似观音形像。", "归向。", "归向。", "见者擎拳合掌。"]'),
('song-ci-168','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','粉脸霞生一缕。',40,'宋词/ci.song.8000.json','["粉脸霞生一缕。", "掩映绿云秋水。", "言语更雍容，具足十分娇美。", "无比。", "无比。", "要比除非镜里。"]'),
('song-ci-169','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','红杏白梨肌理。',40,'宋词/ci.song.8000.json','["红杏白梨肌理。", "时样新妆淡伫。", "真个是观音，少个杨枝净水。", "欢喜。", "欢喜。", "尽此一锺醇美。"]'),
('song-ci-170','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','罗袜半钩新月。',40,'宋词/ci.song.8000.json','["罗袜半钩新月。", "更把凤鞋珠结。", "步步著金莲，行得轻轻瞥瞥。", "难说。", "难说。", "真是世间奇绝。"]'),
('song-ci-171','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','试把珠帘低卷。',40,'宋词/ci.song.8000.json','["试把珠帘低卷。", "宛见梅妆粉面。", "绿绕更红围，齐捧瑶卮来劝。", "堪羡。", "堪羡。", "此是神仙阆苑。"]'),
('song-ci-172','如梦令','史浩','宋','宋词','song-ci','如梦令','[]','一笑尊前相语。',40,'宋词/ci.song.8000.json','["一笑尊前相语。", "莫遣良辰虚度。", "饮兴正浓时，兔碗聊分春露。", "留住。", "留住。", "催办后筵歌舞。"]'),
('song-ci-173','南歌子','史浩','宋','宋词','song-ci','南歌子','[]','藻涧蟾光动，松风蟹眼鸣。',62,'宋词/ci.song.8000.json','["藻涧蟾光动，松风蟹眼鸣。", "浓熏沈麝入金瓶。", "泻出温温一盏、涤烦膺。", "爽继云龙饼，香无芝术名。", "主人襟韵有馀清。", "不向今宵忘了、淡交情。"]'),
('song-ci-174','画堂春','史浩','宋','宋词','song-ci','画堂春','[]','小槽春酿香红。',58,'宋词/ci.song.8000.json','["小槽春酿香红。", "良辰飞盖相从。", "主人着意在金钟。", "茗碗作先容。", "欲到醉乡深处，应须仗、两腋香风。", "献酬高兴渺无穷。", "归骑莫匆匆。"]'),
('song-ci-175','杏花天','史浩','宋','宋词','song-ci','杏花天','[]','梦魂飞过屏山曲。',65,'宋词/ci.song.8000.json','["梦魂飞过屏山曲。", "见依旧、如花似玉。", "天寒翠袖依修竹。", "两点春山斗绿。", "披衣起、闲愁万斛。", "正月澹、梅花照屋。", "重温绣被薰清馥。", "不管明烧画烛。"]'),
('song-ci-176','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','忆昔来时双髻小，如今云鬓堆鸦。',70,'宋词/ci.song.8000.json','["忆昔来时双髻小，如今云鬓堆鸦。", "绿窗冉冉度年华。", "秋波娇殢酒，春笋惯分茶。", "居士近来心绪懒，不堪老眼看花。", "画堂明月隔天涯。", "春风吹柳絮，知是落谁家。"]'),
('song-ci-177','临江仙','史浩','宋','宋词','song-ci','临江仙','[]','试凭阑干春欲暮，桃花点点胭脂。',70,'宋词/ci.song.8000.json','["试凭阑干春欲暮，桃花点点胭脂。", "故山凝望水云迷。", "数堆苍玉髻，千顷碧琉璃。", "我本清都闲散客，蓬莱未是幽奇。", "明朝归去鹤齐飞。", "三山乘缥缈，海运到天池。"]'),
('song-ci-178','忆王孙','仲并','宋','宋词','song-ci','忆王孙','[]','庭梧叶密未惊秋。',36,'宋词/ci.song.8000.json','["庭梧叶密未惊秋。", "风雨潇潇特地愁。", "愁绪如丝无尽头。", "思悠悠。", "怅望王孙空倚楼。"]'),
('song-ci-179','点绛唇','仲并','宋','宋词','song-ci','点绛唇','[]','秀出群儿，柳眉濯濯春庭院。',50,'宋词/ci.song.8000.json','["秀出群儿，柳眉濯濯春庭院。", "不亲歌扇。", "弄笔勤书篆。", "翁已无能，老退惭赪面。", "欣同宴。", "坐来喜见。", "痛饮惊无算。"]'),
('song-ci-180','浣溪沙','仲并','宋','宋词','song-ci','浣溪沙','[]','举案家风未肯低。',48,'宋词/ci.song.8000.json','["举案家风未肯低。", "清心端自秀深闺。", "芝兰玉树宁馨儿。", "早岁安禅灵照女，静中经卷手常携。", "声名要与断机齐。"]'),
('song-ci-181','浣溪沙','仲并','宋','宋词','song-ci','浣溪沙','[]','雅称诗人美孟都。',48,'宋词/ci.song.8000.json','["雅称诗人美孟都。", "清新幽韵比来无。", "新来学得绣工夫。", "经卷但知从阿母，醉来翁已要人扶。", "尚能把盏劝屠苏。"]'),
('song-ci-182','浣溪沙','仲并','宋','宋词','song-ci','浣溪沙','[]','说似当年老季伦。',48,'宋词/ci.song.8000.json','["说似当年老季伦。", "君家虽富客常贫。", "何曾一笑任吾真。", "酒满罢留天下士，词新空赋坐中春。", "谁能绝笔更书麟。"]'),
('song-ci-183','菩萨蛮','仲并','宋','宋词','song-ci','菩萨蛮','[]','宛如姑射人冰雪。',52,'宋词/ci.song.8000.json','["宛如姑射人冰雪。", "知公不负佳风月。", "莫放漏声残。", "清风生坐间。", "赏春心未足。", "翦尽尊前烛。", "此乐自难忘。", "一觞还一觞。"]'),
('song-ci-184','好事近','仲并','宋','宋词','song-ci','好事近','[]','二陆起云间，千载风流人物。',53,'宋词/ci.song.8000.json','["二陆起云间，千载风流人物。", "未似一门三凤，向层霄联翼。", "贞元朝士苦无多，公今未华发。", "重向紫宸朝路，立鹓鸾前列。"]'),
('song-ci-185','好事近','仲并','宋','宋词','song-ci','好事近','[]','今古满胸中，韬略一时人杰。',53,'宋词/ci.song.8000.json','["今古满胸中，韬略一时人杰。", "高卧溪山好处，迟十年斋钺。", "朱轓休傍武陵溪，梅花记曾别。", "早晚殿前归侍，总周庐千列。"]'),
('song-ci-186','好事近','仲并','宋','宋词','song-ci','好事近','[]','淮上五分符，名在图书东壁。',53,'宋词/ci.song.8000.json','["淮上五分符，名在图书东壁。", "坐对书成多暇，写青箱千帙。", "一杯先为祝东风，丹诏来朝夕。", "何处称公挥翰，定北扉西掖。"]'),
('song-ci-187','好事近','仲并','宋','宋词','song-ci','好事近','[]','阀阅盛中州，冠冕共推华族。',53,'宋词/ci.song.8000.json','["阀阅盛中州，冠冕共推华族。", "耐久松筠交契，更襟怀金玉。", "诸儒皆自愧卢前，小试暂符竹。", "行看世官入践，继西枢前躅。"]'),
('song-ci-188','好事近','仲并','宋','宋词','song-ci','好事近','[]','分手又三秋，犹记花时歌别。',53,'宋词/ci.song.8000.json','["分手又三秋，犹记花时歌别。", "每念征帆归晚，误五湖风月。", "清江休望使君来，指日趋天阙。", "婿玉翁冰相映，看紫薇花发。"]'),
('song-ci-189','好事近','仲并','宋','宋词','song-ci','好事近','[]','襟韵绝纤尘，炯炯夜光明月。',53,'宋词/ci.song.8000.json','["襟韵绝纤尘，炯炯夜光明月。", "合是紫荷持橐，侍丹墀清切。", "暗香疏影想公家，人与梅超绝。", "酒罢帝城早去，占百花先发。"]'),
('song-ci-190','好事近','仲并','宋','宋词','song-ci','好事近','[]','今雨几人来，冰霰更凝寒色。',53,'宋词/ci.song.8000.json','["今雨几人来，冰霰更凝寒色。", "门外车多长者，顿光生蓬荜。", "缤纷飞雪更初梅，特特为留客。", "惟恨坐无华馔，只平时真率。"]'),
('song-ci-191','忆秦娥','仲并','宋','宋词','song-ci','忆秦娥','[]','隈岩侧。',56,'宋词/ci.song.8000.json','["隈岩侧。", "怪生小院香来别。", "香来别。", "嫩黄细细，商量齐发。", "佳人敛笑贪先折。", "重新为翦斜斜叶。", "斜斜叶。", "钗头常带，一秋风月。"]'),
('song-ci-192','画堂春','仲并','宋','宋词','song-ci','画堂春','[]','春波浅碧涨方池。',55,'宋词/ci.song.8000.json','["春波浅碧涨方池。", "池台深锁烟霏。", "缓歌争胜早莺啼。", "客忍轻归。", "合坐香凝宿雾，垫巾梅插寒枝。", "渐西蟾影漾馀辉。", "醉倒谁知。"]'),
('song-ci-193','大圣乐令・玉团儿','仲并','宋','宋词','song-ci','大圣乐令・玉团儿','[]','豆蔻梢头春正早。',64,'宋词/ci.song.8000.json','["豆蔻梢头春正早。", "敛修眉、未经重扫。", "湖山清远，几年牢落，风韵初好。", "慢绾垂螺最娇小。", "是谁家、舞腰袅袅。", "而今莫谓，春归等闲，分付芳草。"]'),
('song-ci-194','浪淘沙','仲并','宋','宋词','song-ci','浪淘沙','[]','趁拍舞初筵。',64,'宋词/ci.song.8000.json','["趁拍舞初筵。", "柳袅春烟。", "街头桃李莫争妍。", "家本凤楼高处住，锦瑟华年。", "不用抹繁弦。", "歌韵天然。", "天教独立百花前。", "但愿人如天上月，三五团圆。"]'),
('song-ci-195','浪淘沙','仲并','宋','宋词','song-ci','浪淘沙','[]','倾国与倾城。',64,'宋词/ci.song.8000.json','["倾国与倾城。", "袅袅盈盈。", "歌喉巧作断肠声。", "看尽风光花不语，却是多情。", "家近董双成。", "三妙齐名。", "谁教蜂蝶漫经营。", "留取无双风味在，真是琼英。"]'),
('song-ci-196','浪淘沙','仲并','宋','宋词','song-ci','浪淘沙','[]','草圣与诗馀。',64,'宋词/ci.song.8000.json','["草圣与诗馀。", "清韵谁如。", "生绡团扇倩谁书。", "月湛素华天似水，深院凉初。", "人散晚钟疏。", "后约还虚。", "良宵忍放枕鸾孤。", "要得相逢除是梦，有梦来无。"]'),
('song-ci-197','鹧鸪天','仲并','宋','宋词','song-ci','鹧鸪天','[]','小泊横塘日欲斜。',64,'宋词/ci.song.8000.json','["小泊横塘日欲斜。", "一枝犹有未残花。", "几年燕子无消息，今日飞来王谢家。", "歌水调，韵琵琶。", "声声都是怨年华。", "钗头杏子今如许，翦烛裁诗莫问他。"]'),
('song-ci-198','鹧鸪天','仲并','宋','宋词','song-ci','鹧鸪天','[]','间世麒麟降自天。',64,'宋词/ci.song.8000.json','["间世麒麟降自天。", "光辉列宿灿初躔。", "他年身致夔龙列，少日心存翰墨边。", "簪彩笔，照金莲。", "词华当使思如泉。", "未论耸壑昂霄事，且与衰翁慰暮年。"]'),
('song-ci-199','蓦山溪','仲并','宋','宋词','song-ci','蓦山溪','[]','冰清玉映，自是闺房秀。',102,'宋词/ci.song.8000.json','["冰清玉映，自是闺房秀。", "十里卷朱帘，好紫陌、家家未有。", "天然情素，高压一城春，花艳丽，月精神，梅韵腰枝瘦。", "曲屏虚幌，枉著鸳鸯绣。", "不是不相逢，泪空滴、年年别袖。", "从他兰菊，秋露与春风，终不似，玉人人，一片心长久。"]'),
('song-ci-200','水调歌头','仲并','宋','宋词','song-ci','水调歌头','[]','华栋一何丽，移下小壶天。',114,'宋词/ci.song.8000.json','["华栋一何丽，移下小壶天。", "几多曲房新户，缥缈似当年。", "曾是使君风度，元有胸中丘壑，六月竹风寒。", "一洗筝笛耳，歌舞粲筵间。", "坐中客，醒复醉，听无眠。", "已回归梦，犹复袅袅记清圆。", "尚想饮中仙子，来处馀香飘坐，胜韵此双全。", "为寄月华语，难与并蝉娟。"]'),
('song-ci-201','芰荷香','仲并','宋','宋词','song-ci','芰荷香','[]','醉凝眸。',119,'宋词/ci.song.8000.json','["醉凝眸。", "正行云遮断，澄练江头。", "皓月今宵何处，不管中秋。", "朱阑倚遍，又微雨、催下危楼。", "秋风空响更筹。", "不将好梦，吹过南州。", "浮远轩窗异日到，山空云净，江远天浮。", "别去客怀，无赖准拟开愁。", "冰轮好在，解随我、天际归舟。", "何须舞袂歌喉。", "一觞一咏，谈笑风流。"]'),
('song-ci-202','八声甘州','仲并','宋','宋词','song-ci','八声甘州','[]','正西山、雨过弄晴景，竹屋贯斜晖。',119,'宋词/ci.song.8000.json','["正西山、雨过弄晴景，竹屋贯斜晖。", "问谁将千斛，霏瑛落屑，吹上花枝。", "风外青鞋未熟，鼻观已先知。", "扰损江南客，诗面难肥。", "两句林边倾盖，笑化工开落，尤甚儿嬉。", "叹额黄人去，还是隔年期。", "渺飞魂、凭谁招取，赖故人、沈水煮花瓷。", "犹堪待，岭梅开后，一战雄雌。"]'),
('song-ci-203','念奴娇','仲并','宋','宋词','song-ci','念奴娇','[]','灰飞嶰竹。',120,'宋词/ci.song.8000.json','["灰飞嶰竹。", "庆群阴消尽，新阳来复。", "云物呈祥连瑞霭，烟气纷纷馥馥。", "紫陌香衢，朱檐影里，罗绮花成簇。", "岭梅惊暖，数枝争绽寒玉。", "有人袅袅盈盈，今朝特地，为我新妆束。", "娇倚银床添绣线，长喜修眉舒绿。", "不道多情，锦屏罗幌，难得欢生足。", "谁知今夜，玉壶银漏催促。"]'),
('song-ci-204','念奴娇','仲并','宋','宋词','song-ci','念奴娇','[]','江南春早，尚馀寒门巷，杨花飘逐。',120,'宋词/ci.song.8000.json','["江南春早，尚馀寒门巷，杨花飘逐。", "一色初梅开尽也，不数芳园红绿。", "珍重骚人，幽怀分寄，高韵歌黄竹。", "六花羞避，满笺凌乱琼玉。", "应念有客长安，履穿东郭，无与怜穷独。", "鼓棹前溪非兴尽，寒怯水栖岩宿。", "咫尺君家，瑶田无径，冰柱排银屋。", "瓮头春到，唤回晚梦清熟。"]'),
('song-ci-205','念奴娇','仲并','宋','宋词','song-ci','念奴娇','[]','金滕事业。',120,'宋词/ci.song.8000.json','["金滕事业。", "庆丹青千载，勋在王室。", "圣主英明平万国，天产非常人物。", "岳渎分灵，熊罴符梦，五百年方出。", "致君尧舜，要须纯用经术。", "须信凤阁仙人，风流文采，蔼家声如昔。", "献纳司存持禁橐，合历三台清秩。", "倦宿承明，乞麾临郡，暂辍金闺直。", "五云深处，一星今在南极。"]'),
('song-ci-206','瑞鹤仙','仲并','宋','宋词','song-ci','瑞鹤仙','[]','试六花院落。',127,'宋词/ci.song.8000.json','["试六花院落。", "正柳绵飘坠，因风无著。", "吴王旧城郭。", "记乌衣门巷，小桥帘幕。", "他州寥索。", "漫等闲、桃英杏萼。", "认幽香来处，群芳尽掩，蕙心先觉。", "行乐。", "燕雏莺友，浪语狂歌，休休莫莫。", "兰房绣幄。", "添新恨，念前约。", "殢十分芳景，十分春意，休惜十分共酌。", "任十分、吹老寒梅，戌楼画角。"]'),
('song-ci-207','水调歌头','仲并','宋','宋词','song-ci','水调歌头','[]','静练平千顷，华栋俯中流。',114,'宋词/ci.song.8000.json','["静练平千顷，华栋俯中流。", "凌晨画戟，来看宿雨断虹收。", "八九胸中云梦，三千笔端风月，无处快凝眸。", "笑咏一堂上，挥麈气横秋。", "俯危阑，红日下，暮云稠。", "无穷伟观，祗应天意为君谋。", "容我时醒时醉，独泛微烟微雨，浩荡逐轻鸥。", "不羡岳阳胜，丹碧耸层楼。"]'),
('song-ci-208','念奴娇','仲并','宋','宋词','song-ci','念奴娇','[]','练江风静，卧冰奁百尺，朱阑飞入。',120,'宋词/ci.song.8000.json','["练江风静，卧冰奁百尺，朱阑飞入。", "江远浮天天在水，水满半天云湿。", "白鸟明边，青山断处，眼冷江头立。", "月明潮上，苇间渔唱声急。", "几度吹老苹花，野香无数，欲寄应难及。", "天借诗人供醉眼，尊俎一时收拾。", "竹里行厨，花间步障，风雨生呼吸。", "酒阑歌罢，钓船先具蓑笠。"]'),
('song-ci-209','画堂春','仲并','宋','宋词','song-ci','画堂春','[]','溪边风物已春分。',55,'宋词/ci.song.8000.json','["溪边风物已春分。", "画堂烟雨黄昏。", "水沈一缕袅炉薰。", "尽醉芳尊。", "舞袖飘摇回雪，歌喉宛转留云。", "人间能得几回闻。", "丞相休嗔。"]'),
('song-ci-210','浣溪沙','仲并','宋','宋词','song-ci','浣溪沙','[]','清远湖山佳丽人。',48,'宋词/ci.song.8000.json','["清远湖山佳丽人。", "柳边花下复清晨。", "向前犹有几多春。", "祓禊秋千时节近，管弦歌舞一回新。", "未嗔狂客污车茵。"]'),
('song-ci-211','眼儿媚','仲并','宋','宋词','song-ci','眼儿媚','[]','铃阁寻盟未肯寒。',58,'宋词/ci.song.8000.json','["铃阁寻盟未肯寒。", "鹢首驻江干。", "云烟翰墨，风流尊俎，不放更残。", "金声掷地西清老，天未许终闲。", "知音素赏，当筵一曲，流水高山。"]'),
('song-ci-212','武陵春','仲并','宋','宋词','song-ci','武陵春','[]','门巷乌衣应好在，风韵尚依然。',56,'宋词/ci.song.8000.json','["门巷乌衣应好在，风韵尚依然。", "知是蓬瀛第几仙。", "秀色粲当筵。", "索句濡毫云阁里，清坐袅炉烟。", "谁赋回文第二篇。", "除是见娟娟。"]'),
('song-ci-213','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','一湖春水夜来生。',32,'宋词/ci.song.8000.json','["一湖春水夜来生。", "几叠春山远更横。", "烟艇小，钓丝轻。", "赢得闲中万古名。"]'),
('song-ci-214','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','薄晚烟林澹翠微。',32,'宋词/ci.song.8000.json','["薄晚烟林澹翠微。", "江边秋月已明晖。", "纵远舵，适天机。", "水底闲云片段飞。"]'),
('song-ci-215','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','云洒清江江上船。',32,'宋词/ci.song.8000.json','["云洒清江江上船。", "一钱何得买江天。", "催短棹，去长川。", "鱼蟹来倾酒舍烟。"]'),
('song-ci-216','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','青草开时已过船。',32,'宋词/ci.song.8000.json','["青草开时已过船。", "锦鳞跃处浪痕圆。", "竹叶酒，柳花毡。", "有意沙鸥伴我眠。"]'),
('song-ci-217','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','扁舟小缆荻花风。',32,'宋词/ci.song.8000.json','["扁舟小缆荻花风。", "四合青山暮霭中。", "明细火，倚孤松。", "但愿尊中酒不空。"]'),
('song-ci-218','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','侬家活计岂能明。',32,'宋词/ci.song.8000.json','["侬家活计岂能明。", "万顷波心月影清。", "倾绿酒，糁藜羹。", "保任衣中一物灵。"]'),
('song-ci-219','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','骇浪吞舟脱巨鳞。',32,'宋词/ci.song.8000.json','["骇浪吞舟脱巨鳞。", "结绳为网也难任。", "纶乍放，饵初沈。", "浅钓纤鳞味更深。"]'),
('song-ci-220','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','鱼信还催花信开。',32,'宋词/ci.song.8000.json','["鱼信还催花信开。", "花风得得为谁来。", "舒柳眼，落梅腮。", "浪暖桃花夜转雷。"]'),
('song-ci-221','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','暮暮朝朝冬复春。',32,'宋词/ci.song.8000.json','["暮暮朝朝冬复春。", "高车驷马趁朝身。", "金拄屋，粟盈囷。", "那知江汉独醒人。"]'),
('song-ci-222','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','远水无涯山有邻。',32,'宋词/ci.song.8000.json','["远水无涯山有邻。", "相看岁晚更情亲。", "笛里月，酒中身。", "举头无我一般人。"]'),
('song-ci-223','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','谁云渔父是愚翁。',32,'宋词/ci.song.8000.json','["谁云渔父是愚翁。", "一叶浮家万虑空。", "轻破浪，细迎风。", "睡起篷窗日正中。"]'),
('song-ci-224','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','水涵微雨湛虚明。',32,'宋词/ci.song.8000.json','["水涵微雨湛虚明。", "小笠轻蓑未要晴。", "明鉴里，縠纹生。", "白鹭飞来空外声。"]'),
('song-ci-225','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','无数菰蒲间藕花。',32,'宋词/ci.song.8000.json','["无数菰蒲间藕花。", "棹歌轻举酌流霞。", "随家好，转山斜。", "也有孤村三两家。"]'),
('song-ci-226','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','春入渭阳花气多。',32,'宋词/ci.song.8000.json','["春入渭阳花气多。", "春归时节自清和。", "冲晓雾，弄沧波。", "载与俱归又若何。"]'),
('song-ci-227','渔父词・渔父','赵构','宋','宋词','song-ci','渔父词・渔父','[]','清湾幽岛任盘纡。',32,'宋词/ci.song.8000.json','["清湾幽岛任盘纡。", "一舸横斜得自如。", "惟有此，更无居。", "从教红袖泣前鱼。"]'),
('song-ci-228','失调名','崔若砺','宋','宋词','song-ci','失调名','[]','愁殢有兵尊，老怕能言李。',12,'宋词/ci.song.8000.json','["愁殢有兵尊，老怕能言李。"]'),
('song-ci-229','多丽','高登','宋','宋词','song-ci','多丽','[]','人间世，偶然攘臂来游。',170,'宋词/ci.song.8000.json','["人间世，偶然攘臂来游。", "何须恁、乾坤角抵，又成冷笑俳优。", "且宽心、待他天命，谩鼓舌、夸吾人谋。", "李广不侯，刘蕡未第，千年公论合谁羞。", "往矣瓦飘无意，甑堕懒回头。", "真堪笑，直钩论议，圆枘机筹。", "幸斯道、元无得丧，壮心岂有沈浮。", "好温存、困中节概，莫冷落、穷里风流。", "酒滴珍珠，饭钞云子，醉饱卧信缘休。", "归去也，幅巾谈笑，卒岁且优游。", "循环事，亡羊须在，失马何忧。"]'),
('song-ci-230','阮郎归','高登','宋','宋词','song-ci','阮郎归','[]','武仙花县谒凫仙。',56,'宋词/ci.song.8000.json','["武仙花县谒凫仙。", "急招横渡船。", "重门昼掩讼庭闲。", "虚檐群雀喧。", "金屋畔，玉阑边。", "新春桃李妍。", "主人情重客无缘。", "销魂空黯然。"]'),
('song-ci-231','蓦山溪','高登','宋','宋词','song-ci','蓦山溪','[]','黄茅时节，病恼南来客。',102,'宋词/ci.song.8000.json','["黄茅时节，病恼南来客。", "瘦得不胜衣，试腰围、都无一搦。", "东篱兴在，手种菊方黄，摘晚艳，泛新蒭，谁道乾坤窄。", "百年役役，乐事真难得。", "短发已无多，更何劳、霜风染白。", "儿曹齐健，扶□一翁孱，龙山帽，习池巾，归路从敧侧。"]'),
('song-ci-232','行香子','高登','宋','宋词','song-ci','行香子','[]','瘴气如云。',84,'宋词/ci.song.8000.json','["瘴气如云。", "暑气如焚。", "病轻时、也是十分。", "沈疴恼客，罪罟萦人。", "叹槛中猿，笼中鸟，辙中鳞。", "休负文章，休说经纶。", "得生还、已早因循。", "菱花照影，筇竹随身。", "奈沈郎尩，潘郎老，阮郎贫。"]'),
('song-ci-233','渔家傲','高登','宋','宋词','song-ci','渔家傲','[]','名利场中空扰扰。',72,'宋词/ci.song.8000.json','["名利场中空扰扰。", "十年南北东西道。", "依旧缘山尘扑帽。", "空懊恼。", "羡他陶令归来早。", "归去来兮秋已杪。", "菊花又绕东篱好。", "有酒一尊开口笑。", "虽然老。", "玉山犹解花前倒。"]'),
('song-ci-234','好事近','高登','宋','宋词','song-ci','好事近','[]','潇洒带霜枝，独向岁寒时节。',53,'宋词/ci.song.8000.json','["潇洒带霜枝，独向岁寒时节。", "触目千林憔悴，更幽姿清绝。", "多才应赋得天真，落笔惊风叶。", "从此绿窗深处，有一梢秋月。"]'),
('song-ci-235','好事近','高登','宋','宋词','song-ci','好事近','[]','送客过江村，况值重阳佳节。',53,'宋词/ci.song.8000.json','["送客过江村，况值重阳佳节。", "向晚西风萧瑟，正离人愁绝。", "尊前相顾惜参商，引十分蕉叶。", "回首高阳人散，负西楼风月。"]'),
('song-ci-236','好事近','高登','宋','宋词','song-ci','好事近','[]','饮兴正阑珊，正是挥毫时节。',53,'宋词/ci.song.8000.json','["饮兴正阑珊，正是挥毫时节。", "霜乾银钩锦句，看壁间三绝。", "西风特地飒秋声，楼外触残叶。", "匹马翩然归去，向征鞍敲月。"]'),
('song-ci-237','浪淘沙','高登','宋','宋词','song-ci','浪淘沙','[]','璧月挂秋宵。',64,'宋词/ci.song.8000.json','["璧月挂秋宵。", "丹桂香飘。", "广寒宫殿路迢迢。", "试问嫦娥缘底事，欲下层霄。", "兰玉自垂髫。", "拜命当朝。", "神仙会里且逍遥。", "分取壶中闲日月，来伴王乔。"]'),
('song-ci-238','西江月','高登','宋','宋词','song-ci','西江月','[]','渺渺西江流水，翩翩北客征帆。',58,'宋词/ci.song.8000.json','["渺渺西江流水，翩翩北客征帆。", "清秋月影浸人寒。", "云净碧天澄淡。", "飘泊道途零落，疏慵鬓发䰐鬖。", "从来涉世戒三缄。", "只好随时饮啖。"]'),
('song-ci-239','南歌子','高登','宋','宋词','song-ci','南歌子','[]','菊拈黄金嫩，杯倾琥珀浓。',62,'宋词/ci.song.8000.json','["菊拈黄金嫩，杯倾琥珀浓。", "良辰何处寄萍踪。", "短艇飘摇一叶、浪花中。", "凤阙游娃馆，幽坡赏梵宫。", "当年乐事总成空。", "目断天边想像、意何穷。"]'),
('song-ci-240','好事近','高登','宋','宋词','song-ci','好事近','[]','富贵本无心，何事故乡轻别。',53,'宋词/ci.song.8000.json','["富贵本无心，何事故乡轻别。", "空惹猿惊鹤怨，误松萝风月。", "囊锥刚强出头来，不道甚时节。", "欲命巾车归去，恐豺狼当辙。"]'),
('song-ci-241','菩萨蛮','闻人武子','宋','宋词','song-ci','菩萨蛮','[]','晴风吹暖枝头雪。',52,'宋词/ci.song.8000.json','["晴风吹暖枝头雪。", "露华香沁庭中月。", "屏上小江南。", "雨昏天际帆。", "翠钗香雾湿。", "侧鬓云松立。", "灯背欲眠时。", "晓莺还又啼。"]'),
('song-ci-242','桂华明・四犯令','关注','宋','宋词','song-ci','桂华明・四犯令','[]','缥缈神京开洞府。',60,'宋词/ci.song.8000.json','["缥缈神京开洞府。", "遇广寒宫女。", "问我双鬟梁溪舞。", "还记得、当时否。", "碧玉词章教仙侣。", "为按歌宫羽。", "皓月满窗人何处。", "声永断、瑶台路。"]'),
('song-ci-243','水调歌头','关注','宋','宋词','song-ci','水调歌头','[]','凤舞龙蟠处，玉室与金堂。',114,'宋词/ci.song.8000.json','["凤舞龙蟠处，玉室与金堂。", "平生想望真境，依约在何方。", "谁信许君丹灶，便与吴君遗剑，只在洞天傍。", "若要安心地，便是远名场。", "几年来，开林麓，建山房。", "安眠饱馆清坐，无事可思量。", "洗尽人间忧患，看尽仙家风月，和气满清扬。", "一笑尘埃外，云水远相忘。"]'),
('song-ci-244','剔银灯','关注','宋','宋词','song-ci','剔银灯','[]','小院烟凉雨细。',92,'宋词/ci.song.8000.json','["小院烟凉雨细。", "正好恹恹春睡。", "蓦被金枝，连推绣枕，报道皇都书至。", "良人得意。", "集英殿、首攀仙桂。", "斗帐重襟惊起。", "斜倚屏山偷喜。", "宝髻慵梳，香笺折破，果见中、高高名第。", "秦楼十二。", "知他向、谁家沈醉。"]'),
('song-ci-245','如梦令','李石','宋','宋词','song-ci','如梦令','[]','桥上水光浮雪。',40,'宋词/ci.song.8000.json','["桥上水光浮雪。", "桥下柳阴遮月。", "梦里去寻香，露冷五更时节。", "胡蝶。", "胡蝶。", "飞过闲红千叶。"]'),
('song-ci-246','如梦令','李石','宋','宋词','song-ci','如梦令','[]','忆被金尊劝倒。',40,'宋词/ci.song.8000.json','["忆被金尊劝倒。", "灯下红香围绕。", "别后有谁怜，一任春残莺老。", "烦恼。", "烦恼。", "肠断绿杨芳草。"]'),
('song-ci-247','生查子','李石','宋','宋词','song-ci','生查子','[]','小桃小杏红，和雨和烟瘦。',48,'宋词/ci.song.8000.json','["小桃小杏红，和雨和烟瘦。", "不是点燕脂，素面偏宜酒。", "也是惯伤春，可惜闲时候。", "正要画眉人，与作双蛾斗。"]'),
('song-ci-248','生查子','李石','宋','宋词','song-ci','生查子','[]','新花上苑枝，枝上娇莺语。',48,'宋词/ci.song.8000.json','["新花上苑枝，枝上娇莺语。", "日日抱花心，啄破燕脂雨。", "莺飞莺去时，谁与花为主。", "守等却飞来，再见花开处。"]'),
('song-ci-249','生查子','李石','宋','宋词','song-ci','生查子','[]','今年花发时，燕子双双语。',48,'宋词/ci.song.8000.json','["今年花发时，燕子双双语。", "谁与卷珠帘，人在花间住。", "明年花发时，燕语人何处。", "且与寄书来，人往江南去。"]'),
('song-ci-250','生查子','李石','宋','宋词','song-ci','生查子','[]','荷花人面红，月影波心见。',48,'宋词/ci.song.8000.json','["荷花人面红，月影波心见。", "扇子倒拈来，敲落红香片。", "窗下翦灯花，今日眉深浅。", "留得镜中看，蹙破春山远。"]'),
('song-ci-251','捣练子','李石','宋','宋词','song-ci','捣练子','[]','斟别酒，问东君。',48,'宋词/ci.song.8000.json','["斟别酒，问东君。", "一年一度一回新。", "看百花，飘舞茵。", "斟别酒，问行人。", "莫将别泪裛罗巾。", "早归来，依旧春。"]'),
('song-ci-252','捣练子','李石','宋','宋词','song-ci','捣练子','[]','腰束素，鬓垂鸦。',48,'宋词/ci.song.8000.json','["腰束素，鬓垂鸦。", "无情笑面醉犹遮。", "扇儿扇，瞥见些。", "双凤小，玉钗斜。", "芙蓉衫子藕花纱。", "戴一枝，薝卜花。"]'),
('song-ci-253','长相思','李石','宋','宋词','song-ci','长相思','[]','花飞飞。',44,'宋词/ci.song.8000.json','["花飞飞。", "絮飞飞。", "三月江南烟雨时。", "楼台春树迷。", "双莺儿。", "双燕儿。", "桥北桥南相对啼。", "行人犹未归。"]'),
('song-ci-254','长相思','李石','宋','宋词','song-ci','长相思','[]','红藕丝。',44,'宋词/ci.song.8000.json','["红藕丝。", "白藕丝。", "艾虎衫裁金缕衣。", "钗头双荔枝。", "鬓符儿。", "背符儿。", "鬼在心头符怎知。", "相思十二时。"]'),
('song-ci-255','长相思','李石','宋','宋词','song-ci','长相思','[]','花深红。',44,'宋词/ci.song.8000.json','["花深红。", "花浅红。", "桃杏浅深花不同。", "年年吹暖风。", "莺语中。", "燕语中。", "唤起碧窗春睡浓。", "日高花影重。"]'),
('song-ci-256','乌夜啼','李石','宋','宋词','song-ci','乌夜啼','[]','红软榴花脸晕，绿愁杨柳眉疏。',56,'宋词/ci.song.8000.json','["红软榴花脸晕，绿愁杨柳眉疏。", "日长院宇闲消遣，荔子赌樗蒲。", "莹雪凉衣乍浴，裁冰素扇新书。", "绣香熏被梅烟润，枕簟碧纱厨。"]'),
('song-ci-257','乌夜啼','李石','宋','宋词','song-ci','乌夜啼','[]','鸾镜愁添眉黛，罗裙瘦减腰肢。',56,'宋词/ci.song.8000.json','["鸾镜愁添眉黛，罗裙瘦减腰肢。", "一回见了一回病，弹指误佳期。", "醉里懵腾泪洗，梦中著摸魂飞。", "一春多少闲风雨，亭院落花时。"]'),
('song-ci-258','乌夜啼','李石','宋','宋词','song-ci','乌夜啼','[]','绣阁和烟飞絮，粉墙映日吹红。',56,'宋词/ci.song.8000.json','["绣阁和烟飞絮，粉墙映日吹红。", "花花柳柳成阴处，休恨五更风。", "絮点铺排绿水，红香收拾黄蜂。", "留春尽道能留得，长在酒杯中。"]'),
('song-ci-259','朝中措','李石','宋','宋词','song-ci','朝中措','[]','飘飘仙袂缕黄金。',57,'宋词/ci.song.8000.json','["飘飘仙袂缕黄金。", "相对弄清音。", "几度教人误听，当窗绿暗红深。", "一声梦破，槐阴转午，别院深沈。", "试问绿杨南陌，何如紫椹西林。"]'),
('song-ci-260','朝中措','李石','宋','宋词','song-ci','朝中措','[]','绿杨庭院觉深沈。',57,'宋词/ci.song.8000.json','["绿杨庭院觉深沈。", "曾听一莺吟。", "今夜却成容易，双莲步步摇金。", "歌声暂驻，颦眉又去，无计重寻。", "应恨玉郎殢酒，教人守到更深。"]'),
('song-ci-261','朝中措','李石','宋','宋词','song-ci','朝中措','[]','凌波庭院藕香残。',57,'宋词/ci.song.8000.json','["凌波庭院藕香残。", "银烛夜生寒。", "两点眉尖新恨，别来谁画遥山。", "南楼皓月，一般瘦影，两处凭阑。", "莫似桃花溪畔，乱随流水人间。"]'),
('song-ci-262','一翦梅','李石','宋','宋词','song-ci','一翦梅','[]','红映阑干绿映阶。',68,'宋词/ci.song.8000.json','["红映阑干绿映阶。", "闲闷闲愁，独自徘徊。", "天涯消息几时归，别后无书有梦来。", "后院棠梨昨夜开。", "雨急风忙次第催。", "罗衣消瘦却春寒，莫管红英，一任苍苔。"]'),
('song-ci-263','一翦梅','李石','宋','宋词','song-ci','一翦梅','[]','百濯香残恨未消。',68,'宋词/ci.song.8000.json','["百濯香残恨未消。", "万绪千丝，莲藕芭蕉。", "临岐犹自说前时，轻翦乌云解翠翘。", "雨意重来风已飘。", "南陌行人折柳条。", "此间无计可留连，枕上今宵。", "马上明朝。"]'),
('song-ci-264','醉落魄・一斛珠','李石','宋','宋词','song-ci','醉落魄・一斛珠','[]','天低日暮。',67,'宋词/ci.song.8000.json','["天低日暮。", "清商一曲行人住。", "著人意态如飞絮。", "才泊春衫，却被风吹去。", "朝期暮约浑无据。", "同心结尽千千缕。", "今宵魂梦知何处。", "翠竹芭蕉，又下黄昏雨。"]'),
('song-ci-265','临江仙','李石','宋','宋词','song-ci','临江仙','[]','烟柳疏疏人悄悄，画楼风外吹笙。',70,'宋词/ci.song.8000.json','["烟柳疏疏人悄悄，画楼风外吹笙。", "倚阑闻唤小红声。", "熏香临欲睡，玉漏已三更。", "坐待不来来又去，一方明月中庭。", "粉墙东畔小桥横。", "起来花影下，扇子扑飞萤。"]'),
('song-ci-266','临江仙','李石','宋','宋词','song-ci','临江仙','[]','八曲阑干垂手处，烛光花影疏疏。',68,'宋词/ci.song.8000.json','["八曲阑干垂手处，烛光花影疏疏。", "一尊共饮记当初。", "彩毫浓点，双带要人书。", "日暮不来朱户隔，碧云高挂蟾蜍。", "琴心密约总成虚。", "醉中言语，醒后忆人无。"]'),
('song-ci-267','临江仙','李石','宋','宋词','song-ci','临江仙','[]','有宅一区家四壁，年年花柳深村。',68,'宋词/ci.song.8000.json','["有宅一区家四壁，年年花柳深村。", "父兄随处宴鸡豚。", "折腰归去，何苦傍侯门。", "拟射九乌留白日，假饶立到黄昏。", "卧龙老矣及三分。", "不如把手，堂上宴芳尊。"]'),
('song-ci-268','临江仙','李石','宋','宋词','song-ci','临江仙','[]','九九之年逢降庆，生年生日同时。',70,'宋词/ci.song.8000.json','["九九之年逢降庆，生年生日同时。", "金花紫诰鬓银丝。", "乞身香火地，日戏老莱衣。", "浑舍集成千岁会，子孙三世庭闱。", "共将春酒祝金卮。", "蟠桃三月暮，莫怪看花迟。"]'),
('song-ci-269','满庭芳','李石','宋','宋词','song-ci','满庭芳','[]','江草抽心，江云弄碧，江波依旧东流。',118,'宋词/ci.song.8000.json','["江草抽心，江云弄碧，江波依旧东流。", "别筵初散，行客上兰舟。", "休唱阳关旧曲，青青柳、无限轻柔。", "应争记，三年乐事，珠翠拥鳌头。", "离愁。", "知几许，花梢著雨，红泪难收。", "看烟火吴天，万里悠悠。", "一望珠宫绛阙，蓬莱路、应在皇州。", "仍回首，蜀山万点，明月满南楼。"]'),
('song-ci-270','木兰花・玉楼春','李石','宋','宋词','song-ci','木兰花・玉楼春','[]','辘轳轭轭门前井。',64,'宋词/ci.song.8000.json','["辘轳轭轭门前井。", "不道隔窗人睡醒。", "柔弦无力玉琴寒，残麝彻心金鸭冷。", "一莺啼破帘栊静。", "红日渐高槐转影。", "起来情绪寄游丝，飞绊翠翘风不定。"]'),
('song-ci-271','木兰花・玉楼春','李石','宋','宋词','song-ci','木兰花・玉楼春','[]','一春闲却花时候。',64,'宋词/ci.song.8000.json','["一春闲却花时候。", "小阁幽窗长独守。", "晴云南浦梦还空，初月西楼眉也皱。", "马嘶何日门前柳。", "脉脉盈盈相见后。", "心头有事不难知，面上看谁真个瘦。"]'),
('song-ci-272','南乡子','李石','宋','宋词','song-ci','南乡子','[]','十月小春天。',66,'宋词/ci.song.8000.json','["十月小春天。", "红叶红花半雨烟。", "点滴红酥真耐冷，争先。", "夺取梅魂斗雪妍。", "坐待晓莺迁。", "织女机头蜀锦川。", "枝上绿毛幺凤子，飞仙。", "乞与双双作被眠。"]'),
('song-ci-273','南乡子','李石','宋','宋词','song-ci','南乡子','[]','裹帽拈吟须。',66,'宋词/ci.song.8000.json','["裹帽拈吟须。", "我是蓬莱旧酒徒。", "除了茅君谁是伴，麻姑。", "洞里仙浆不用沽。", "弱水渺江湖。", "醉里笙歌醉里扶。", "纵饮菊潭餐菊蕊，茱萸。", "医得人间瘦也无。"]'),
('song-ci-274','西江月','李石','宋','宋词','song-ci','西江月','[]','一脉分溪浅绿，数枝约岸猗红。',58,'宋词/ci.song.8000.json','["一脉分溪浅绿，数枝约岸猗红。", "小船横系碧芦丛。", "似我江湖春梦。", "晒网渔归别浦，举头雁度晴空。", "短蓑独宿月明中。", "醉笛一声风弄。"]'),
('song-ci-275','八声甘州','李石','宋','宋词','song-ci','八声甘州','[]','向吴天万里、一叶归舟。',119,'宋词/ci.song.8000.json','["向吴天万里、一叶归舟。", "岁月尽悠悠。", "有清歌一曲，醉中自笑，酒醒还愁。", "几度春莺啭午，塞雁横秋。", "渔笛蓑衣底，依旧勾收。", "多谢飞来双鹤，□水边林下，伴我遨游。", "笑老莱晨昏，色笑为亲留。", "有向来、素琴三尺，枕一编、周易在床头。", "君知否，家山梦寐，浑胜瀛洲。"]'),
('song-ci-276','雨中花慢','李石','宋','宋词','song-ci','雨中花慢','["\u897f\u6e56"]','潋滟云霞，空濛雾雨，长堤柳色如茵。',117,'宋词/ci.song.8000.json','["潋滟云霞，空濛雾雨，长堤柳色如茵。", "问西湖何似，粉面初匀。", "尽道软红香土，东华风月俱新。", "旧游如梦，尘缘未断，几度逢春。", "蓬莱阁上，风流二老，相携把酒论文。", "最好是、四娘桃李，约近东邻。", "别后使君须鬓，十分白了三分。", "是人笑道，醉中文字，更要红裙。"]'),
('song-ci-277','醉蓬莱','李石','宋','宋词','song-ci','醉蓬莱','["\u957f\u6c5f"]','望长江东去，逐客西来，几逢秋杪。',122,'宋词/ci.song.8000.json','["望长江东去，逐客西来，几逢秋杪。", "江草江花，约鬓丝俱老。", "朝士红萸，佳人雪藕，别后忍孤欢笑。", "楚水楼台，巫山宫殿，五湖烟渺。", "又是征帆，万里行去，旧恨鲈鱼，昔日鸥鸟。", "九日江南，上蓬莱仙岛。", "三度刘郎，黄花醉里，问我几时来到。", "寄语西风，饶他老子，莫欺乌帽。"]'),
('song-ci-278','渔家傲','李石','宋','宋词','song-ci','渔家傲','[]','西去征鸿东去水。',72,'宋词/ci.song.8000.json','["西去征鸿东去水。", "几重别恨千山里。", "梦绕绿窗书半纸。", "何处是。", "桃花溪畔人千里。", "瘦玉倚香愁黛翠。", "劝人须要人先醉。", "问道明朝行也未。", "犹自记。", "灯前背立偷弹泪。"]'),
('song-ci-279','卜算子','李石','宋','宋词','song-ci','卜算子','[]','密叶蜡蜂房，花下频来往。',52,'宋词/ci.song.8000.json','["密叶蜡蜂房，花下频来往。", "不知辛苦为谁甜，山月梅花上。", "玉质紫金衣，香雪随风荡。", "人间唤作返魂梅，仍是蜂儿样。"]'),
('song-ci-280','捣练子','李石','宋','宋词','song-ci','捣练子','["\u6d1e\u5ead\u6e56"]','心自小，玉钗头。',48,'宋词/ci.song.8000.json','["心自小，玉钗头。", "月娥飞下白苹洲。", "水中仙，月下游。", "江汉佩，洞庭舟。", "香名薄幸寄青楼。", "问何如，打泊浮。"]'),
('song-ci-281','捣练子','李石','宋','宋词','song-ci','捣练子','[]','红粉里，绛金裳。',48,'宋词/ci.song.8000.json','["红粉里，绛金裳。", "一卮仙酒艳晨妆。", "醉温柔，别有乡。", "清暑殿，藕风凉。", "鸡头擘破误君王。", "泣梨花，春梦长。"]'),
('song-ci-282','谢池春','李石','宋','宋词','song-ci','谢池春','[]','烟雨池塘，绿野乍添春涨。',82,'宋词/ci.song.8000.json','["烟雨池塘，绿野乍添春涨。", "凤楼高、珠帘卷上。", "金柔玉困，舞腰肢相向。", "似玉人、瘦时模样。", "离亭别后，试问阳关谁唱。", "对青春、翻成怅望。", "重门静院，度香风屏障。", "吐飞花、伴人来往。"]'),
('song-ci-283','出塞・谒金门','李石','宋','宋词','song-ci','出塞・谒金门','[]','花树树。',53,'宋词/ci.song.8000.json','["花树树。", "吹碎胭脂红雨。", "将谓郎来推绣户。", "暖风摇竹坞。", "睡起栏干凝伫。", "漠漠红楼飞絮。", "划踏袜儿垂手处。", "隔溪莺对语。"]'),
('song-ci-284','望江南・忆江南','康与之','宋','宋词','song-ci','望江南・忆江南','[]','重阳日，四面雨垂垂。',64,'宋词/ci.song.8000.json','["重阳日，四面雨垂垂。", "戏马台前泥拍肚，龙山路上水平脐。", "淹浸倒东篱。", "茱萸胖，黄菊湿齑齑。", "落帽孟嘉寻箬笠，漉巾陶令买蓑衣。", "都道不如归。"]'),
('song-ci-285','满江红','康与之','宋','宋词','song-ci','满江红','[]','叹诗书万卷、致君人，番沈陆。',46,'宋词/ci.song.8000.json','["叹诗书万卷、致君人，番沈陆。", "……且置请缨封万户，径须卖剑酬黄犊。", "恸当年、寂寞贾长沙，伤时哭。"]'),
('song-ci-286','鹧鸪天','康与之','宋','宋词','song-ci','鹧鸪天','[]','解将天上千年艳，换得人间九日黄。',16,'宋词/ci.song.8000.json','["解将天上千年艳，换得人间九日黄。"]'),
('song-ci-287','忆秦娥','康与之','宋','宋词','song-ci','忆秦娥','[]','春寂寞。',56,'宋词/ci.song.8000.json','["春寂寞。", "长安古道东风恶。", "东风恶。", "胭脂满地，杏花零落。", "臂销不奈黄金约。", "天寒犹怯春衫薄。", "春衫薄。", "不禁珠泪，为君弹却。"]'),
('song-ci-288','洞仙歌令・洞仙歌','康与之','宋','宋词','song-ci','洞仙歌令・洞仙歌','[]','若耶溪路。',107,'宋词/ci.song.8000.json','["若耶溪路。", "别岸花无数。", "欲敛娇红向人语。", "与绿荷、相倚恨，回首西风，波淼淼、三十六陂烟雨。", "新妆明照水，汀渚生香，不嫁东风被谁误。", "遣踟蹰、骚客意，千里绵绵，仙浪远、何处凌波微步。", "想南浦、潮生画桡归，正月晓风清，断肠凝伫。"]'),
('song-ci-289','西江月','康与之','宋','宋词','song-ci','西江月','[]','名与牡丹联谱，南珍独比江瑶。',58,'宋词/ci.song.8000.json','["名与牡丹联谱，南珍独比江瑶。", "闽山入贡冠前朝。", "露叶风枝袅袅。", "香玉满苞仙液，绉红圆戚鲛绡。", "华清宫殿蜀山遥。", "一骑红尘失笑。"]'),
('song-ci-290','曲游春','康与之','宋','宋词','song-ci','曲游春','[]','脸薄难藏泪，恨柳风，不与吹断行色。',42,'宋词/ci.song.8000.json','["脸薄难藏泪，恨柳风，不与吹断行色。", "……但掩袖转面面啼红，无言应得。", "……哭得浑无气力。"]'),
('song-ci-291','舞杨花','康与之','宋','宋词','song-ci','舞杨花','[]','牡丹半坼初经雨，雕槛翠幕朝阳。',118,'宋词/ci.song.8000.json','["牡丹半坼初经雨，雕槛翠幕朝阳。", "娇困倚动风，羞谢了群芳。", "洗烟凝露向清晓，步瑶台、月底霓裳。", "轻笑淡拂宫黄。", "浅拟飞燕新妆。", "杨柳啼鸦昼永，正秋千庭馆，风絮池塘。", "三十六宫，簪艳粉浓香。", "慈宁玉殿庆清赏，占东君、谁比花王。", "良夜万烛荧煌。", "影里留住年光。"]'),
('song-ci-292','瑞鹤仙','康与之','宋','宋词','song-ci','瑞鹤仙','[]','瑞烟浮禁苑。',127,'宋词/ci.song.8000.json','["瑞烟浮禁苑。", "正绛阙春回，新正方半。", "冰轮桂华满。", "溢花衢歌市，芙蓉开遍。", "龙楼两观。", "见银烛、星球有烂。", "卷珠帘、尽日笙歌，盛集宝钗金钏。", "堪羡。", "绮罗丛里，兰麝香中，正宜游玩。", "风柔夜暖。", "花影乱，笑声喧。", "闹蛾儿满路，成团打块，簇著冠儿斗转。", "喜皇都、旧日风光，太平再见。"]'),
('song-ci-293','瑞鹤仙','康与之','宋','宋词','song-ci','瑞鹤仙','[]','薄寒罗袖怯。',127,'宋词/ci.song.8000.json','["薄寒罗袖怯。", "教小玉添香，被翻宫襭。", "兰缸半明灭。", "听几声归雁，一帘微月。", "情波恨叶。", "索新词、犹自怨别。", "梦回时、雪暖酥凝，掠鬓宝鸳钗折。", "凄切。", "纹窗描绣，旧谱寻棋，变成虚设。", "同心对结。", "重来是，甚时节。", "怅姑苏台上，征帆何许，隐隐遥山万叠。", "袖红绡、独立无言，偷弹泪血。"]'),
('song-ci-294','汉宫春','康与之','宋','宋词','song-ci','汉宫春','[]','云海沈沈，峭寒收建章。',118,'宋词/ci.song.8000.json','["云海沈沈，峭寒收建章。", "雪残鳷鹊。", "华灯照夜，万井禁城行乐。", "春随鬓影，映参差、柳丝梅萼。", "丹禁杳，鳌峰对耸，三山上通寥廓。", "春衫绣罗香薄。", "步金莲影下，三千绰约。", "冰轮桂满，皓色冷浸楼阁。", "霓裳帝乐，奏升平、天风吹落。", "留凤辇、通宵宴赏，莫放漏声闲却。"]'),
('song-ci-295','喜迁莺','康与之','宋','宋词','song-ci','喜迁莺','[]','腊残春早。',126,'宋词/ci.song.8000.json','["腊残春早。", "正帘幕护寒，楼台清晓。", "宝运当千，佳辰馀五，嵩岳诞生元老。", "帝遣阜安宗社，人仰雍容廊庙。", "尽总道，是文章孔孟，勋庸周召。", "师表。", "方眷遇，鱼水君臣，须信从来少。", "玉带金鱼，朱颜绿鬓，占断世间荣耀。", "篆刻鼎彝将遍，整顿乾坤都了。", "愿岁岁，见柳梢青浅，梅英红小。"]'),
('song-ci-296','喜迁莺','康与之','宋','宋词','song-ci','喜迁莺','["\u6d1e\u5ead\u6e56"]','秋寒初劲。',125,'宋词/ci.song.8000.json','["秋寒初劲。", "看云路雁来，碧天如镜。", "湘浦烟深，衡阳沙远，风外几行斜阵。", "回首塞门何处，故国关河重省。", "汉使老，认上林欲下，徘徊清影。", "江南烟水暝。", "声过小楼，烛暗金猊冷。", "送目鸣琴，裁诗挑锦，此恨此情无尽。", "梦想洞庭飞下，散入云涛千顷。", "过尽也，奈社陵人远，玉关无信。"]'),
('song-ci-297','丑奴儿令・采桑子','康与之','宋','宋词','song-ci','丑奴儿令・采桑子','[]','冯夷剪碎澄溪练，飞下同云。',52,'宋词/ci.song.8000.json','["冯夷剪碎澄溪练，飞下同云。", "著地无痕。", "柳絮梅花处处春。", "山阴此夜明如昼，月满前村。", "莫掩溪门。", "恐有扁舟乘兴人。"]'),
('song-ci-298','丑奴儿令・采桑子','康与之','宋','宋词','song-ci','丑奴儿令・采桑子','[]','红楼紫陌青春路，柳色皇州。',52,'宋词/ci.song.8000.json','["红楼紫陌青春路，柳色皇州。", "月淡烟柔。", "袅袅亭亭不自由。", "旧时扶上雕鞍处，此地重游。", "总是新愁。", "柳自轻盈水自流。"]'),
('song-ci-299','诉衷情令','康与之','宋','宋词','song-ci','诉衷情令','[]','郁孤台上立多时。',54,'宋词/ci.song.8000.json','["郁孤台上立多时。", "烟晚暮云低。", "山川城郭良是，回首昔人非。", "今古事，只堪悲。", "此心知。", "一尊芳酒，慷慨悲歌，月堕人归。"]'),
('song-ci-300','诉衷情令','康与之','宋','宋词','song-ci','诉衷情令','[]','阿房废址汉荒丘。',54,'宋词/ci.song.8000.json','["阿房废址汉荒丘。", "狐兔又群游。", "豪华尽成春梦，留下古今愁。", "君莫上，古原头。", "泪难收。", "夕阳西下，塞雁南飞，渭水东流。"]'),
('song-ci-301','菩萨蛮令・菩萨蛮','康与之','宋','宋词','song-ci','菩萨蛮令・菩萨蛮','[]','秦时宫殿咸阳里。',52,'宋词/ci.song.8000.json','["秦时宫殿咸阳里。", "千门万户连云起。", "复道互西东。", "不禁三月风。", "汉唐乘王气。", "万岁千秋计。", "毕竟是荒丘。", "荆榛满地愁。"]'),
('song-ci-302','菩萨蛮令・菩萨蛮','康与之','宋','宋词','song-ci','菩萨蛮令・菩萨蛮','[]','龙蟠虎踞金陵郡。',52,'宋词/ci.song.8000.json','["龙蟠虎踞金陵郡。", "古来六代豪华盛。", "缥凤不来游。", "台空江自流。", "下临全楚地。", "包举中原势。", "可惜草连天。", "晴郊狐兔眠。"]'),
('song-ci-303','感皇恩','康与之','宋','宋词','song-ci','感皇恩','[]','一雨一番凉，江南秋兴。',81,'宋词/ci.song.8000.json','["一雨一番凉，江南秋兴。", "门掩苍苔锁寒径。", "红尘不到，尽日鸟啼人静。", "绿荷风已过，摇香柄。", "澹阴未解，园林清润。", "一片花飞堕红影。", "残书读尽，袖手高吟清咏。", "任从车马客，劳方寸。"]'),
('song-ci-304','卖花声','康与之','宋','宋词','song-ci','卖花声','[]','蹙损远山眉。',64,'宋词/ci.song.8000.json','["蹙损远山眉。", "幽怨谁知。", "罗衾滴尽泪胭脂。", "夜过春寒愁未起，门外鸦啼。", "惆怅阻佳期。", "人在天涯。", "东风频动小桃枝。", "正是销魂时候也，撩乱花飞。"]'),
('song-ci-305','卖花声','康与之','宋','宋词','song-ci','卖花声','[]','愁拈断钗金。',64,'宋词/ci.song.8000.json','["愁拈断钗金。", "远信沈沈。", "秦筝调怨不成音。", "郎马不知何处也，楼外春深。", "好梦已难寻。", "夜夜馀衾。", "目穷千里正伤心。", "记得当初郎去路，绿树阴阴。"]'),
('song-ci-306','江城子','康与之','宋','宋词','song-ci','江城子','[]','南溪二月雨初晴。',86,'宋词/ci.song.8000.json','["南溪二月雨初晴。", "四郊明。", "暖风轻。", "一雨一风，铺地落红英。", "枝上流莺啼劝我，春欲去，且留春。", "登临行乐慰闲情。", "过长亭。", "暮潮平。", "四面青芜，中是越王城。", "信马行吟归路晚，山簇簇，柳阴阴。"]'),
('song-ci-307','风入松','康与之','宋','宋词','song-ci','风入松','[]','一宵风雨送春归。',86,'宋词/ci.song.8000.json','["一宵风雨送春归。", "绿暗红稀。", "画楼整日无人到，与谁同拈花枝。", "门外蔷薇开也，枝头梅子酸时。", "玉人应是数归期。", "翠敛愁眉。", "塞鸿不到双鱼远，叹楼前、流水难西。", "新恨欲题红叶，东风满院花飞。"]'),
('song-ci-308','风入松','康与之','宋','宋词','song-ci','风入松','[]','碧苔满地衬残红。',84,'宋词/ci.song.8000.json','["碧苔满地衬残红。", "绿树阴浓。", "晓莺啼破眉心事，旧愁新恨重重。", "翠黛不忺重扫，佳时每恨难同。", "花开花谢任东风。", "此恨无穷。", "梦魂拟逐杨花去，殢人休下帘栊。", "要见只凭清梦，几时真个相逢。"]'),
('song-ci-309','谒金门','康与之','宋','宋词','song-ci','谒金门','[]','春又晚。',53,'宋词/ci.song.8000.json','["春又晚。", "风劲落红如剪。", "睡起绣床飞絮满。", "日长门半掩。", "不管离肠欲断。", "听尽梁间双燕。", "试上小楼还不见。", "楼前芳草远。"]'),
('song-ci-310','长相思','康与之','宋','宋词','song-ci','长相思','[]','南高峰。',44,'宋词/ci.song.8000.json','["南高峰。", "北高峰。", "一片湖光烟霭中。", "春来愁杀侬。", "郎意浓。", "妾意浓。", "油壁车轻郎马骢。", "相逢九里松。"]'),
('song-ci-311','应天长','康与之','宋','宋词','song-ci','应天长','[]','管弦绣陌，灯火画桥，尘香旧时归路。',122,'宋词/ci.song.8000.json','["管弦绣陌，灯火画桥，尘香旧时归路。", "肠断萧娘，旧日风帘映朱户。", "莺能舞，花解语。", "念后约、顿成轻负。", "缓雕佩、独自归来，凭栏情绪。", "楚岫在何处。", "香梦悠悠，花月更谁主。", "惆怅后期，空有鳞鸿寄纨素。", "枕前泪，窗外雨。", "翠幕冷、夜凉虚度。", "未应信、此度相思，寸肠千缕。"]'),
('song-ci-312','玉楼春令・玉楼春','康与之','宋','宋词','song-ci','玉楼春令・玉楼春','[]','青笺后约无凭据。',64,'宋词/ci.song.8000.json','["青笺后约无凭据。", "误我碧桃花下语。", "谁将消息问刘郎，怅望玉溪溪上路。", "春来无限伤情绪。", "拟欲题红都寄与。", "东风吹落一庭花，手把新愁无写处。"]'),
('song-ci-313','风入松','康与之','宋','宋词','song-ci','风入松','[]','画桥流水欲平阑。',88,'宋词/ci.song.8000.json','["画桥流水欲平阑。", "雨后青山。", "去年芳草今年恨，恨香车、不逐雕鞍。", "红杏墙头院落，绿杨楼外秋千。", "谢娘别后忆前欢。", "泪滴春衫。", "柔荑共折香红处，劝东风、且与流连。", "早是相思瘦损，梅花谢了春寒。"]'),
('song-ci-314','忆少年令・忆少年','康与之','宋','宋词','song-ci','忆少年令・忆少年','[]','双龙烛影，千门夜色，三五宴瑶台。',62,'宋词/ci.song.8000.json','["双龙烛影，千门夜色，三五宴瑶台。", "舞蝶随香，飞蝉扑鬓，人自蕊宫来。", "太平箫鼓宸居晓，清漏玉壶催。", "步辇归时，绮罗生润，花上月徘徊。"]'),
('song-ci-315','风流子','康与之','宋','宋词','song-ci','风流子','[]','结客少年场。',134,'宋词/ci.song.8000.json','["结客少年场。", "繁华梦，当日赏风光。", "红灯九街，买移花市，画楼十里，特地梅妆。", "醉魂荡，龙跳撝万字，鲸饮吸三江。", "娇随钿车，玉骢南陌，喜摇双桨，红袖横塘。", "天涯归期阻，衡阳雁不到，路隔三湘。", "难见谢娘诗好，苏小歌长。", "漫自惜鸾胶，朱弦何在，暗藏罗结，红绶消香。", "歌罢泪沾宫锦，襟袖淋浪。"]'),
('song-ci-316','瑞鹤仙令・临江仙','康与之','宋','宋词','song-ci','瑞鹤仙令・临江仙','[]','樱桃落尽春归去，蝶翻金粉双飞。',70,'宋词/ci.song.8000.json','["樱桃落尽春归去，蝶翻金粉双飞。", "子规啼恨小楼西。", "曲屏珠箔晚，惆怅卷金泥。", "门巷寂寥人去后，望残烟草低迷。", "闲寻旧曲玉笙悲。", "关山千里恨，云汉月重规。"]'),
('song-ci-317','杏花天','康与之','宋','宋词','song-ci','杏花天','[]','帝城柳色藏春絮。',65,'宋词/ci.song.8000.json','["帝城柳色藏春絮。", "嫩绿满、游人归路。", "残红剩蕊留春住。", "无奈霏微细雨。", "南陌上、玉佩钿车，怅紫陌、青门日暮。", "黄昏院落人归去。", "犹有流莺对语。"]'),
('song-ci-318','卜算子','康与之','宋','宋词','song-ci','卜算子','[]','潮生浦口云，潮落津头树。',52,'宋词/ci.song.8000.json','["潮生浦口云，潮落津头树。", "潮本无心落又生，人自来还去。", "今古短长亭，送往迎来处。", "老尽东西南北人，亭下潮如故。"]'),
('song-ci-319','金菊对芙蓉','康与之','宋','宋词','song-ci','金菊对芙蓉','[]','梧叶飘黄，万山空翠，断霞流水争辉。',121,'宋词/ci.song.8000.json','["梧叶飘黄，万山空翠，断霞流水争辉。", "正金风西起，海燕东归。", "凭栏不见南来雁，望故人、消息迟迟。", "木樨开后，不应误我，好景良时。", "只念独守孤帏。", "把枕前嘱付，一旦分飞。", "上秦楼游赏，酒殢花迷。", "谁知别后相思苦，悄为伊、瘦损香肌。", "花前月下，黄昏院落，珠泪偷垂。"]'),
('song-ci-320','满江红','康与之','宋','宋词','song-ci','满江红','[]','恼杀行人，东风里、为谁啼血。',111,'宋词/ci.song.8000.json','["恼杀行人，东风里、为谁啼血。", "正青春未老，流莺方歇。", "蝴蝶枕前颠倒梦，杏花枝上朦胧月。", "问天涯、何事苦关情，思离别。", "声一唤，肠千结。", "闽岭外，江南陌。", "正是堤杨柳，翠条堪折。", "镇日叮咛千百遍，只将一句频频说。", "道不如归去不如归，伤情切。"]'),
('song-ci-321','失调名','康与之','宋','宋词','song-ci','失调名','[]','玉楼人静。',12,'宋词/ci.song.8000.json','["玉楼人静。", "高卷疏帘情迥。"]');
